--==================================================

function HolyCleanText(value)

    local text =
        tostring(value or "")

    text =
        text:gsub(
            "^%s+",
            ""
        )

    text =
        text:gsub(
            "%s+$",
            ""
        )

    return text
end

function HolyGetRequestFunction()

    if type(syn) == "table"
    and type(syn.request) == "function" then

        return syn.request
    end

    if type(http_request) == "function" then
        return http_request
    end

    if type(request) == "function" then
        return request
    end

    if type(fluxus) == "table"
    and type(fluxus.request) == "function" then

        return fluxus.request
    end

    local env =
        type(getgenv) == "function"
        and getgenv()
        or _G

    if type(env) == "table" then

        if type(env.request) == "function" then
            return env.request
        end

        if type(env.http_request) == "function" then
            return env.http_request
        end
    end

    return nil
end

function HolyValidateSource(body)

    if type(body) ~= "string"
    or body == "" then

        return nil,
            "empty response"
    end

    if body:sub(1, 3) == "\239\187\191" then
        body = body:sub(4)
    end

    local preview =
        body:sub(1, 220):lower()

    if preview:find("<!doctype html", 1, true)
    or preview:find("<html", 1, true)
    or preview:find("rate limit", 1, true) then

        return nil,
            "response was HTML/rate-limit page"
    end

    if body:find("\0", 1, true) then

        return nil,
            "response contains binary null bytes"
    end

    return body,
        nil
end

function HolyHttpGet(url)

    url =
        HolyCleanText(url)

    if url == "" then
        return nil, "empty URL"
    end

    local failures =
        {}

    local ok,
        result =
        pcall(function()

            return game:HttpGet(
                url,
                true
            )
        end)

    if ok == true then

        local source,
            sourceError =
            HolyValidateSource(result)

        if source then
            return source, nil
        end

        failures[#failures + 1] =
            "game:HttpGet: "
            .. tostring(sourceError)

    else

        failures[#failures + 1] =
            "game:HttpGet failed: "
            .. tostring(result)
    end

    local requestFunction =
        HolyGetRequestFunction()

    if type(requestFunction) == "function" then

        local requestOk,
            response =
            pcall(function()

                return requestFunction({
                    Url = url,
                    Method = "GET",
                    Headers = {
                        ["Accept"] = "text/plain",
                        ["Accept-Encoding"] = "identity",
                        ["Cache-Control"] = "no-cache",
                    },
                })
            end)

        if requestOk == true then

            local body =
                nil

            if type(response) == "string" then

                body =
                    response

            elseif type(response) == "table" then

                body =
                    response.Body
                    or response.body
                    or response.ResponseBody
                    or response.responseBody
            end

            local source,
                sourceError =
                HolyValidateSource(body)

            if source then
                return source, nil
            end

            failures[#failures + 1] =
                "request: "
                .. tostring(sourceError)

        else

            failures[#failures + 1] =
                "request failed: "
                .. tostring(response)
        end
    end

    return nil,
        table.concat(
            failures,
            " | "
        )
end

function HolyGetCompiler()

    if type(loadstring) == "function" then
        return loadstring
    end

    if type(load) == "function" then
        return load
    end

    local env =
        type(getgenv) == "function"
        and getgenv()
        or _G

    if type(env) == "table" then

        if type(env.loadstring) == "function" then
            return env.loadstring
        end

        if type(env.load) == "function" then
            return env.load
        end
    end

    return nil
end

function HolyLoadUrl(url, name)

    name =
        tostring(name or "remote script")

    local source,
        downloadError =
        HolyHttpGet(url)

    if type(source) ~= "string"
    or source == "" then

        error(
            "[HOLY] Failed to download "
            .. name
            .. ": "
            .. tostring(downloadError),
            0
        )
    end

    local compiler =
        HolyGetCompiler()

    if type(compiler) ~= "function" then

        error(
            "[HOLY] loadstring/load is missing.",
            0
        )
    end

    local compileOk,
        chunk,
        compileError =
        pcall(
            compiler,
            source
        )

    if compileOk ~= true
    or type(chunk) ~= "function" then

        error(
            "[HOLY] Failed to compile "
            .. name
            .. ": "
            .. tostring(compileError or chunk),
            0
        )
    end

    local runOk,
        result =
        pcall(chunk)

    if runOk ~= true then

        error(
            "[HOLY] Failed to run "
            .. name
            .. ": "
            .. tostring(result),
            0
        )
    end

    return result
end

function HolyCanUseFiles()

    return type(writefile) == "function"
        and type(readfile) == "function"
        and type(isfile) == "function"
end

function HolyEnsureFolder()

