            data.UnloadOwnGarden

    elseif type(data.DeleteOwnGarden) == "boolean" then

        HOLY_DEV_UI_STATE.UnloadOwnGarden =
            data.DeleteOwnGarden
    end

    if type(data.HideMiddle) == "boolean" then

        HOLY_DEV_UI_STATE.HideMiddle =
            data.HideMiddle

    elseif type(data.DeleteMiddle) == "boolean" then

        HOLY_DEV_UI_STATE.HideMiddle =
            data.DeleteMiddle

    elseif type(data.UnloadMiddle) == "boolean" then

        HOLY_DEV_UI_STATE.HideMiddle =
            data.UnloadMiddle
    end

    return true
end

function HolyVisualReadNumberText(value, fallback, maxValue)

    local number =
        tonumber(
            tostring(value or "")
                :match("%d+%.?%d*")
        )

    if number == nil then

        number =
            tonumber(fallback)
            or 0
    end

    number =
        math.max(
            0,
            number
        )

    if maxValue ~= nil then

        number =
            math.min(
                number,
                tonumber(maxValue)
                or number
            )
    end

    if math.abs(number - math.floor(number)) < 0.001 then

        return tostring(
            math.floor(number)
        )
    end

    return tostring(
        math.floor(number * 100 + 0.5) / 100
    )
end

function HolyVisualNormalizeGardenFruitMode(value)

    local text =
        HolyCleanText(
            value
        )

    local lower =
        text:lower()

    if lower == "only selected"
    or lower == "selected"
    or (
        lower:find("only", 1, true)
        and lower:find("selected", 1, true)
    ) then

        return "Only Selected"
    end

    if lower == "skip selected"
    or lower == "exclude selected"
    or lower:find("skip", 1, true)
    or lower:find("exclude", 1, true)
    or lower:find("ignore selected", 1, true) then

        return "Skip Selected"
    end

    return "All"
end

function HolyVisualNormalizeGardenFruitSelection(value)

    local raw =
        HolyShopSelectionArray(
            value
        )

    if #raw <= 0 then
        return {}
    end

    local validMap =
        {}

    if type(HolyFarmGetPlantValueMap) == "function" then

        validMap =
            HolyFarmGetPlantValueMap()
    end

    local output =
        {}

    local seen =
        {}

    for _, fruitName in ipairs(raw) do

        local normalized =
            ""

        if type(HolyFarmNormalizePlantName) == "function" then

            normalized =
                HolyFarmNormalizePlantName(
                    fruitName
                )

        else

            normalized =
                HolyCleanText(
                    fruitName
                )
        end

        if normalized ~= ""
        and normalized ~= "All"
        and seen[normalized] ~= true
        and (
            next(validMap) == nil
            or validMap[normalized] == true
        ) then

            seen[normalized] =
                true

            table.insert(
                output,
                normalized
            )
        end
    end

    table.sort(output, function(a, b)

        return tostring(a):lower()
            < tostring(b):lower()
    end)

    return output
end

function HolyVisualNormalizeGardenMutationMode(value)

    local text =
        HolyCleanText(
            value
        )

    local lower =
        text:lower()

    if lower == "only mutated"
    or (
        lower:find("only", 1, true)
        and lower:find("mutat", 1, true)
    ) then

        return "Only Mutated"
    end

    if lower == "only selected"
    or (
        lower:find("only", 1, true)
        and lower:find("selected", 1, true)
    ) then

        return "Only Selected"
    end

    if lower == "skip selected"
    or lower:find("skip", 1, true)
    or lower:find("exclude", 1, true)
    or lower:find("ignore selected", 1, true) then

        return "Skip Selected"
    end

    return "All"
end

