    pcall(function()

        exists =
            isfile(
                GROUPBOX_SETTINGS_FILE
            )
    end)

    if exists ~= true then
        return false
    end

    local readOk,
        raw =
        pcall(function()

            return readfile(
                GROUPBOX_SETTINGS_FILE
            )
        end)

    if readOk ~= true
    or type(raw) ~= "string"
    or raw == "" then

        return false
    end

    local decodeOk,
        data =
        pcall(function()

            return HttpService:JSONDecode(
                raw
            )
        end)

    if decodeOk ~= true
    or type(data) ~= "table" then

        return false
    end

    local collapsed =
        type(data.Collapsed) == "table"
        and data.Collapsed
        or {}

    HOLY_GROUPBOX_STATE.Collapsed =
        {}

    for key, value in pairs(collapsed) do

        key =
            HolyNormalizeGroupboxKey(
                key
            )

        if key ~= "" then

            HOLY_GROUPBOX_STATE.Collapsed[key] =
                value == true
        end
    end

    return true
end

