function HolyFarmGetGardensRoot()

    local gardens =
        workspace:FindFirstChild(
            "Gardens"
        )

    if typeof(gardens) == "Instance" then
        return gardens
    end

    gardens =
        workspace:FindFirstChild(
            "Gardens",
            true
        )

    if typeof(gardens) == "Instance" then
        return gardens
    end

    return nil
end

function HolyFarmCountOwnPrefixedPlants(plantsFolder)

    if typeof(plantsFolder) ~= "Instance" then
        return 0
    end

    local prefix =
        tostring(
            LocalPlayer
            and LocalPlayer.UserId
            or ""
        )
        .. "_"

    if prefix == "_" then
        return 0
    end

    local count =
        0

    for _, plant in ipairs(plantsFolder:GetChildren()) do

        if tostring(plant.Name):sub(1, #prefix) == prefix then

            count =
                count + 1
        end
    end

    return count
end

function HolyFarmScorePlot(plot)

    if typeof(plot) ~= "Instance" then
        return 0
    end

    local score =
        0

    local localUserId =
        tostring(
            LocalPlayer
            and LocalPlayer.UserId
            or ""
        )

    local localName =
        HolyCleanText(
            LocalPlayer
            and LocalPlayer.Name
            or ""
        )

    local ownerUserId =
        nil

    pcall(function()

        ownerUserId =
            plot:GetAttribute(
                "OwnerUserId"
            )
    end)

    if ownerUserId ~= nil
    and tostring(ownerUserId) == localUserId then

        score =
            score + 1000
    end

    local owner =
        nil

    pcall(function()

        owner =
            plot:GetAttribute(
                "Owner"
            )
    end)

    owner =
        HolyCleanText(
            owner
        )

    if owner ~= ""
    and localName ~= ""
    and owner == localName then

        score =
            score + 900
    end

    local plantsFolder =
        plot:FindFirstChild(
            "Plants"
        )

    local ownPrefixCount =
        HolyFarmCountOwnPrefixedPlants(
            plantsFolder
        )

    if ownPrefixCount > 0 then

        score =
            score + 100 + math.min(
                ownPrefixCount,
                100
            )
    end

    return score
end

function HolyFarmResolveOwnPlot(forceRefresh)

    local runtime =
        HolyFarmEnsureRuntime()

    local gardens =
        HolyFarmGetGardensRoot()

    if typeof(gardens) ~= "Instance" then
        return nil
    end

    if forceRefresh ~= true
    and typeof(runtime.OwnPlot) == "Instance"
    and runtime.OwnPlot.Parent == gardens
    and HolyFarmScorePlot(runtime.OwnPlot) > 0 then

        runtime.PlantsFolder =
            runtime.OwnPlot:FindFirstChild(
                "Plants"
            )

        return runtime.OwnPlot
    end

    local bestPlot =
        nil

    local bestScore =
        0

    for _, plot in ipairs(gardens:GetChildren()) do

        local score =
            HolyFarmScorePlot(
                plot
            )

        if score > bestScore then

            bestScore =
                score

            bestPlot =
                plot
        end
    end

    if typeof(bestPlot) == "Instance"
    and bestScore > 0 then

        runtime.OwnPlot =
            bestPlot

        runtime.PlantsFolder =
            bestPlot:FindFirstChild(
                "Plants"
            )

        return bestPlot
    end

    runtime.OwnPlot =
        nil

    runtime.PlantsFolder =
        nil

    return nil
end

function HolyFarmReadAttribute(instance, names)

    if typeof(instance) ~= "Instance" then
        return ""
    end

    for _, name in ipairs(names or {}) do

        local ok,
            value =
            pcall(function()

                return instance:GetAttribute(
                    name
                )
            end)

        value =
            HolyCleanText(
                ok == true
                and value
                or ""
            )

        if value ~= "" then
            return value
        end
    end

    return ""
end

function HolyFarmReadNumberAttribute(instance, names)

    local raw =
        HolyFarmReadAttribute(
            instance,
            names
        )

    return tonumber(raw)
end

function HolyFarmReadPlantId(plant)

    local fromAttr =
        HolyFarmReadAttribute(
            plant,
            {
                "PlantId",
                "PlantID",
                "PlantUUID",
                "PlantUid",
                "UUID",
                "Uuid",
                "Id",
                "ID",
            }
        )

    if fromAttr ~= "" then
        return fromAttr
    end

    local fromName =
        tostring(
            plant
            and plant.Name
            or ""
        )

    local plantId =
        fromName:match(
            "^%d+_(.+)$"
        )

    if plantId
    and plantId ~= "" then
        return plantId
    end

    local uuid =
        fromName:match(
            "([%w]+%-%w+%-%w+%-%w+%-%w+)$"
        )

    return HolyCleanText(
        uuid
        or fromName
    )
end

function HolyFarmReadFruitId(plant, fruit)

    local fromAttr =
        HolyFarmReadAttribute(
            fruit,
            {
                "FruitId",
                "FruitID",
                "FruitUUID",
                "FruitUid",
                "UUID",
                "Uuid",
                "Id",
                "ID",
            }
        )

    if fromAttr ~= "" then
        return fromAttr
    end

    local fruitName =
        tostring(
            fruit
            and fruit.Name
            or ""
        )

    if typeof(plant) == "Instance" then

        local plantName =
            tostring(
                plant.Name
                or ""
            )

        local prefix =
            plantName
            .. "_"

        if fruitName:sub(1, #prefix) == prefix then

            return HolyCleanText(
                fruitName:sub(
                    #prefix + 1
                )
            )
        end
    end

    local uuid =
        fruitName:match(
            "([%w]+%-%w+%-%w+%-%w+%-%w+)$"
        )

    return HolyCleanText(
        uuid
        or fruitName
    )
end

function HolyFarmReadPlantName(plant, fruit)

    local plantName =
        HolyFarmReadAttribute(
            plant,
            {
                "SeedName",
                "PlantName",
                "CropName",
                "FruitName",
                "DisplayName",
                "ItemName",
                "Name",
            }
        )

    if plantName ~= "" then
        return plantName
    end

    plantName =
        HolyFarmReadAttribute(
            fruit,
            {
                "CorePartName",
                "FruitName",
                "SeedName",
                "PlantName",
                "CropName",
                "DisplayName",
                "ItemName",
                "Name",
            }
        )

    if plantName ~= "" then
        return plantName
    end

    return "Unknown"
end

function HolyFarmFindHarvestPrompt(fruit)

    if typeof(fruit) ~= "Instance" then
        return nil
    end

    local harvestPart =
        fruit:FindFirstChild(
            "HarvestPart"
        )

    if harvestPart then

        local prompt =
            harvestPart:FindFirstChildWhichIsA(
                "ProximityPrompt",
                true
            )

        if prompt then
            return prompt
        end
    end

    return fruit:FindFirstChildWhichIsA(
        "ProximityPrompt",
        true
    )
end

function HolyFarmReadBooleanAttribute(instance, names)

    if typeof(instance) ~= "Instance" then
        return nil
    end

    for _, name in ipairs(names or {}) do

        local ok,
            value =
            pcall(function()

                return instance:GetAttribute(
                    name
                )
            end)

        if ok == true
        and value ~= nil then

            if value == true then
                return true
            end

            if value == false then
                return false
            end

            local text =
                tostring(value)
                    :lower()

            if text == "true"
            or text == "1"
            or text == "yes"
            or text == "ready"
            or text == "harvestable" then

                return true
            end

            if text == "false"
            or text == "0"
            or text == "no" then

                return false
            end
        end
    end

    return nil
end

function HolyFarmPromptUnderFruits(prompt, plant)

    if typeof(prompt) ~= "Instance"
    or typeof(plant) ~= "Instance" then

        return false
    end

    local current =
        prompt.Parent

    while current
    and current ~= plant do

        if current.Name == "Fruits" then
            return true
        end

        current =
            current.Parent
    end

    return false
end

function HolyFarmFindPlantHarvestPrompt(plant)

    if typeof(plant) ~= "Instance" then
        return nil
    end

    local prompt =
        HolyFarmFindHarvestPrompt(
            plant
        )

    if typeof(prompt) == "Instance"
    and prompt:IsA("ProximityPrompt")
    and HolyFarmPromptUnderFruits(
        prompt,
        plant
    ) ~= true then

        return prompt
    end

    return nil
end

function HolyFarmPlantHasFruitsFolder(plant)

    if typeof(plant) ~= "Instance" then
        return false
    end

    local fruitsFolder =
        plant:FindFirstChild(
            "Fruits"
        )

    return typeof(fruitsFolder) == "Instance"
end

function HolyFarmInstanceReady(instance)

    if typeof(instance) ~= "Instance"
    or instance.Parent == nil then

        return false
    end

    local age =
        HolyFarmReadNumberAttribute(
            instance,
            {
                "Age",
                "Growth",
                "GrowAge",
                "CurrentAge",
            }
        )

    local maxAge =
        HolyFarmReadNumberAttribute(
            instance,
            {
                "MaxAge",
                "MaxGrowth",
                "GrowTime",
                "GrowthTime",
                "RequiredAge",
            }
        )

    if age ~= nil
    and maxAge ~= nil then

        return age >= maxAge
    end

    local ready =
        HolyFarmReadBooleanAttribute(
            instance,
            {
                "PlantGrowthReady",
                "Ready",
                "IsReady",
                "Harvestable",
                "CanHarvest",
                "Grown",
                "FullyGrown",
                "Ripe",
            }
        )

    if ready == true then
        return true
    end

    return false
end

function HolyFarmFruitReady(fruit)

    if HolyFarmInstanceReady(
        fruit
    ) == true then

        return true
    end

    local prompt =
        HolyFarmFindHarvestPrompt(
            fruit
        )

    if typeof(prompt) == "Instance"
    and prompt:IsA("ProximityPrompt") then

        return prompt.Enabled == true
    end

    return false
end

function HolyFarmPlantLevelHarvestReady(plant)

    if typeof(plant) ~= "Instance"
    or plant.Parent == nil then

        return false
    end

    if HolyFarmPlantHasFruitsFolder(
        plant
    ) == true then

        return false
    end

    if HolyFarmInstanceReady(
        plant
    ) == true then

        return true
    end

    local prompt =
        HolyFarmFindPlantHarvestPrompt(
            plant
        )

    if typeof(prompt) == "Instance"
    and prompt:IsA("ProximityPrompt") then

        return prompt.Enabled == true
    end

    return false
end

function HolyFarmBuildFruitKey(plantId, fruitId)

    plantId =
        HolyCleanText(
            plantId
        )

    fruitId =
        HolyCleanText(
            fruitId
        )

    if plantId == ""
    or fruitId == "" then

        return ""
    end

    return plantId
        .. ":"
        .. fruitId
end

function HolyFarmBuildPlantHarvestKey(plantId)

    plantId =
        HolyCleanText(
            plantId
        )

    if plantId == "" then
        return ""
    end

    return plantId
        .. ":__PLANT_HARVEST__"
end

function HolyFarmResolveCollectFruitPacket(forceRefresh)

    local runtime =
        HolyFarmEnsureRuntime()

    if forceRefresh ~= true
    and type(runtime.CollectFruitPacket) == "table"
    and type(runtime.CollectFruitPacket.Fire) == "function" then

        return runtime.CollectFruitPacket,
            "cached"
    end

    runtime.CollectFruitPacket =
        nil

    local networking =
        nil

    if type(HolyShopRequireModule) == "function" then

        networking =
            HolyShopRequireModule(
                "SharedModules.Networking"
            )
    end

    if type(networking) ~= "table" then

        local module =
            ReplicatedStorage:FindFirstChild("SharedModules")
            and ReplicatedStorage.SharedModules:FindFirstChild("Networking")

        if typeof(module) == "Instance"
        and module:IsA("ModuleScript") == true then

            local ok,
                result =
                pcall(function()

                    return require(
                        module
                    )
                end)

            if ok == true
            and type(result) == "table" then

                networking =
                    result
            end
        end
    end

    local packet =
        type(networking) == "table"
        and type(networking.Garden) == "table"
        and networking.Garden.CollectFruit
        or nil

    if type(packet) ~= "table"
    or type(packet.Fire) ~= "function" then

        return nil,
            "Networking.Garden.CollectFruit missing"
    end

    runtime.CollectFruitPacket =
        packet

    return packet,
        "ok"
end

function HolyFarmPrimeStaticCaches(forceRefresh)

    local runtime =
        HolyFarmEnsureRuntime()

    if forceRefresh ~= true
    and runtime.StaticCachesPrimed == true then

        return true
    end

    pcall(function()

        HolyFarmBuildPlantNameCache(
            forceRefresh == true
        )
    end)

    pcall(function()

        HolyFarmBuildMutationNameCache(
            forceRefresh == true
        )
    end)

    pcall(function()

        HolyFarmLoadBaseKgCache(
            forceRefresh == true
        )
    end)

    pcall(function()

        HolyFarmResolveCollectFruitPacket(
            forceRefresh == true
        )
    end)

    pcall(function()

        HolyFarmResolveOwnPlot(
            forceRefresh == true
        )
    end)

    runtime.StaticCachesPrimed =
        true

    runtime.StaticCachesPrimedAt =
        os.clock()

    return true
end

function HolyFarmIndexerReady()

    local runtime =
        HolyFarmEnsureRuntime()

    return runtime.IndexerInstalled == true
        and typeof(runtime.OwnPlot) == "Instance"
        and runtime.OwnPlot.Parent ~= nil
        and typeof(runtime.PlantsFolder) == "Instance"
        and runtime.PlantsFolder.Parent ~= nil
end

function HolyFarmQueueFruit(plant, fruit, reason)

    local runtime =
        HolyFarmEnsureRuntime()

    if typeof(plant) ~= "Instance"
    or typeof(fruit) ~= "Instance"
    or fruit.Parent == nil then

        return false
    end

    if HolyFarmFruitReady(fruit) ~= true then
        return false
    end

    local plantName =
        HolyFarmReadPlantName(
            plant,
            fruit
        )

    if HolyFarmSelectionAllowsPlant(plantName) ~= true then
        return false
    end

    local plantId =
        HolyFarmReadPlantId(
            plant
        )

    local fruitId =
        HolyFarmReadFruitId(
            plant,
            fruit
        )

    local key =
        HolyFarmBuildFruitKey(
            plantId,
            fruitId
        )

    if key == "" then
        return false
    end

    local entry = {
        Key =
            key,

        Kind =
            "FruitHarvest",

        Plant =
            plant,

        Fruit =
            fruit,

        PlantName =
            plantName,

        PlantId =
            plantId,

        FruitId =
            fruitId,

        QueuedAt =
            os.clock(),

        Reason =
            tostring(reason or "ready"),
    }

    if HolyFarmMutationAllowsEntry(entry) ~= true then
        return false
    end

    if HolyFarmWeightAllowsEntry(entry) ~= true then
        return false
    end

    if runtime.Pending[key] ~= nil
    or runtime.ReadyMap[key] == true then

        return false
    end

    runtime.ReadyMap[key] =
        true

    table.insert(
        runtime.ReadyQueue,
        entry
    )

    return true
end

function HolyFarmQueuePlantHarvest(plant, reason)

    local runtime =
        HolyFarmEnsureRuntime()

    if typeof(plant) ~= "Instance"
    or plant.Parent == nil then

        return false
    end

    if HolyFarmPlantLevelHarvestReady(
        plant
    ) ~= true then

        return false
    end

    local plantName =
        HolyFarmReadPlantName(
            plant,
            nil
        )

    if HolyFarmSelectionAllowsPlant(
        plantName
    ) ~= true then

        return false
    end

    local plantId =
        HolyFarmReadPlantId(
            plant
        )

    local key =
        HolyFarmBuildPlantHarvestKey(
            plantId
        )

    if key == "" then
        return false
    end

    local entry = {
        Key =
            key,

        Kind =
            "PlantHarvest",

        Plant =
            plant,

        Fruit =
            plant,

        PlantName =
            plantName,

        PlantId =
            plantId,

        FruitId =
            "",

        QueuedAt =
            os.clock(),

        Reason =
            tostring(reason or "plant ready"),
    }

    if HolyFarmMutationAllowsEntry(entry) ~= true then
        return false
    end

    if HolyFarmWeightAllowsEntry(entry) ~= true then
        return false
    end

    if runtime.Pending[key] ~= nil
    or runtime.ReadyMap[key] == true then

        return false
    end

    runtime.ReadyMap[key] =
        true

    table.insert(
        runtime.ReadyQueue,
        entry
    )

    return true
end

function HolyFarmRetryEntry(entry, reason)

    if type(entry) ~= "table" then
        return false
    end

    if entry.Kind == "PlantHarvest" then

        return HolyFarmQueuePlantHarvest(
            entry.Plant,
            reason or "retry plant"
        )
    end

    return HolyFarmQueueFruit(
        entry.Plant,
        entry.Fruit,
        reason or "retry fruit"
    )
end

function HolyFarmUnwatchFruit(fruit)

    local runtime =
        HolyFarmEnsureRuntime()

    local connections =
        runtime.FruitConnections[fruit]

    HolyFarmDisconnectConnectionList(
        connections
    )

    runtime.FruitConnections[fruit] =
        nil

    runtime.WatchedFruits[fruit] =
        nil

    return true
end

function HolyFarmWatchFruit(plant, fruit)

    local runtime =
        HolyFarmEnsureRuntime()

    if typeof(plant) ~= "Instance"
    or typeof(fruit) ~= "Instance" then

        return false
    end

    if runtime.WatchedFruits[fruit] == true then

        HolyFarmQueueFruit(
            plant,
            fruit,
            "refresh"
        )

        return true
    end

    runtime.WatchedFruits[fruit] =
        true

    runtime.FruitConnections[fruit] =
        {}

    local function refreshFruit()

        task.defer(function()

            if HOLY_FARM_STATE.AutoCollectFruits == true then

                HolyFarmQueueFruit(
                    plant,
                    fruit,
                    "changed"
                )
            end
        end)
    end

    for _, attributeName in ipairs({
        "Age",
        "MaxAge",
        "Mutation",
        "Mutations",
        "SizeMulti",
        "SizeMultiplier",
        "ScaleMultiplier",
        "ScaleMulti",
        "Scale",
        "SizeScale",
    }) do

        local ok,
            signal =
            pcall(function()

                return fruit:GetAttributeChangedSignal(
                    attributeName
                )
            end)

        if ok == true
        and signal then

            table.insert(
                runtime.FruitConnections[fruit],
                signal:Connect(
                    refreshFruit
                )
            )
        end
    end

    table.insert(
        runtime.FruitConnections[fruit],
        fruit.AncestryChanged:Connect(function(_, parent)

            if parent == nil then

                local plantId =
                    HolyFarmReadPlantId(
                        plant
                    )

                local fruitId =
                    HolyFarmReadFruitId(
                        plant,
                        fruit
                    )

                local key =
                    HolyFarmBuildFruitKey(
                        plantId,
                        fruitId
                    )

                if key ~= "" then

                    runtime.ReadyMap[key] =
                        nil

                    runtime.Pending[key] =
                        nil
                end

                HolyFarmUnwatchFruit(
                    fruit
                )
            end
        end)
    )

    HolyFarmQueueFruit(
        plant,
        fruit,
        "initial"
    )

    return true
end

function HolyFarmUnwatchPlant(plant)

    local runtime =
        HolyFarmEnsureRuntime()

    if typeof(plant) == "Instance" then

        local plantId =
            HolyFarmReadPlantId(
                plant
            )

        local plantKey =
            HolyFarmBuildPlantHarvestKey(
                plantId
            )

        if plantKey ~= "" then

            runtime.ReadyMap[plantKey] =
                nil

            runtime.Pending[plantKey] =
                nil
        end
    end

    HolyFarmDisconnectConnectionList(
        runtime.PlantConnections[plant]
    )

    runtime.PlantConnections[plant] =
        nil

    runtime.WatchedPlants[plant] =
        nil

    return true
end

function HolyFarmWatchPlant(plant)

    local runtime =
        HolyFarmEnsureRuntime()

    if typeof(plant) ~= "Instance" then
        return false
    end

    if runtime.WatchedPlants[plant] == true then

        HolyFarmQueuePlantHarvest(
            plant,
            "plant refresh"
        )

        return true
    end

    runtime.WatchedPlants[plant] =
        true

    runtime.PlantConnections[plant] =
        {}

    local plantPromptConnected =
        false

    local function refreshPlantHarvest()

        task.defer(function()

            if HOLY_FARM_STATE.AutoCollectFruits == true then

                HolyFarmQueuePlantHarvest(
                    plant,
                    "plant changed"
                )
            end
        end)
    end

    local function connectPlantHarvestPrompt()

        if plantPromptConnected == true then
            return false
        end

        local prompt =
            HolyFarmFindPlantHarvestPrompt(
                plant
            )

        if typeof(prompt) ~= "Instance"
        or prompt:IsA("ProximityPrompt") ~= true then

            return false
        end

        plantPromptConnected =
            true

        table.insert(
            runtime.PlantConnections[plant],
            prompt:GetPropertyChangedSignal("Enabled"):Connect(
                refreshPlantHarvest
            )
        )

        return true
    end

    for _, attributeName in ipairs({
        "Age",
        "MaxAge",
        "Mutation",
        "Mutations",
        "PlantGrowthReady",
        "Ready",
        "IsReady",
        "Harvestable",
        "CanHarvest",
        "Grown",
        "FullyGrown",
        "Ripe",
        "SizeMulti",
        "SizeMultiplier",
        "ScaleMultiplier",
        "ScaleMulti",
        "Scale",
        "SizeScale",
    }) do

        local ok,
            signal =
            pcall(function()

                return plant:GetAttributeChangedSignal(
                    attributeName
                )
            end)

        if ok == true
        and signal then

            table.insert(
                runtime.PlantConnections[plant],
                signal:Connect(
                    refreshPlantHarvest
                )
            )
        end
    end

    local function attachFruitsFolder(fruitsFolder)

        if typeof(fruitsFolder) ~= "Instance" then
            return false
        end

        for _, fruit in ipairs(fruitsFolder:GetChildren()) do

            HolyFarmWatchFruit(
                plant,
                fruit
            )
        end

        table.insert(
            runtime.PlantConnections[plant],
            fruitsFolder.ChildAdded:Connect(function(fruit)

                task.defer(function()

                    HolyFarmWatchFruit(
                        plant,
                        fruit
                    )
                end)
            end)
        )

        table.insert(
            runtime.PlantConnections[plant],
            fruitsFolder.ChildRemoved:Connect(function(fruit)

                local plantId =
                    HolyFarmReadPlantId(
                        plant
                    )

                local fruitId =
                    HolyFarmReadFruitId(
                        plant,
                        fruit
                    )

                local key =
                    HolyFarmBuildFruitKey(
                        plantId,
                        fruitId
                    )

                if key ~= "" then

                    runtime.ReadyMap[key] =
                        nil

                    runtime.Pending[key] =
                        nil
                end

                HolyFarmUnwatchFruit(
                    fruit
                )
            end)
        )

        return true
    end

    attachFruitsFolder(
        plant:FindFirstChild(
            "Fruits"
        )
    )

    connectPlantHarvestPrompt()

    HolyFarmQueuePlantHarvest(
        plant,
        "initial plant"
    )

    table.insert(
        runtime.PlantConnections[plant],
        plant.ChildAdded:Connect(function(child)

            if child.Name == "Fruits" then

                task.defer(function()

                    attachFruitsFolder(
                        child
                    )
                end)

            elseif child.Name == "HarvestPart" then

                task.defer(function()

                    connectPlantHarvestPrompt()

                    refreshPlantHarvest()
                end)
            end
        end)
    )

    table.insert(
        runtime.PlantConnections[plant],
        plant.AncestryChanged:Connect(function(_, parent)

            if parent == nil then

                HolyFarmUnwatchPlant(
                    plant
                )
            end
        end)
    )

    return true
end

function HolyFarmInstallIndexer(forceRefresh)

    local runtime =
        HolyFarmEnsureRuntime()

    local plot =
        HolyFarmResolveOwnPlot(
            forceRefresh == true
        )

    if typeof(plot) ~= "Instance" then
        return false, "own plot missing"
    end

    local plantsFolder =
        plot:FindFirstChild(
            "Plants"
        )

    if typeof(plantsFolder) ~= "Instance" then
        return false, "plants folder missing"
    end

    if forceRefresh ~= true
    and runtime.PlantsFolder == plantsFolder
    and runtime.IndexerInstalled == true then

        return true, "cached"
    end

    HolyFarmDisconnectConnectionMap(
        runtime.Connections
    )

    HolyFarmDisconnectConnectionMap(
        runtime.PlantConnections
    )

    HolyFarmDisconnectConnectionMap(
        runtime.FruitConnections
    )

    runtime.Connections =
        {}

    runtime.PlantConnections =
        {}

    runtime.FruitConnections =
        {}

    runtime.WatchedPlants =
        {}

    runtime.WatchedFruits =
        {}

    runtime.ReadyQueue =
        {}

    runtime.ReadyMap =
        {}

    runtime.Pending =
        {}

    runtime.OwnPlot =
        plot

    runtime.PlantsFolder =
        plantsFolder

    runtime.IndexerInstalled =
        true

    for _, plant in ipairs(plantsFolder:GetChildren()) do

        HolyFarmWatchPlant(
            plant
        )
    end

    table.insert(
        runtime.Connections,
        plantsFolder.ChildAdded:Connect(function(plant)

            task.defer(function()

                HolyFarmWatchPlant(
                    plant
                )
            end)
        end)
    )

    table.insert(
        runtime.Connections,
        plantsFolder.ChildRemoved:Connect(function(plant)

            HolyFarmUnwatchPlant(
                plant
            )
        end)
    )

    return true, "ok"
end

function HolyFarmRebuildReadyQueue(reason)

    local runtime =
        HolyFarmEnsureRuntime()

    runtime.ReadyQueue =
        {}

    runtime.ReadyMap =
        {}

    runtime.Pending =
        {}

    if typeof(runtime.PlantsFolder) ~= "Instance"
    or runtime.PlantsFolder.Parent == nil then

        return false
    end

    for _, plant in ipairs(runtime.PlantsFolder:GetChildren()) do

        HolyFarmWatchPlant(
            plant
        )

        local fruitsFolder =
            plant:FindFirstChild(
                "Fruits"
            )

        if typeof(fruitsFolder) == "Instance" then

            for _, fruit in ipairs(fruitsFolder:GetChildren()) do

                HolyFarmQueueFruit(
                    plant,
                    fruit,
                    reason or "rebuild"
                )
            end

        else

            HolyFarmQueuePlantHarvest(
                plant,
                reason or "rebuild plant"
            )
        end
    end

    return true
end

function HolyFarmCollectEntry(entry)

    local runtime =
        HolyFarmEnsureRuntime()

    if type(entry) ~= "table" then
        return false
    end

    if typeof(entry.Plant) ~= "Instance"
    or entry.Plant.Parent == nil then

        return false
    end

    local key =
        ""

    if entry.Kind == "PlantHarvest" then

        if HolyFarmPlantLevelHarvestReady(
            entry.Plant
        ) ~= true then

            return false
        end

        key =
            HolyFarmBuildPlantHarvestKey(
                entry.PlantId
            )

    else

        if typeof(entry.Fruit) ~= "Instance"
        or entry.Fruit.Parent == nil then

            return false
        end

        if HolyFarmFruitReady(
            entry.Fruit
        ) ~= true then

            return false
        end

        key =
            HolyFarmBuildFruitKey(
                entry.PlantId,
                entry.FruitId
            )
    end

    if HolyFarmSelectionAllowsPlant(entry.PlantName) ~= true then
        return false
    end

    if HolyFarmMutationAllowsEntry(entry) ~= true then
        return false
    end

    if HolyFarmWeightAllowsEntry(entry) ~= true then
        return false
    end

    if key == "" then
        return false
    end

    entry.Key =
        key

    if runtime.Pending[key] ~= nil then
        return false
    end

    local packet,
        packetReason =
        HolyFarmResolveCollectFruitPacket(
            false
        )

    if type(packet) ~= "table" then

        local now =
            os.clock()

        if now - (
            tonumber(runtime.LastPacketWarnAt)
            or 0
        ) > 5 then

            runtime.LastPacketWarnAt =
                now

            if type(HolyNotify) == "function" then

                HolyNotify(
                    "HOLY Farm",
                    tostring(packetReason or "CollectFruit packet missing."),
                    4
                )
            end
        end

        return false
    end

    runtime.Pending[key] = {
        At =
            os.clock(),

        Entry =
            entry,
    }

    local ok,
        result =
        pcall(function()

            if entry.Kind == "PlantHarvest" then

                return packet:Fire(
                    entry.PlantId,
                    ""
                )
            end

            return packet:Fire(
                entry.PlantId,
                entry.FruitId
            )
        end)

    if ok ~= true then

        runtime.Pending[key] =
            nil

        task.delay(0.35, function()

            if HOLY_FARM_STATE.AutoCollectFruits == true then

                HolyFarmRetryEntry(
                    entry,
                    "retry"
                )
            end
        end)

        return false,
            tostring(result)
    end

    return true
end

function HolyFarmPrunePending()

    local runtime =
        HolyFarmEnsureRuntime()

    local now =
        os.clock()

    for key, row in pairs(runtime.Pending) do

        local entry =
            type(row) == "table"
            and row.Entry
            or nil

        local at =
            type(row) == "table"
            and tonumber(row.At)
            or 0

        local missing =
            false

        if type(entry) ~= "table" then

            missing =
                true

        elseif entry.Kind == "PlantHarvest" then

            missing =
                typeof(entry.Plant) ~= "Instance"
                or entry.Plant.Parent == nil

        else

            missing =
                typeof(entry.Fruit) ~= "Instance"
                or entry.Fruit.Parent == nil
        end

        if missing == true then

            runtime.Pending[key] =
                nil

            runtime.ReadyMap[key] =
                nil

        elseif now - at >= 3 then

            runtime.Pending[key] =
                nil

            HolyFarmRetryEntry(
                entry,
                "pending retry"
            )
        end
    end
end

function HolyFarmAutoCollectBlocked()

    local sniper =
        type(HOLY_SNIPER_RUNTIME) == "table"
        and HOLY_SNIPER_RUNTIME
        or {}

    if sniper.Buying == true
    or sniper.Returning == true
    or sniper.AutoHopInProgress == true
    or sniper.CurrentTarget ~= nil
    or HolyCleanText(sniper.CurrentTargetKey) ~= "" then

        return true
    end

    return false
end

function HolyFarmRunAutoCollectWorker(token)

    local runtime =
        HolyFarmEnsureRuntime()

    runtime.Running =
        true

    runtime.LastIndexerCheckAt =
        0

    while runtime.Token == token
    and HOLY_FARM_STATE.AutoCollectFruits == true do

        if HolyFarmAutoCollectBlocked() == true then

            task.wait(
                0.20
            )

            continue
        end

        local now =
            os.clock()

        if HolyFarmIndexerReady() ~= true
        or now - (
            tonumber(runtime.LastIndexerCheckAt)
            or 0
        ) >= 5 then

            runtime.LastIndexerCheckAt =
                now

            local installed =
                HolyFarmInstallIndexer(
                    false
                )

            if installed ~= true then

                if now - (
                    tonumber(runtime.LastPlotWarnAt)
                    or 0
                ) > 8 then

                    runtime.LastPlotWarnAt =
                        now

                    print(
                        "[HOLY FARM]",
                        "Waiting for own plot / Plants folder."
                    )
                end

                task.wait(
                    0.75
                )

                continue
            end
        end

        HolyFarmPrunePending()

        local entry =
            table.remove(
                runtime.ReadyQueue,
                1
            )

        if type(entry) == "table" then

            runtime.ReadyMap[entry.Key] =
                nil

            HolyFarmCollectEntry(
                entry
            )

            task.wait(
                0.045
            )

        else

            task.wait(
                0.20
            )
        end
    end

    if runtime.Token == token then

        runtime.Running =
            false
    end
end

function HolyFarmStartAutoCollect(reason)

    HolyFarmEnsureState()

    if HOLY_FARM_STATE.AutoCollectFruits ~= true then
        return false
    end

    local runtime =
        HolyFarmEnsureRuntime()

    if runtime.Running == true then
        return false
    end

    HolyFarmPrimeStaticCaches(
        false
    )

    runtime.Token =
        {}

    local token =
        runtime.Token

    local installed =
        HolyFarmInstallIndexer(
            false
        )

    if installed == true then

        HolyFarmRebuildReadyQueue(
            reason or "start"
        )
    end

    task.spawn(function()

        HolyFarmRunAutoCollectWorker(
            token
        )
    end)

    return true
end

function HolyFarmStopAutoCollect(reason)

    local runtime =
        HolyFarmEnsureRuntime()

    runtime.Token =
        nil

    runtime.Running =
        false

    HolyFarmDisconnectIndexer()

    return true
end

function HolyFarmSetAutoCollectFruits(value)

    HolyFarmEnsureState()

    HOLY_FARM_STATE.AutoCollectFruits =
        value == true

    HolySaveFarmSettings()

    if HOLY_FARM_STATE.AutoCollectFruits == true then

        return HolyFarmStartAutoCollect(
            "toggle on"
        )
    end

    return HolyFarmStopAutoCollect(
        "toggle off"
    )
end

function HolySniperNormalizeAnySelection(value)

    local selection =
        HolyShopSelectionArray(
            value
        )

    if #selection <= 0 then

        return {
            "Any",
        }
    end

    for _, itemName in ipairs(selection) do

        if itemName == "Any" then

            return {
                "Any",
            }
        end
    end

    return selection
end

function HolySniperGetPetSizesModule()

    local petSizes =
        HolyDataGetModule(
            "PetSizes"
        )

    if type(petSizes) ~= "table" then
        return {}
    end

    return petSizes
end

function HolySniperGetPetTypesModule()

    local petTypes =
        HolyDataGetModule(
            "PetTypes"
        )

    if type(petTypes) ~= "table" then
        return {}
    end

    return petTypes
end

function HolySniperNormalizeSizeName(value)

    local text =
        HolyCleanText(
            value
        )

    local lower =
        text:lower()

    if lower == ""
    or lower == "none"
    or lower == "nil"
    or lower == "normal"
    or lower == "regular" then

        return "Normal"
    end

    if lower == "mega"
    or lower == "huge" then

        return "Huge"
    end

    local petSizes =
        HolySniperGetPetSizesModule()

    if type(petSizes.Normalize) == "function" then

        local ok,
            result =
            pcall(function()

                return petSizes.Normalize(
                    text
                )
            end)

        result =
            HolyCleanText(
                ok == true
                and result
                or ""
            )

        if result ~= "" then

            if result == "Mega" then
                return "Huge"
            end

            return result
        end
    end

    return text
end

function HolySniperAddSortedValue(values, seen, value)

    value =
        HolyCleanText(
            value
        )

    if value == "" then
        return false
    end

    if value == "Mega" then
        value =
            "Huge"
    end

    if seen[value] == true then
        return false
    end

    seen[value] =
        true

    table.insert(
        values,
        value
    )

    return true
end

function HolySniperSortSizeValues(values)

    table.sort(values, function(a, b)

        local order = {
            Any = 0,
            Normal = 1,
            Big = 2,
            Huge = 3,
        }

        local rankA =
            order[a]
            or 50

        local rankB =
            order[b]
            or 50

        if rankA ~= rankB then
            return rankA < rankB
        end

        return tostring(a) < tostring(b)
    end)
end

function HolySniperSortVariantValues(values)

    table.sort(values, function(a, b)

        local order = {
            Any = 0,
            Normal = 1,
            Rainbow = 2,
        }

        local rankA =
            order[a]
            or 50

        local rankB =
            order[b]
            or 50

        if rankA ~= rankB then
            return rankA < rankB
        end

        return tostring(a) < tostring(b)
    end)
end

function HolySniperGetSizeValues()

    local values =
        {}

    local seen =
        {}

    HolySniperAddSortedValue(
        values,
        seen,
        "Any"
    )

    HolySniperAddSortedValue(
        values,
        seen,
        "Normal"
    )

    local petSizes =
        HolySniperGetPetSizesModule()

    local function addSizeFromKey(key)

        key =
            HolyCleanText(
                key
            )

        if key == "" then
            return
        end

        local normalized =
            HolySniperNormalizeSizeName(
                key
            )

        if normalized ~= ""
        and normalized ~= "Normal" then

            HolySniperAddSortedValue(
                values,
                seen,
                normalized
            )
        end
    end

    if type(petSizes.Scales) == "table" then

        for key in pairs(petSizes.Scales) do

            addSizeFromKey(
                key
            )
        end
    end

    if type(petSizes.BoostMultipliers) == "table" then

        for key in pairs(petSizes.BoostMultipliers) do

            addSizeFromKey(
                key
            )
        end
    end

    HolySniperSortSizeValues(
        values
    )

    return values
end

function HolySniperSizeValueMap()

    local map =
        {}

    for _, value in ipairs(HolySniperGetSizeValues()) do

        if value ~= "Any" then

            map[value] =
                true
        end
    end

    return map
end

function HolySniperNormalizeSizeSelection(value)

    local selection =
        HolyShopSelectionArray(
            value
        )

    if #selection <= 0 then

        return {
            "Any",
        }
    end

    for _, itemName in ipairs(selection) do

        if itemName == "Any" then

            return {
                "Any",
            }
        end
    end

    local validMap =
        HolySniperSizeValueMap()

    local output =
        {}

    local seen =
        {}

    for _, itemName in ipairs(selection) do

        local normalized =
            HolySniperNormalizeSizeName(
                itemName
            )

        if validMap[normalized] == true
        and seen[normalized] ~= true then

            seen[normalized] =
                true

            table.insert(
                output,
                normalized
            )
        end
    end

    if #output <= 0 then

        return {
            "Normal",
        }
    end

    HolySniperSortSizeValues(
        output
    )

    return output
end

function HolySniperPetTypeIsValid(typeName)

    typeName =
        HolyCleanText(
            typeName
        )

    if typeName == "" then
        return false
    end

    if typeName == "Normal" then
        return true
    end

    local petTypes =
        HolySniperGetPetTypesModule()

    if type(petTypes.IsValid) == "function" then

        local ok,
            result =
            pcall(function()

                return petTypes.IsValid(
                    typeName
                )
            end)

        if ok == true then
            return result == true
        end
    end

    return false
end

function HolySniperNormalizeVariantName(value)

    local text =
        HolyCleanText(
            value
        )

    local lower =
        text:lower()

    if lower == ""
    or lower == "none"
    or lower == "nil"
    or lower == "normal"
    or lower == "regular" then

        return "Normal"
    end

    return text
end

function HolySniperGetVariantValues()

    local values =
        {}

    local seen =
        {}

    HolySniperAddSortedValue(
        values,
        seen,
        "Any"
    )

    HolySniperAddSortedValue(
        values,
        seen,
        "Normal"
    )

    local petTypes =
        HolySniperGetPetTypesModule()

    for key, value in pairs(petTypes) do

        if type(value) == "string" then

            local normalized =
                HolySniperNormalizeVariantName(
                    value
                )

            if normalized ~= "Normal"
            and HolySniperPetTypeIsValid(normalized) == true then

                HolySniperAddSortedValue(
                    values,
                    seen,
                    normalized
                )
            end
        end

        if type(key) == "string"
        and type(value) ~= "function"
        and key ~= "BOOST_MULTIPLIER" then

            local normalized =
                HolySniperNormalizeVariantName(
                    key
                )

            if normalized ~= "Normal"
            and HolySniperPetTypeIsValid(normalized) == true then

                HolySniperAddSortedValue(
                    values,
                    seen,
                    normalized
                )
            end
        end
    end

    -- Safe fallback only if the module did not expose string variants.
    if seen.Rainbow ~= true
    and HolySniperPetTypeIsValid("Rainbow") == true then

        HolySniperAddSortedValue(
            values,
            seen,
            "Rainbow"
        )
    end

    HolySniperSortVariantValues(
        values
    )

    return values
end

function HolySniperVariantValueMap()

    local map =
        {}

    for _, value in ipairs(HolySniperGetVariantValues()) do

        if value ~= "Any" then

            map[value] =
                true
        end
    end

    return map
end

function HolySniperNormalizeVariantSelection(value)

    local selection =
        HolyShopSelectionArray(
            value
        )

    if #selection <= 0 then

        return {
            "Any",
        }
    end

    for _, itemName in ipairs(selection) do

        if itemName == "Any" then

            return {
                "Any",
            }
        end
    end

    local validMap =
        HolySniperVariantValueMap()

    local output =
        {}

    local seen =
        {}

    for _, itemName in ipairs(selection) do

        local normalized =
            HolySniperNormalizeVariantName(
                itemName
            )

        -- Gold is ignored unless PetTypes ever marks it as valid.
        if validMap[normalized] == true
        and seen[normalized] ~= true then

            seen[normalized] =
                true

            table.insert(
                output,
                normalized
            )
        end
    end

    if #output <= 0 then

        return {
            "Normal",
        }
    end

    HolySniperSortVariantValues(
        output
    )

    return output
end

function HolySniperNormalizePriority(value)

    local text =
        HolyCleanText(
            value
        )
        :lower()

    if text:find("high", 1, true) then
        return "High"
    end

    if text:find("low", 1, true) then
        return "Low"
    end

    return "Medium"
end

function HolySniperNormalizeMovementMode(value)

    local text =
        HolyCleanText(
            value
        )
        :lower()

    if text:find("teleport", 1, true) then
        return "Teleport"
    end

    return "Walk"
end

function HolyDefenseNormalizeMovement(value)

    local text =
        HolyCleanText(
            value
        )
        :lower()

    if text:find("hybrid", 1, true) then
        return "Hybrid"
    end

    if text:find("tween", 1, true) then
        return "Tween"
    end

    return "Walk"
end

function HolyDefenseNormalizeGear(value)

    local text =
        HolyCleanText(
            value
        )

    local lower =
        text:lower()

    if lower == "shovel" then
        return "Shovel"
    end

    return "Strawberry Sniper"
end

function HolySniperNormalizeBuyMode(value)

    local text =
        HolyCleanText(
            value
        )
        :lower()

    if text:find("hold", 1, true) then
        return "Hold"
    end

    return "Instant"
end

function HolySniperNormalizeReturnTiming(value)

    local text =
        HolyCleanText(
            value
        )
        :lower()

    if text:find("each", 1, true)
    or text:find("buy", 1, true) then

        return "After Buy"
    end

    return "After Batch"
end

function HolySniperNormalizeReturnMode(value)

    local text =
        HolyCleanText(
            value
        )
        :lower()

    if text:find("teleport", 1, true) then
        return "Teleport"
    end

    return "Walk"
end

function HolySniperNormalizeReturnDestination(value)

    local text =
        HolyCleanText(
            value
        )
        :lower()

    if text:find("saved", 1, true)
    or text:find("position", 1, true) then

        return "Saved Position"
    end

    return "Farm Center"
end

function HolySniperNormalizeAutoHopTiming(value)

    local text =
        HolyCleanText(
            value
        )
        :lower()

    if text:find("fast", 1, true)
    or text:find("during", 1, true)
    or text:find("before", 1, true) then

        return "Fast - During Loading"
    end

    return "Safe - After Loading"
end

function HolySniperReadHopDelay(value)

    local text =
        HolyCleanText(
            value
        )

    text =
        text:gsub(
            "[sS]",
            ""
        )

    local number =
        tonumber(
            text
        )

    if not number then

        number =
            5
    end

    return math.max(
        0,
        number
    )
end

function HolySniperFormatDelay(value)

    local number =
        HolySniperReadHopDelay(
            value
        )

    if math.abs(number - math.floor(number)) < 0.001 then

        return tostring(
            math.floor(number)
        )
    end

    return tostring(
        math.floor(number * 100 + 0.5) / 100
    )
end

function HolySniperReadAmount(value)

    local amount =
        math.floor(
            tonumber(value)
            or 999
        )

    return math.clamp(
        amount,
        1,
        999
    )
end

function HolySniperReadMaxPrice(value)

    local text =
        HolyCleanText(
            value
        )

    text =
        text:gsub("¢", "")
            :gsub("%$", "")
            :gsub(",", "")
            :gsub("%s+", "")

    local lower =
        text:lower()

    if lower == ""
    or lower == "0"
    or lower == "none"
    or lower == "off"
    or lower == "no" then

        return 0
    end

    local multiplier =
        1

    if lower:find("b", 1, true) then

        multiplier =
            1000000000

    elseif lower:find("m", 1, true) then

        multiplier =
            1000000

    elseif lower:find("k", 1, true) then

        multiplier =
            1000
    end

    local rawNumber =
        lower:match("%d+%.?%d*")

    local number =
        tonumber(rawNumber)

    if number == nil then
        return 0
    end

    return math.max(
        0,
        math.floor(number * multiplier + 0.5)
    )
end

function HolySniperFormatMaxPrice(value)

    local number =
        HolySniperReadMaxPrice(
            value
        )

    if number <= 0 then
        return "No Cap"
    end

    return "Max "
        .. HolySniperFormatMoney(
            number
        )
end

function HolySniperArrayText(values, fallback)

    values =
        HolyShopSelectionArray(
            values
        )

    fallback =
        tostring(fallback or "Any")

    if #values <= 0 then
        return fallback
    end

    if #values == 1
    and values[1] == "Any" then
        return fallback
    end

    return table.concat(
        values,
        "/"
    )
end

function HolySniperGetPetData()

    local petData =
        HolyDataGetModule(
            "PetData"
        )

    if type(petData) ~= "table" then
        return {}
    end

    return petData
end

function HolySniperIsPetDataRow(key, row)

    if type(key) ~= "string" then
        return false
    end

    if type(row) ~= "table" then
        return false
    end

    if type(row.DisplayName) == "string"
    or type(row.BasePrice) == "number"
    or type(row.Rarity) == "string"
    or type(row.SpawnChance) == "number" then

        return true
    end

    return false
end

function HolySniperPetAliasKey(value)

    return HolyCleanText(
        value
    )
        :lower()
        :gsub("[%s_%-%[%]%(%)%.]", "")
end

function HolySniperBuildPetMaps()

    local values = {
        "Any Pet",
    }

    local seen = {
        ["Any Pet"] = true,
    }

    local displayToKey = {
        ["Any Pet"] = "*",
    }

    local keyToDisplay = {
        ["*"] = "Any Pet",
    }

    local petData =
        HolySniperGetPetData()

    for key, row in pairs(petData) do

        if HolySniperIsPetDataRow(key, row) == true then

            local internalKey =
                HolyCleanText(
                    key
                )

            local displayName =
                HolyCleanText(
                    row.DisplayName
                    or row.PetName
                    or row.Name
                    or key
                )

            if internalKey ~= ""
            and displayName ~= "" then

                if seen[displayName] ~= true then

                    seen[displayName] =
                        true

                    table.insert(
                        values,
                        displayName
                    )
                end

                displayToKey[displayName] =
                    internalKey

                keyToDisplay[internalKey] =
                    displayName
            end
        end
    end

    table.sort(values, function(a, b)

        if a == "Any Pet" then
            return true
        end

        if b == "Any Pet" then
            return false
        end

        return tostring(a) < tostring(b)
    end)

    if #values <= 1 then

        values = {
            "Any Pet",
            "Raccoon",
        }

        displayToKey["Any Pet"] =
            "*"

        displayToKey.Raccoon =
            "Raccoon"

        keyToDisplay["*"] =
            "Any Pet"

        keyToDisplay.Raccoon =
            "Raccoon"
    end

    HOLY_SNIPER_STATE.PetDisplayToKey =
        displayToKey

    HOLY_SNIPER_STATE.PetKeyToDisplay =
        keyToDisplay

    return values,
        displayToKey,
        keyToDisplay
end

function HolySniperGetPetValues()

    local values =
        HolySniperBuildPetMaps()

    return values
end

function HolySniperGetDefaultPetName()

    local values =
        HolySniperGetPetValues()

    for _, petName in ipairs(values) do

        if petName == "Raccoon" then
            return "Raccoon"
        end
    end

    return values[1]
        or "Raccoon"
end

function HolySniperResolvePetKey(value)

    local text =
        HolyCleanText(
            value
        )

    local lower =
        text:lower()

    if lower == "any"
    or lower == "all"
    or lower == "any pet"
    or lower == "all pets"
    or lower == "*" then

        return "*"
    end

    if text == "" then
        return "Raccoon"
    end

    HolySniperGetPetValues()

    local displayToKey =
        type(HOLY_SNIPER_STATE.PetDisplayToKey) == "table"
        and HOLY_SNIPER_STATE.PetDisplayToKey
        or {}

    local keyToDisplay =
        type(HOLY_SNIPER_STATE.PetKeyToDisplay) == "table"
        and HOLY_SNIPER_STATE.PetKeyToDisplay
        or {}

    if displayToKey[text] then
        return displayToKey[text]
    end

    if keyToDisplay[text] then
        return text
    end

    local wantedAlias =
        HolySniperPetAliasKey(
            text
        )

    for internalKey, displayName in pairs(keyToDisplay) do

        if HolySniperPetAliasKey(internalKey) == wantedAlias
        or HolySniperPetAliasKey(displayName) == wantedAlias then

            return internalKey
        end
    end

    return text
end

function HolySniperResolvePetDisplay(value)

    local text =
        HolyCleanText(
            value
        )

    local lower =
        text:lower()

    if lower == "any"
    or lower == "all"
    or lower == "any pet"
    or lower == "all pets"
    or lower == "*" then

        return "Any Pet"
    end

    if text == "" then
        return HolySniperGetDefaultPetName()
    end

    HolySniperGetPetValues()

    local displayToKey =
        type(HOLY_SNIPER_STATE.PetDisplayToKey) == "table"
        and HOLY_SNIPER_STATE.PetDisplayToKey
        or {}

    local keyToDisplay =
        type(HOLY_SNIPER_STATE.PetKeyToDisplay) == "table"
        and HOLY_SNIPER_STATE.PetKeyToDisplay
        or {}

    if displayToKey[text] then
        return text
    end

    if keyToDisplay[text] then
        return keyToDisplay[text]
    end

    local wantedAlias =
        HolySniperPetAliasKey(
            text
        )

    for internalKey, displayName in pairs(keyToDisplay) do

        if HolySniperPetAliasKey(internalKey) == wantedAlias
        or HolySniperPetAliasKey(displayName) == wantedAlias then

            return displayName
        end
    end

    return text
end

function HolySniperNormalizeFilter(row)

    row =
        type(row) == "table"
        and row
        or {}

    local rawPet =
        row.Pet
        or row.PetName
        or row.Name
        or HolySniperGetDefaultPetName()

    local petName =
        HolySniperResolvePetDisplay(
            rawPet
        )

    if petName == "" then

        petName =
            HolySniperGetDefaultPetName()
    end

    local maxPrice =
        HolySniperReadMaxPrice(
            row.MaxPrice
            or row.Max
            or row.PriceLimit
            or row.BuilderMaxPrice
            or 0
        )

    return {
        Pet =
            petName,

        PetKey =
            HolySniperResolvePetKey(
                petName
            ),

        Sizes =
            HolySniperNormalizeSizeSelection(
                row.Sizes
                or row.Size
                or {
                    "Any",
                }
            ),

        Variants =
            HolySniperNormalizeVariantSelection(
                row.Variants
                or row.Variant
                or {
                    "Any",
                }
            ),

        MaxPrice =
            maxPrice,

        Amount =
            999,

        Priority =
            HolySniperNormalizePriority(
                row.Priority
                or "Medium"
            ),

        Enabled =
            row.Enabled ~= false,
    }
end

function HolySniperNormalizeWatchlist(value)

    local output =
        {}

    if type(value) ~= "table" then
        return output
    end

    for _, row in ipairs(value) do

        table.insert(
            output,
            HolySniperNormalizeFilter(
                row
            )
        )
    end

    return output
end

function HolySniperFilterKey(row)

    row =
        HolySniperNormalizeFilter(
            row
        )

    return table.concat({
        HolyCleanText(
            row.PetKey
            or HolySniperResolvePetKey(
                row.Pet
            )
        ):lower(),

        HolySniperArrayText(row.Sizes, "Any"):lower(),

        HolySniperArrayText(row.Variants, "Any"):lower(),

        tostring(
            tonumber(row.MaxPrice)
            or 0
        ),
    }, "|")
end

function HolySniperGetBasePrice(row)

    local petKey =
        ""

    if type(row) == "table" then

        petKey =
            HolyCleanText(
                row.PetKey
                or HolySniperResolvePetKey(
                    row.Pet
                )
            )

    else

        petKey =
            HolyCleanText(
                HolySniperResolvePetKey(
                    row
                )
            )
    end

    if petKey == "" then
        return 0
    end

    local petData =
        HolySniperGetPetData()

    local data =
        type(petData) == "table"
        and petData[petKey]
        or nil

    if type(data) ~= "table" then
        return 0
    end

    return tonumber(data.BasePrice)
        or 0
end

function HolySniperFormatMoney(value)

    value =
        math.max(
            0,
            tonumber(value)
            or 0
        )

    if value >= 1000000 then

        return "$"
            .. string.format(
                "%.1fM",
                value / 1000000
            )
    end

    if value >= 1000 then

        return "$"
            .. string.format(
                "%.0fK",
                value / 1000
            )
    end

    return "$"
        .. tostring(
            math.floor(value)
        )
end

function HolySniperShortValue(value)

    value =
        HolyCleanText(
            value
        )

    if value == "Mega" then
        return "Huge"
    end

    if value == "Rainbow" then
        return "Rb"
    end

    if value == "Normal" then
        return "Norm"
    end

    return value
end

function HolySniperShortArrayText(values, fallback)

    values =
        HolyShopSelectionArray(
            values
        )

    fallback =
        tostring(fallback or "Any")

    if #values <= 0 then
        return fallback
    end

    if #values == 1
    and values[1] == "Any" then
        return fallback
    end

    local output =
        {}

    for _, value in ipairs(values) do

        if value ~= "Any" then

            table.insert(
                output,
                HolySniperShortValue(
                    value
                )
            )
        end
    end

    if #output <= 0 then
        return fallback
    end

    return table.concat(
        output,
        "+"
    )
end

function HolySniperPriorityRank(value)

    value =
        HolySniperNormalizePriority(
            value
        )

    if value == "High" then
        return 1
    end

    if value == "Medium" then
        return 2
    end

    return 3
end

function HolySniperPriorityShort(value)

    value =
        HolySniperNormalizePriority(
            value
        )

    return value:sub(
        1,
        1
    )
end

function HolySniperSortWatchlist(watchlist)

    table.sort(watchlist, function(a, b)

        local priceA =
            tonumber(a.ValueNumber)
            or HolySniperGetBasePrice(a)

        local priceB =
            tonumber(b.ValueNumber)
            or HolySniperGetBasePrice(b)

        if priceA ~= priceB then
            return priceA > priceB
        end

        local rankA =
            HolySniperPriorityRank(
                a.Priority
            )

        local rankB =
            HolySniperPriorityRank(
                b.Priority
            )

        if rankA ~= rankB then
            return rankA < rankB
        end

        return tostring(a.Pet) < tostring(b.Pet)
    end)

    return watchlist
end

function HolySniperMatchesSearch(row, searchText)

    searchText =
        HolyCleanText(
            searchText
        )
        :lower()

    if searchText == "" then
        return true
    end

    local haystack =
        table.concat({
            tostring(row.Pet or ""),
            tostring(row.PetKey or ""),
            tostring(row.Value or ""),
            tostring(row.Size or ""),
            tostring(row.Variant or ""),
            tostring(row.MaxPrice or ""),
            tostring(row.Amount or ""),
            tostring(row.Priority or ""),
            tostring(row.PriorityFull or ""),
        }, " "):lower()

    return haystack:find(
        searchText,
        1,
        true
    ) ~= nil
end

function HolySniperBuildAllWatchlistRows()

    local rows =
        {}

    local searchText =
        HolyCleanText(
            HOLY_SNIPER_STATE.WatchlistSearch
            or ""
        )

    for sourceIndex, row in ipairs(HOLY_SNIPER_STATE.Watchlist or {}) do

        local filter =
            HolySniperNormalizeFilter(
                row
            )

        local price =
            HolySniperGetBasePrice(
                filter
            )

        local maxPriceText =
            HolySniperFormatMaxPrice(
                filter.MaxPrice
            )

        local tableRow = {
            SourceIndex =
                sourceIndex,

            Pet =
                tostring(filter.Pet),

            PetKey =
                tostring(filter.PetKey),

            Value =
                HolySniperFormatMoney(
                    price
                ),

            ValueNumber =
                price,

            MaxPrice =
                maxPriceText,

            MaxPriceNumber =
                tonumber(filter.MaxPrice)
                or 0,

            Size =
                HolySniperShortArrayText(
                    filter.Sizes,
                    "Any"
                ),

            Variant =
                HolySniperShortArrayText(
                    filter.Variants,
                    "Any"
                ),

            Amount =
                maxPriceText,

            AmountNumber =
                tonumber(filter.MaxPrice)
                or 0,

            Priority =
                HolySniperPriorityShort(
                    filter.Priority
                ),

            PriorityFull =
                HolySniperNormalizePriority(
                    filter.Priority
                ),
        }

        if HolySniperMatchesSearch(
            tableRow,
            searchText
        ) == true then

            table.insert(
                rows,
                tableRow
            )
        end
    end

    HolySniperSortWatchlist(
        rows
    )

    return rows
end

function HolySniperGetWatchlistPageSize()

    local pageSize =
        math.floor(
            tonumber(
                HOLY_SNIPER_STATE.WatchlistPageSize
            )
            or 7
        )

    return math.clamp(
        pageSize,
        1,
        20
    )
end

function HolySniperGetWatchlistPageCount(totalRows)

    totalRows =
        math.max(
            0,
            math.floor(
                tonumber(totalRows)
                or 0
            )
        )

    local pageSize =
        HolySniperGetWatchlistPageSize()

    return math.max(
        1,
        math.ceil(
            totalRows / pageSize
        )
    )
end

function HolySniperClampWatchlistPage(totalRows)

    local pageCount =
        HolySniperGetWatchlistPageCount(
            totalRows
        )

    local page =
        math.floor(
            tonumber(
                HOLY_SNIPER_STATE.WatchlistPage
            )
            or 1
        )

    page =
        math.clamp(
            page,
            1,
            pageCount
        )

    HOLY_SNIPER_STATE.WatchlistPage =
        page

    return page,
        pageCount
end

function HolySniperBuildWatchlistRows()

    local allRows =
        HolySniperBuildAllWatchlistRows()

    local page,
        pageCount =
        HolySniperClampWatchlistPage(
            #allRows
        )

    local pageSize =
        HolySniperGetWatchlistPageSize()

    local firstIndex =
        ((page - 1) * pageSize) + 1

    local lastIndex =
        math.min(
            #allRows,
            firstIndex + pageSize - 1
        )

    local pageRows =
        {}

    for index = firstIndex, lastIndex do

        if type(allRows[index]) == "table" then

            table.insert(
                pageRows,
                allRows[index]
            )
        end
    end

    return pageRows,
        {
            Page =
                page,

            PageCount =
                pageCount,

            TotalRows =
                #allRows,

            FirstIndex =
                firstIndex,

            LastIndex =
                lastIndex,
        }
end

function HolySniperBuildWatchlistPageText()

    local allRows =
        HolySniperBuildAllWatchlistRows()

    local page,
        pageCount =
        HolySniperClampWatchlistPage(
            #allRows
        )

    return "Page "
        .. tostring(page)
        .. "/"
        .. tostring(pageCount)
end

function HolySniperSetWatchlistPage(page)

    local allRows =
        HolySniperBuildAllWatchlistRows()

    local pageCount =
        HolySniperGetWatchlistPageCount(
            #allRows
        )

    HOLY_SNIPER_STATE.WatchlistPage =
        math.clamp(
            math.floor(
                tonumber(page)
                or 1
            ),
            1,
            pageCount
        )

    HOLY_SNIPER_STATE.SelectedWatchlistSourceIndex =
        nil

    if HOLY_SNIPER_UI
    and type(HOLY_SNIPER_UI.WatchlistTable) == "table"
    and type(HOLY_SNIPER_UI.WatchlistTable.SetSelected) == "function" then

        HOLY_SNIPER_UI.WatchlistTable:SetSelected(
            nil
        )
    end

    HolySniperRefreshUI()

    return true
end

function HolySniperWatchlistPrevPage()

    return HolySniperSetWatchlistPage(
        (
            tonumber(
                HOLY_SNIPER_STATE.WatchlistPage
            )
            or 1
        )
        - 1
    )
end

function HolySniperWatchlistNextPage()

    return HolySniperSetWatchlistPage(
        (
            tonumber(
                HOLY_SNIPER_STATE.WatchlistPage
            )
            or 1
        )
        + 1
    )
end


function HolySniperBuildWatchlistText()

    local rows =
        HolySniperBuildWatchlistRows()

    if #rows <= 0 then

        return "No active watchlist filters."
    end

    local lines =
        {}

    for index, row in ipairs(rows) do

        lines[#lines + 1] =
            tostring(index)
            .. ". "
            .. tostring(row.Value)
            .. " "
            .. tostring(row.Priority)
            .. " "
            .. tostring(row.Pet)
            .. " "
            .. tostring(row.Size)
            .. " "
            .. tostring(row.Variant)
            .. " "
            .. tostring(row.MaxPrice or row.Amount or "No Cap")
    end

    return table.concat(
        lines,
        "\n"
    )
end

function HolySniperBuildStatusText()

    return "Status: "
        .. tostring(
            HOLY_SNIPER_STATE.Status
            or "Ready"
        )
end

function HolySniperAddLabel(groupbox, text)

    if type(groupbox) ~= "table"
    or type(groupbox.AddLabel) ~= "function" then

        return nil
    end

    local ok,
        label =
        pcall(function()

            return groupbox:AddLabel({
                Text =
                    tostring(text or ""),
            })
        end)

    if ok == true then
        return label
    end

    ok,
        label =
        pcall(function()

            return groupbox:AddLabel(
                tostring(text or "")
            )
        end)

    if ok == true then
        return label
    end

    return nil
end

function HolySniperSetLabel(label, text)

    text =
        tostring(text or "")

    if type(label) == "table" then

        if type(label.SetText) == "function" then

            pcall(function()

                label:SetText(
                    text
                )
            end)

            return true
        end

        if label.TextLabel
        and typeof(label.TextLabel) == "Instance" then

            pcall(function()

                label.TextLabel.Text =
                    text
            end)

            return true
        end
    end

    if typeof(label) == "Instance" then

        pcall(function()

            label.Text =
                text
        end)

        return true
    end

    return false
end

function HolySniperRefreshUI()

    HOLY_SNIPER_UI =
        type(HOLY_SNIPER_UI) == "table"
        and HOLY_SNIPER_UI
        or {}

    HolySniperSetLabel(
        HOLY_SNIPER_UI.StatusLabel,
        HolySniperBuildStatusText()
    )

    local pageRows,
        pageInfo =
        HolySniperBuildWatchlistRows()

    if type(HOLY_SNIPER_UI.WatchlistTable) == "table"
    and type(HOLY_SNIPER_UI.WatchlistTable.SetRows) == "function" then

        HOLY_SNIPER_UI.WatchlistTable:SetRows(
            pageRows
        )

    else

        HolySniperSetLabel(
            HOLY_SNIPER_UI.WatchlistLabel,
            HolySniperBuildWatchlistText()
        )
    end

    local pager =
        HOLY_SNIPER_UI.WatchlistPager

    if type(pager) == "table" then

        local page =
            tonumber(
                pageInfo
                and pageInfo.Page
            )
            or 1

        local pageCount =
            tonumber(
                pageInfo
                and pageInfo.PageCount
            )
            or 1

        if type(pager.SetText) == "function" then

            pager:SetText(
                "Page",
                "Page "
                .. tostring(page)
                .. "/"
                .. tostring(pageCount)
            )
        end

        if type(pager.SetDisabled) == "function" then

            pager:SetDisabled(
                "Prev",
                page <= 1
            )

            pager:SetDisabled(
                "Next",
                page >= pageCount
            )
        end
    end
end

function HolySniperSetStatus(status)

    HOLY_SNIPER_STATE.Status =
        tostring(status or "Ready")

    HolySniperRefreshUI()
end

