function HolySniperMovementToolClearBlocked()

    if type(HOLY_DEFENSE_RUNTIME) == "table"
    and HOLY_DEFENSE_RUNTIME.Active == true then

        local sniper =
            type(HOLY_SNIPER_RUNTIME) == "table"
            and HOLY_SNIPER_RUNTIME
            or {}

        if sniper.Buying == true
        or sniper.Returning == true
        or sniper.CurrentTarget ~= nil
        or HolyCleanText(
            sniper.CurrentTargetKey
            or ""
        ) ~= "" then

            return false
        end

        return true
    end

    return false
end

function HolySniperClearHeldToolForMovement(reason)

    HOLY_SNIPER_RUNTIME =
        type(HOLY_SNIPER_RUNTIME) == "table"
        and HOLY_SNIPER_RUNTIME
        or {}

    if HolySniperMovementToolClearBlocked() == true then
        return false
    end

    local equippedTool =
        HolySniperGetEquippedToolForMovement()

    if typeof(equippedTool) ~= "Instance"
    or equippedTool:IsA("Tool") ~= true then

        return false
    end

    local humanoid =
        HolySniperGetCharacterHumanoid()

    if typeof(humanoid) ~= "Instance"
    or humanoid:IsA("Humanoid") ~= true then

        return false
    end

    local now =
        os.clock()

    if now - (
        tonumber(HOLY_SNIPER_RUNTIME.LastMovementUnequipAt)
        or 0
    ) < 0.28 then

        return true
    end

    HOLY_SNIPER_RUNTIME.LastMovementUnequipAt =
        now

    HOLY_SNIPER_RUNTIME.LastMovementUnequipTool =
        tostring(
            equippedTool.Name
            or "Tool"
        )

    HOLY_SNIPER_RUNTIME.LastMovementUnequipReason =
        tostring(
            reason
            or "movement"
        )

    pcall(function()

        humanoid:UnequipTools()
    end)

    task.wait(
        0.10
    )

    return true
end

function HolySniperGetEquippedToolForBuy()

    return HolySniperGetEquippedToolForMovement()
end

function HolySniperClearHeldToolForBuy(reason)

    return HolySniperClearHeldToolForMovement(
        reason
        or "buy"
    )
end

function HolySniperStillActive(token)

    HOLY_SNIPER_RUNTIME =
        type(HOLY_SNIPER_RUNTIME) == "table"
        and HOLY_SNIPER_RUNTIME
        or {}

    if HOLY_SNIPER_RUNTIME.ManualBuying == true then

        if token ~= nil
        and HOLY_SNIPER_RUNTIME.ManualToken ~= token then

            return false
        end

        return true
    end

    if HOLY_SNIPER_STATE.ActivateSniper ~= true then
        return false
    end

    if token ~= nil
    and HOLY_SNIPER_RUNTIME.Token ~= token then

        return false
    end

    return true
end

function HolySniperLoadingGateReady()

    if HolySniperGetCharacterRoot() == nil then
        return false
    end

    local loadingGui =
        HolyLoadingGetWorkspaceLoadingGui()

    if loadingGui == nil then
        return true
    end

    if type(HOLY_LOADING_SKIP_STATE) == "table"
    and HOLY_LOADING_SKIP_STATE.PressedFinal == true then

        return true
    end

    if type(HOLY_LOADING_SKIP_STATE) == "table"
    and HOLY_LOADING_SKIP_STATE.ClickedSkip == true
    and loadingGui == nil then

        return true
    end

    return false
end

