if type(HOLY_DEFENSE_RUNTIME) == "table" then

    HOLY_DEFENSE_RUNTIME.Token =
        nil

    HOLY_DEFENSE_RUNTIME.Active =
        false

    if type(HOLY_DEFENSE_RUNTIME.Connections) == "table" then

        for _, connection in ipairs(HOLY_DEFENSE_RUNTIME.Connections) do

            pcall(function()

                connection:Disconnect()
            end)
        end
    end
end

HOLY_DEFENSE_RUNTIME = {
    Active = false,
    Token = nil,
    Target = nil,
    Entry = nil,
    Filter = nil,
    Connections = {},

    RebuyCount = 0,
    MaxRebuys = 3,

    LastEquipAt = 0,
    LastMoveAt = 0,
    LastMoveToAt = 0,
    LastShotAt = 0,
    LastShovelAt = 0,
    LastPreAimAt = 0,

    LastPetSamplePos = nil,
    LastPetSampleAt = 0,
    StablePetDirection = nil,
    SmoothedFollowGoal = nil,

    OriginalWalkSpeed = nil,
    PlayerControls = nil,
    ControlsDisabled = false,

    Networking = nil,
    WildTamePacket = nil,
    StrawberryPacket = nil,
    ShovelSwingPacket = nil,
    ShovelHitPacket = nil,
    PetScarePacket = nil,
}

function HolyDefenseEnsureRuntime()

    HOLY_DEFENSE_RUNTIME =
        type(HOLY_DEFENSE_RUNTIME) == "table"
        and HOLY_DEFENSE_RUNTIME
        or {}

    local runtime =
        HOLY_DEFENSE_RUNTIME

    runtime.Connections =
        type(runtime.Connections) == "table"
        and runtime.Connections
        or {}

    runtime.MaxRebuys =
        tonumber(runtime.MaxRebuys)
        or 3

    return runtime
end

function HolyDefenseDisconnect()

    local runtime =
        HolyDefenseEnsureRuntime()

    for _, connection in ipairs(runtime.Connections or {}) do

        pcall(function()

            connection:Disconnect()
        end)
    end

    runtime.Connections =
        {}
end

function HolyDefenseAddConnection(connection)

    local runtime =
        HolyDefenseEnsureRuntime()

    if connection ~= nil then

        table.insert(
            runtime.Connections,
            connection
        )
    end

    return connection
end

function HolyDefenseReadAttr(instance, name)

    if typeof(instance) ~= "Instance" then
        return nil
    end

    local ok,
        value =
        pcall(function()

            return instance:GetAttribute(
                name
            )
        end)

    if ok == true then
        return value
    end

    return nil
end

function HolyDefenseGetPosition(object)

    if typeof(object) ~= "Instance" then
        return nil
    end

    if object:IsA("BasePart") then
        return object.Position
    end

    if object:IsA("Model") then

        local ok,
            pivot =
            pcall(function()

                return object:GetPivot()
            end)

        if ok == true
        and typeof(pivot) == "CFrame" then

            return pivot.Position
        end
    end

    local part =
        object:FindFirstChild(
            "HumanoidRootPart",
            true
        )
        or object:FindFirstChild(
            "RootPart",
            true
        )
        or object:FindFirstChildWhichIsA(
            "BasePart",
            true
        )

    if typeof(part) == "Instance"
    and part:IsA("BasePart") then

        return part.Position
    end

    return nil
end

function HolyDefenseDeepGet(root, path)

    local current =
        root

    for part in tostring(path or ""):gmatch("[^%.]+") do

        if type(current) ~= "table" then
            return nil
        end

        current =
            current[part]
    end

    return current
end

function HolyDefenseGetNetworking()

    local runtime =
        HolyDefenseEnsureRuntime()

    if type(runtime.Networking) == "table" then
        return runtime.Networking
    end

    local networking =
        nil

    if type(HolyShopRequireModule) == "function" then

        networking =
            HolyShopRequireModule(
                "SharedModules.Networking"
            )
    end

    if type(networking) ~= "table" then

        local module =
            ReplicatedStorage:FindFirstChild("SharedModules")
            and ReplicatedStorage.SharedModules:FindFirstChild("Networking")

        if typeof(module) == "Instance"
        and module:IsA("ModuleScript") then

            local ok,
                result =
                pcall(function()

                    return require(
                        module
                    )
                end)

            if ok == true
            and type(result) == "table" then

                networking =
                    result
            end
        end
    end

    runtime.Networking =
        type(networking) == "table"
        and networking
        or nil

    return runtime.Networking
end

function HolyDefenseResolvePackets()

    local runtime =
        HolyDefenseEnsureRuntime()

    local networking =
        HolyDefenseGetNetworking()

    if type(networking) ~= "table" then
        return false
    end

    runtime.WildTamePacket =
        runtime.WildTamePacket
        or HolyDefenseDeepGet(
            networking,
            "Pets.WildPetTame"
        )

    runtime.StrawberryPacket =
        runtime.StrawberryPacket
        or HolyDefenseDeepGet(
            networking,
            "StrawberrySniper.Fire"
        )

    runtime.ShovelSwingPacket =
        runtime.ShovelSwingPacket
        or HolyDefenseDeepGet(
            networking,
            "Shovel.SwingShovel"
        )

    runtime.ShovelHitPacket =
        runtime.ShovelHitPacket
        or HolyDefenseDeepGet(
            networking,
            "Shovel.HitPlayer"
        )

    runtime.PetScarePacket =
        runtime.PetScarePacket
        or HolyDefenseDeepGet(
            networking,
            "Pets.ScarePet"
        )

    return true
end

function HolyDefenseFirePacket(packet, ...)

    if type(packet) ~= "table"
    or type(packet.Fire) ~= "function" then

        return false
    end

    local ok =
        pcall(function(...)

            packet:Fire(
                ...
            )
        end, ...)

    return ok == true
end

function HolyDefenseGetCharacter()

    return LocalPlayer
        and LocalPlayer.Character
        or nil
end

function HolyDefenseGetHumanoid()

    local character =
        HolyDefenseGetCharacter()

    if typeof(character) ~= "Instance" then
        return nil
    end

    return character:FindFirstChildOfClass(
        "Humanoid"
    )
end

function HolyDefenseGetRoot()

    local character =
        HolyDefenseGetCharacter()

    if typeof(character) ~= "Instance" then
        return nil
    end

    return character:FindFirstChild(
        "HumanoidRootPart"
    )
    or character:FindFirstChild(
        "RootPart"
    )
    or character.PrimaryPart
end

function HolyDefenseToolMatches(tool, gearName)

    if typeof(tool) ~= "Instance"
    or tool:IsA("Tool") ~= true then

        return false
    end

    gearName =
        HolyDefenseNormalizeGear(
            gearName
        )

    local lowerName =
        tostring(tool.Name or "")
            :lower()

    local attrs =
        ""

    pcall(function()

        for key, value in pairs(tool:GetAttributes()) do

            attrs =
                attrs
                .. " "
                .. tostring(key)
                .. "="
                .. tostring(value)
        end
    end)

    attrs =
        attrs:lower()

    if gearName == "Shovel" then

        return lowerName == "shovel"
            or attrs:find("shovel", 1, true) ~= nil
    end

    return lowerName == "strawberry sniper"
        or (
            lowerName:find("strawberry", 1, true)
            and lowerName:find("sniper", 1, true)
        )
        or attrs:find("strawberrysniper", 1, true) ~= nil
        or attrs:find("strawberry sniper", 1, true) ~= nil
end

function HolyDefenseGetEquippedTool()

    local character =
        HolyDefenseGetCharacter()

    if typeof(character) ~= "Instance" then
        return nil
    end

    return character:FindFirstChildOfClass(
        "Tool"
    )
end

function HolyDefenseFindTool(gearName)

    gearName =
        HolyDefenseNormalizeGear(
            gearName
        )

    local containers =
        {}

    local character =
        HolyDefenseGetCharacter()

    if typeof(character) == "Instance" then

        table.insert(
            containers,
            character
        )
    end

    local backpack =
        LocalPlayer
        and LocalPlayer:FindFirstChildOfClass("Backpack")
        or nil

    if typeof(backpack) == "Instance" then

        table.insert(
            containers,
            backpack
        )
    end

    for _, container in ipairs(containers) do

        for _, child in ipairs(container:GetChildren()) do

            if HolyDefenseToolMatches(
                child,
                gearName
            ) == true then

                return child
            end
        end
    end

    return nil
end

function HolyDefenseEquipSelectedGear(reason)

    local runtime =
        HolyDefenseEnsureRuntime()

    if runtime.Active ~= true then
        return false
    end

    local gear =
        HolyDefenseNormalizeGear(
            HOLY_SNIPER_STATE.DefendGear
        )

    if HolyDefenseToolMatches(
        HolyDefenseGetEquippedTool(),
        gear
    ) == true then

        return true
    end

    local tool =
        HolyDefenseFindTool(
            gear
        )

    if typeof(tool) ~= "Instance" then
        return false
    end

    local humanoid =
        HolyDefenseGetHumanoid()

    if typeof(humanoid) ~= "Instance" then
        return false
    end

    local ok =
        pcall(function()

            humanoid:EquipTool(
                tool
            )
        end)

    if ok == true then

        runtime.LastEquipAt =
            os.clock()
    end

    return ok == true
end

function HolyDefenseGetPlayerRoot(player)

    local character =
        player
        and player.Character
        or nil

    if typeof(character) ~= "Instance" then
        return nil
    end

    return character:FindFirstChild(
        "HumanoidRootPart"
    )
    or character:FindFirstChild(
        "RootPart"
    )
    or character.PrimaryPart
end

function HolyDefenseFindThreat(targetPos)

    if typeof(targetPos) ~= "Vector3" then
        return nil
    end

    local best =
        nil

    for _, player in ipairs(Players:GetPlayers()) do

        if player ~= LocalPlayer then

            local root =
                HolyDefenseGetPlayerRoot(
                    player
                )

            if typeof(root) == "Instance"
            and root:IsA("BasePart") then

                local distance =
                    (
                        root.Position
                        - targetPos
                    ).Magnitude

                if distance <= 45
                and (
                    best == nil
                    or distance < best.Distance
                ) then

                    best = {
                        Player =
                            player,

                        Root =
                            root,

                        Distance =
                            distance,
                    }
                end
            end
        end
    end

    return best
end

function HolyDefenseGetPlayerControls()

    local runtime =
        HolyDefenseEnsureRuntime()

    if runtime.PlayerControls ~= nil then
        return runtime.PlayerControls
    end

    local playerScripts =
        LocalPlayer
        and LocalPlayer:FindFirstChild("PlayerScripts")
        or nil

    local playerModule =
        playerScripts
        and playerScripts:FindFirstChild("PlayerModule")
        or nil

    if typeof(playerModule) ~= "Instance"
    or playerModule:IsA("ModuleScript") ~= true then

        return nil
    end

    local okModule,
        module =
        pcall(require, playerModule)

    if okModule ~= true
    or type(module) ~= "table"
    or type(module.GetControls) ~= "function" then

        return nil
    end

    local okControls,
        controls =
        pcall(function()

            return module:GetControls()
        end)

    if okControls == true then

        runtime.PlayerControls =
            controls

        return controls
    end

    return nil
end

function HolyDefenseDisableControls()

    local runtime =
        HolyDefenseEnsureRuntime()

    if runtime.ControlsDisabled == true then
        return true
    end

    local controls =
        HolyDefenseGetPlayerControls()

    if controls == nil then
        return false
    end

    local ok =
        pcall(function()

            controls:Disable()
        end)

    if ok == true then

        runtime.ControlsDisabled =
            true
    end

    return ok == true
end

function HolyDefenseRestoreControls()

    local runtime =
        HolyDefenseEnsureRuntime()

    if runtime.ControlsDisabled ~= true then
        return
    end

    local controls =
        runtime.PlayerControls

    if controls ~= nil then

        pcall(function()

            controls:Enable()
        end)
    end

    runtime.ControlsDisabled =
        false
end

function HolyDefenseUpdatePetDirection(targetPos)

    local runtime =
        HolyDefenseEnsureRuntime()

    local root =
        HolyDefenseGetRoot()

    local now =
        os.clock()

    if runtime.StablePetDirection == nil then

        if typeof(root) == "Instance"
        and root:IsA("BasePart") then

            local fromPetToSelf =
                root.Position
                - targetPos

            local flat =
                Vector3.new(
                    fromPetToSelf.X,
                    0,
                    fromPetToSelf.Z
                )

            if flat.Magnitude > 0.2 then

                runtime.StablePetDirection =
                    -flat.Unit

            else

                runtime.StablePetDirection =
                    Vector3.new(0, 0, 1)
            end

        else

            runtime.StablePetDirection =
                Vector3.new(0, 0, 1)
        end
    end

    if runtime.LastPetSamplePos == nil then

        runtime.LastPetSamplePos =
            targetPos

        runtime.LastPetSampleAt =
            now

        return runtime.StablePetDirection
    end

    if now - (
        tonumber(runtime.LastPetSampleAt)
        or 0
    ) < 0.10 then

        return runtime.StablePetDirection
    end

    local delta =
        targetPos
        - runtime.LastPetSamplePos

    local flatDelta =
        Vector3.new(
            delta.X,
            0,
            delta.Z
        )

    runtime.LastPetSamplePos =
        targetPos

    runtime.LastPetSampleAt =
        now

    if flatDelta.Magnitude >= 0.22 then

        local fresh =
            flatDelta.Unit

        local mixed =
            runtime.StablePetDirection:Lerp(
                fresh,
                0.22
            )

        if mixed.Magnitude > 0.05 then

            runtime.StablePetDirection =
                mixed.Unit

        else

            runtime.StablePetDirection =
                fresh
        end
    end

    return runtime.StablePetDirection
end

function HolyDefenseSmoothGoal(rawGoal)

    local runtime =
        HolyDefenseEnsureRuntime()

    if typeof(rawGoal) ~= "Vector3" then
        return rawGoal
    end

    if runtime.SmoothedFollowGoal == nil
    or (
        runtime.SmoothedFollowGoal
        - rawGoal
    ).Magnitude >= 18 then

        runtime.SmoothedFollowGoal =
            rawGoal

    else

        runtime.SmoothedFollowGoal =
            runtime.SmoothedFollowGoal:Lerp(
                rawGoal,
                0.30
            )
    end

    return runtime.SmoothedFollowGoal
end

function HolyDefenseChooseGoal(targetPos, threat)

    local root =
        HolyDefenseGetRoot()

    if typeof(root) ~= "Instance"
    or root:IsA("BasePart") ~= true then

        return nil
    end

    if threat
    and threat.Root
    and threat.Distance <= 18 then

        local diff =
            threat.Root.Position
            - targetPos

        local flat =
            Vector3.new(
                diff.X,
                0,
                diff.Z
            )

        if flat.Magnitude > 0.1 then

            local threatDir =
                flat.Unit

            local guardDistance =
                threat.Distance <= 8
                and 3.85
                or 4.75

            return Vector3.new(
                targetPos.X,
                root.Position.Y,
                targetPos.Z
            )
            + threatDir * guardDistance
        end
    end

    local stableDir =
        HolyDefenseUpdatePetDirection(
            targetPos
        )

    local rawGoal =
        targetPos
        - stableDir * 5.75

    rawGoal =
        Vector3.new(
            rawGoal.X,
            root.Position.Y,
            rawGoal.Z
        )

    return HolyDefenseSmoothGoal(
        rawGoal
    )
end

function HolyDefenseSetWalkSpeed(distance, threat)

    local runtime =
        HolyDefenseEnsureRuntime()

    local humanoid =
        HolyDefenseGetHumanoid()

    if typeof(humanoid) ~= "Instance" then
        return
    end

    if runtime.OriginalWalkSpeed == nil then

        runtime.OriginalWalkSpeed =
            humanoid.WalkSpeed
    end

    local base =
        tonumber(runtime.OriginalWalkSpeed)
        or humanoid.WalkSpeed

    local wanted =
        math.max(
            base,
            22
        )

    if threat
    and threat.Distance <= 8 then

        wanted =
            math.max(
                base,
                31
            )

    elseif threat
    and threat.Distance <= 24 then

        wanted =
            math.max(
                base,
                27
            )

    elseif distance >= 14 then

        wanted =
            math.max(
                base,
                27
            )
    end

    pcall(function()

        humanoid.WalkSpeed =
            wanted

        humanoid.AutoRotate =
            true
    end)
end

function HolyDefenseWalkTo(goal, threat)

    local runtime =
        HolyDefenseEnsureRuntime()

    local humanoid =
        HolyDefenseGetHumanoid()

    local root =
        HolyDefenseGetRoot()

    if typeof(goal) ~= "Vector3"
    or typeof(humanoid) ~= "Instance"
    or typeof(root) ~= "Instance"
    or root:IsA("BasePart") ~= true then

        return false
    end

    HolyDefenseDisableControls()

    local delta =
        goal
        - root.Position

    local flat =
        Vector3.new(
            delta.X,
            0,
            delta.Z
        )

    local distance =
        flat.Magnitude

    HolyDefenseSetWalkSpeed(
        distance,
        threat
    )

    if distance <= 2.30 then

        pcall(function()

            humanoid:Move(
                Vector3.zero,
                false
            )
        end)

        return true
    end

    local now =
        os.clock()

    if now - (
        tonumber(runtime.LastMoveAt)
        or 0
    ) >= 0.04 then

        runtime.LastMoveAt =
            now

        pcall(function()

            humanoid:Move(
                flat.Unit,
                false
            )
        end)
    end

    if now - (
        tonumber(runtime.LastMoveToAt)
        or 0
    ) >= 0.16 then

        runtime.LastMoveToAt =
            now

        pcall(function()

            humanoid:MoveTo(
                goal
            )
        end)
    end

    return true
end

function HolyDefenseTweenTo(goal)

    local root =
        HolyDefenseGetRoot()

    if typeof(goal) ~= "Vector3"
    or typeof(root) ~= "Instance"
    or root:IsA("BasePart") ~= true then

        return false
    end

    local distance =
        (
            root.Position
            - goal
        ).Magnitude

    if distance <= 2.30 then
        return true
    end

    local speed =
        30

    local duration =
        math.clamp(
            distance / speed,
            0.10,
            0.35
        )

    local TweenService =
        game:GetService("TweenService")

    local tween =
        TweenService:Create(
            root,
            TweenInfo.new(
                duration,
                Enum.EasingStyle.Linear,
                Enum.EasingDirection.Out
            ),
            {
                CFrame =
                    CFrame.new(
                        goal,
                        goal + root.CFrame.LookVector
                    ),
            }
        )

    pcall(function()

        tween:Play()
    end)

    return true
end

function HolyDefenseMoveTo(goal, threat)

    local movement =
        HolyDefenseNormalizeMovement(
            HOLY_SNIPER_STATE.DefendMovement
        )

    local root =
        HolyDefenseGetRoot()

    if typeof(root) ~= "Instance"
    or root:IsA("BasePart") ~= true then

        return false
    end

    local distance =
        typeof(goal) == "Vector3"
        and (
            root.Position
            - goal
        ).Magnitude
        or 0

    if movement == "Tween" then

        return HolyDefenseTweenTo(
            goal
        )
    end

    if movement == "Hybrid" then

        if distance >= 15
        or (
            threat
            and threat.Distance <= 8
        ) then

            return HolyDefenseTweenTo(
                goal
            )
        end
    end

    return HolyDefenseWalkTo(
        goal,
        threat
    )
end

function HolyDefenseRayClear(fromPos, toPos, targetCharacter)

    if typeof(fromPos) ~= "Vector3"
    or typeof(toPos) ~= "Vector3" then

        return false
    end

    local params =
        RaycastParams.new()

    params.FilterType =
        Enum.RaycastFilterType.Exclude

    local ignore =
        {}

    local character =
        HolyDefenseGetCharacter()

    if typeof(character) == "Instance" then

        table.insert(
            ignore,
            character
        )
    end

    local runtime =
        HolyDefenseEnsureRuntime()

    if typeof(runtime.Target) == "Instance" then

        table.insert(
            ignore,
            runtime.Target
        )
    end

    params.FilterDescendantsInstances =
        ignore

    local result =
        workspace:Raycast(
            fromPos,
            toPos - fromPos,
            params
        )

    if result == nil then
        return true
    end

    if typeof(targetCharacter) == "Instance"
    and result.Instance
    and result.Instance:IsDescendantOf(
        targetCharacter
    ) then

        return true
    end

    return false
end

function HolyDefenseGetThreatParts(threat)

    local character =
        threat
        and threat.Player
        and threat.Player.Character
        or nil

    if typeof(character) ~= "Instance" then
        return nil
    end

    local root =
        character:FindFirstChild(
            "HumanoidRootPart"
        )
        or character:FindFirstChild(
            "RootPart"
        )
        or character.PrimaryPart

    local head =
        character:FindFirstChild(
            "Head"
        )

    return {
        Character =
            character,

        Root =
            root,

        Head =
            head,
    }
end

function HolyDefenseGetVelocity(part)

    if typeof(part) ~= "Instance"
    or part:IsA("BasePart") ~= true then

        return Vector3.zero
    end

    local ok,
        velocity =
        pcall(function()

            return part.AssemblyLinearVelocity
        end)

    if ok == true
    and typeof(velocity) == "Vector3" then

        return velocity
    end

    return Vector3.zero
end

function HolyDefenseChooseAim(threat)

    local parts =
        HolyDefenseGetThreatParts(
            threat
        )

    if parts == nil
    or typeof(parts.Root) ~= "Instance"
    or parts.Root:IsA("BasePart") ~= true then

        return nil
    end

    local root =
        HolyDefenseGetRoot()

    if typeof(root) ~= "Instance"
    or root:IsA("BasePart") ~= true then

        return nil
    end

    local velocity =
        HolyDefenseGetVelocity(
            parts.Root
        )

    local distance =
        tonumber(threat.Distance)
        or 0

    local tinyLead =
        math.clamp(
            distance / 470,
            0.010,
            0.050
        )

    local softLead =
        math.clamp(
            distance / 330,
            0.020,
            0.090
        )

    local headPos =
        typeof(parts.Head) == "Instance"
        and parts.Head:IsA("BasePart")
        and (
            parts.Head.Position
            + Vector3.new(0, -0.05, 0)
        )
        or (
            parts.Root.Position
            + Vector3.new(0, 2.3, 0)
        )

    local rootHigh =
        parts.Root.Position
        + Vector3.new(0, 1.45, 0)

    local candidates = {
        headPos + velocity * tinyLead,
        headPos + velocity * softLead,
        rootHigh,
        rootHigh + velocity * tinyLead,
    }

    local camera =
        workspace.CurrentCamera

    local rootFrom =
        root.Position
        + Vector3.new(0, 1.5, 0)

    local cameraFrom =
        camera
        and camera.CFrame.Position
        or rootFrom

    for _, aim in ipairs(candidates) do

        if HolyDefenseRayClear(
            rootFrom,
            aim,
            parts.Character
        ) == true
        and HolyDefenseRayClear(
            cameraFrom,
            aim,
            parts.Character
        ) == true then

            return aim
        end
    end

    return nil
end

function HolyDefensePreAim(aim)

    local camera =
        workspace.CurrentCamera

    if typeof(camera) == "Instance"
    and typeof(aim) == "Vector3" then

        pcall(function()

            camera.CFrame =
                CFrame.new(
                    camera.CFrame.Position,
                    aim
                )
        end)
    end
end

function HolyDefenseFaceShot(aim)

    local root =
        HolyDefenseGetRoot()

    if typeof(root) ~= "Instance"
    or root:IsA("BasePart") ~= true
    or typeof(aim) ~= "Vector3" then

        return
    end

    local lookAt =
        Vector3.new(
            aim.X,
            root.Position.Y,
            aim.Z
        )

    if (
        lookAt
        - root.Position
    ).Magnitude < 0.35 then

        return
    end

    pcall(function()

        root.CFrame =
            CFrame.lookAt(
                root.Position,
                lookAt
            )
    end)
end

function HolyDefenseUseStrawberry(threat)

    local runtime =
        HolyDefenseEnsureRuntime()

    if threat == nil
    or threat.Player == nil
    or threat.Root == nil then

        return false
    end

    if threat.Distance > 30 then
        return false
    end

    local velocity =
        HolyDefenseGetVelocity(
            threat.Root
        )

    local flatSpeed =
        Vector3.new(
            velocity.X,
            0,
            velocity.Z
        ).Magnitude

    if threat.Distance > 22
    and flatSpeed > 7 then

        return false
    end

    local cooldown =
        threat.Distance <= 8
        and 2.78
        or 3.00

    if os.clock() - (
        tonumber(runtime.LastShotAt)
        or 0
    ) < cooldown then

        return false
    end

    HolyDefenseResolvePackets()

    local packet =
        runtime.StrawberryPacket

    if type(packet) ~= "table" then
        return false
    end

    local aim =
        HolyDefenseChooseAim(
            threat
        )

    if typeof(aim) ~= "Vector3" then
        return false
    end

    if HolyDefenseEquipSelectedGear(
        "shot"
    ) ~= true then

        return false
    end

    local tool =
        HolyDefenseFindTool(
            "Strawberry Sniper"
        )

    if typeof(tool) ~= "Instance" then
        return false
    end

    HolyDefensePreAim(
        aim
    )

    HolyDefenseFaceShot(
        aim
    )

    task.wait()

    local ok =
        HolyDefenseFirePacket(
            packet,
            aim,
            tool,
            threat.Player
        )

    if ok == true then

        runtime.LastShotAt =
            os.clock()
    end

    return ok
end

function HolyDefenseReadTargetPetId()

    local runtime =
        HolyDefenseEnsureRuntime()

    local target =
        runtime.Target

    if typeof(target) ~= "Instance" then
        return ""
    end

    local petId =
        HolyCleanText(
            HolyDefenseReadAttr(
                target,
                "PetId"
            )
            or HolyDefenseReadAttr(
                target,
                "PetID"
            )
            or HolyDefenseReadAttr(
                target,
                "UUID"
            )
            or ""
        )

    if petId ~= "" then
        return petId
    end

    return HolySniperUuidFromName(
        target.Name
    )
end

function HolyDefenseUseShovel(threat)

    local runtime =
        HolyDefenseEnsureRuntime()

    if threat == nil
    or threat.Player == nil
    or threat.Distance > 7 then

        return false
    end

    if os.clock() - (
        tonumber(runtime.LastShovelAt)
        or 0
    ) < 0.85 then

        return false
    end

    HolyDefenseResolvePackets()

    if HolyDefenseEquipSelectedGear(
        "shovel"
    ) ~= true then

        return false
    end

    local ok =
        false

    if type(runtime.ShovelSwingPacket) == "table" then

        ok =
            HolyDefenseFirePacket(
                runtime.ShovelSwingPacket
            )
            or ok
    end

    if type(runtime.ShovelHitPacket) == "table" then

        ok =
            HolyDefenseFirePacket(
                runtime.ShovelHitPacket,
                threat.Player.UserId
            )
            or ok
    end

    local petId =
        HolyDefenseReadTargetPetId()

    if petId ~= ""
    and type(runtime.PetScarePacket) == "table" then

        ok =
            HolyDefenseFirePacket(
                runtime.PetScarePacket,
                threat.Player.UserId,
                petId
            )
            or ok
    end

    runtime.LastShovelAt =
        os.clock()

    return ok
end

function HolyDefenseUseGear(threat)

    local gear =
        HolyDefenseNormalizeGear(
            HOLY_SNIPER_STATE.DefendGear
        )

    if gear == "Shovel" then

        return HolyDefenseUseShovel(
            threat
        )
    end

    return HolyDefenseUseStrawberry(
        threat
    )
end

function HolyDefenseStop(reason)

    local runtime =
        HolyDefenseEnsureRuntime()

    runtime.Token =
        nil

    runtime.Active =
        false

    runtime.Target =
        nil

    runtime.Entry =
        nil

    runtime.Filter =
        nil

    runtime.SmoothedFollowGoal =
        nil

    runtime.StablePetDirection =
        nil

    runtime.LastPetSamplePos =
        nil

    HolyDefenseDisconnect()

    HolyDefenseRestoreControls()

    local humanoid =
        HolyDefenseGetHumanoid()

    if typeof(humanoid) == "Instance" then

        pcall(function()

            humanoid:Move(
                Vector3.zero,
                false
            )

            if runtime.OriginalWalkSpeed ~= nil then

                humanoid.WalkSpeed =
                    runtime.OriginalWalkSpeed
            end

            humanoid.AutoRotate =
                true
        end)
    end

    return true
end

function HolyDefenseCanRebuy(target)

    local runtime =
        HolyDefenseEnsureRuntime()

    if HOLY_SNIPER_STATE.DefendRebuyIfStolen ~= true then
        return false
    end

    local filter =
        type(runtime.Filter) == "table"
        and HolySniperNormalizeFilter(
            runtime.Filter
        )
        or {}

    local maxPrice =
        tonumber(filter.MaxPrice)
        or 0

    if maxPrice <= 0 then
        return false
    end

    if runtime.RebuyCount >= runtime.MaxRebuys then
        return false
    end

    local price =
        tonumber(
            HolyDefenseReadAttr(
                target,
                "Price"
            )
        )
        or 0

    if price <= 0
    or price > maxPrice then

        return false
    end

    local state =
        HolyCleanText(
            HolyDefenseReadAttr(
                target,
                "State"
            )
            or ""
        )

    if HolySniperPetBuyStateLooksPending(
        state
    ) ~= true then

        return false
    end

    return true
end

function HolyDefenseTryRebuy(target)

    local runtime =
        HolyDefenseEnsureRuntime()

    if typeof(target) ~= "Instance" then
        return false
    end

    if HolyDefenseCanRebuy(target) ~= true then
        return false
    end

    HolyDefenseResolvePackets()

    if type(runtime.WildTamePacket) ~= "table" then
        return false
    end

    local ok =
        HolyDefenseFirePacket(
            runtime.WildTamePacket,
            target
        )

    if ok == true then

        runtime.RebuyCount =
            (
                tonumber(runtime.RebuyCount)
                or 0
            )
            + 1

        runtime.Target =
            target

        HolyDefenseEquipSelectedGear(
            "rebuy"
        )
    end

    return ok
end

function HolyDefenseHandleOwnerChanged(target)

    local runtime =
        HolyDefenseEnsureRuntime()

    if runtime.Active ~= true
    or target ~= runtime.Target then

        return
    end

    task.delay(0.05, function()

        local liveRuntime =
            HolyDefenseEnsureRuntime()

        if liveRuntime.Active ~= true
        or target ~= liveRuntime.Target
        or typeof(target) ~= "Instance"
        or target.Parent == nil then

            return
        end

        local owner =
            tonumber(
                HolyDefenseReadAttr(
                    target,
                    "OwnerUserId"
                )
            )
            or 0

        if owner == 0
        or owner == tonumber(LocalPlayer.UserId) then

            return
        end

        if HolyDefenseTryRebuy(
            target
        ) == true then

            return
        end

        HolyDefenseStop(
            "stolen"
        )
    end)
end

function HolyDefenseWatchTarget(target)

    local runtime =
        HolyDefenseEnsureRuntime()

    HolyDefenseDisconnect()

    for _, attrName in ipairs({
        "OwnerUserId",
        "OwnerName",
        "State",
        "Price",
    }) do

        pcall(function()

            HolyDefenseAddConnection(
                target:GetAttributeChangedSignal(
                    attrName
                ):Connect(function()

                    if attrName == "OwnerUserId" then

                        HolyDefenseHandleOwnerChanged(
                            target
                        )
                    end
                end)
            )
        end)
    end

    HolyDefenseAddConnection(
        target.AncestryChanged:Connect(function(_, parent)

            if parent == nil
            and runtime.Target == target then

                HolyDefenseStop(
                    "target removed"
                )
            end
        end)
    )
end

function HolyDefenseRunWorker(token)

    local runtime =
        HolyDefenseEnsureRuntime()

    while runtime.Token == token
    and runtime.Active == true do

        local sniper =
            type(HOLY_SNIPER_RUNTIME) == "table"
            and HOLY_SNIPER_RUNTIME
            or {}

        if sniper.Buying == true
        or sniper.Returning == true then

            task.wait(
                0.10
            )

            continue
        end

        local target =
            runtime.Target

        if typeof(target) ~= "Instance"
        or target.Parent == nil then

            HolyDefenseStop(
                "target gone"
            )

            return
        end

        local owner =
            tonumber(
                HolyDefenseReadAttr(
                    target,
                    "OwnerUserId"
                )
            )
            or 0

        if owner ~= tonumber(LocalPlayer.UserId) then

            HolyDefenseHandleOwnerChanged(
                target
            )

            task.wait(
                0.15
            )

            continue
        end

        HolyDefenseEquipSelectedGear(
            "defending"
        )

        local targetPos =
            HolyDefenseGetPosition(
                target
            )

        if typeof(targetPos) == "Vector3" then

            local threat =
                HolyDefenseFindThreat(
                    targetPos
                )

            local goal =
                HolyDefenseChooseGoal(
                    targetPos,
                    threat
                )

            if typeof(goal) == "Vector3" then

                HolyDefenseMoveTo(
                    goal,
                    threat
                )
            end

            if threat ~= nil then

                HolyDefenseUseGear(
                    threat
                )
            end
        end

        task.wait(
            0.04
        )
    end
end

function HolyDefenseWaitForOwnedTarget(entry)

    entry =
        type(entry) == "table"
        and entry
        or {}

    local ref =
        entry.Ref

    if typeof(ref) ~= "Instance"
    or ref.Parent == nil then

        ref =
            HolySniperFindPetBuyProtectionRef({
                UUID =
                    entry.UUID
                    or entry.Key,

                Key =
                    entry.Key,
            })
    end

    if typeof(ref) ~= "Instance" then
        return nil
    end

    local deadline =
        os.clock() + 2.5

    while os.clock() <= deadline do

        if typeof(ref) ~= "Instance"
        or ref.Parent == nil then

            return nil
        end

        local owner =
            tonumber(
                HolyDefenseReadAttr(
                    ref,
                    "OwnerUserId"
                )
            )
            or 0

        local state =
            HolyCleanText(
                HolyDefenseReadAttr(
                    ref,
                    "State"
                )
                or ""
            )

        if owner == tonumber(LocalPlayer.UserId)
        and HolySniperPetBuyStateLooksPending(
            state
        ) == true then

            return ref
        end

        task.wait(
            0.05
        )
    end

    return ref
end

function HolyDefenseArm(entry, filter, reason)

    if HOLY_SNIPER_STATE.DefendBoughtPets ~= true then
        return false
    end

    local target =
        HolyDefenseWaitForOwnedTarget(
            entry
        )

    if typeof(target) ~= "Instance" then
        return false
    end

    local runtime =
        HolyDefenseEnsureRuntime()

    HolyDefenseStop(
        "new defense"
    )

    runtime =
        HolyDefenseEnsureRuntime()

    runtime.Active =
        true

    runtime.Token =
        {}

    runtime.Target =
        target

    runtime.Entry =
        entry

    runtime.Filter =
        filter

    runtime.RebuyCount =
        0

    runtime.SmoothedFollowGoal =
        nil

    runtime.StablePetDirection =
        nil

    runtime.LastPetSamplePos =
        nil

    runtime.LastPetSampleAt =
        0

    local humanoid =
        HolyDefenseGetHumanoid()

    if typeof(humanoid) == "Instance"
    and runtime.OriginalWalkSpeed == nil then

        runtime.OriginalWalkSpeed =
            humanoid.WalkSpeed
    end

    HolyDefenseResolvePackets()

    HolyDefenseWatchTarget(
        target
    )

    HolyDefenseEquipSelectedGear(
        reason or "defense start"
    )

    local token =
        runtime.Token

    task.spawn(function()

        HolyDefenseRunWorker(
            token
        )
    end)

    return true
end

function HolyDefenseSetDefendBoughtPets(value)

    HOLY_SNIPER_STATE.DefendBoughtPets =
        value == true

    if HOLY_SNIPER_STATE.DefendBoughtPets ~= true then

        HolyDefenseStop(
            "toggle off"
        )
    end

    HolySaveSniperSettings()
end

function HolyDefenseSetGear(value)

    HOLY_SNIPER_STATE.DefendGear =
        HolyDefenseNormalizeGear(
            value
        )

    if HOLY_DEFENSE_RUNTIME
    and HOLY_DEFENSE_RUNTIME.Active == true then

        HolyDefenseEquipSelectedGear(
            "gear changed"
        )
    end

    HolySaveSniperSettings()
end

function HolyDefenseSetMovement(value)

    HOLY_SNIPER_STATE.DefendMovement =
        HolyDefenseNormalizeMovement(
            value
        )

    HolySaveSniperSettings()
end

function HolyDefenseSetRebuyIfStolen(value)

    HOLY_SNIPER_STATE.DefendRebuyIfStolen =
        value == true

    HolySaveSniperSettings()
end

--==================================================
-- [2.45] LIVE WILD PETS MAIN PANEL
--==================================================

if type(HOLY_LIVE_PETS_RUNTIME) == "table" then

    HOLY_LIVE_PETS_RUNTIME.Running =
        false

    HOLY_LIVE_PETS_RUNTIME.Token =
        nil

    local oldConnections =
        HOLY_LIVE_PETS_RUNTIME.Connections

    if type(oldConnections) == "table" then

        for _, connection in ipairs(oldConnections) do

            pcall(function()

                connection:Disconnect()
            end)
        end
    end
end

HOLY_LIVE_PETS_RUNTIME = {
    Running = false,
    Token = nil,
    Connections = {},
    LastRows = {},
    LastSummary = "Next Spawn: --:-- | Active: 0",

    LastSpawnedAt = 0,
    LastSpawnKey = "",
    LastPet = "None",
    SpawnSequence = {},
}

function HolyLivePetsReadAttr(instance, names)

    if typeof(instance) ~= "Instance" then
        return ""
    end

    for _, name in ipairs(names or {}) do

        local ok,
            value =
            pcall(function()

                return instance:GetAttribute(
                    name
                )
            end)

        value =
            HolyCleanText(
                ok == true
                and value
                or ""
            )

        if value ~= "" then
            return value
        end
    end

    return ""
end

function HolyLivePetsReadNumber(instance, names)

    local value =
        HolyLivePetsReadAttr(
            instance,
            names
        )

    return tonumber(value)
        or 0
end

function HolyLivePetsFormatTime(seconds)

    seconds =
        math.max(
            0,
            math.floor(
                tonumber(seconds)
                or 0
            )
        )

    local minutes =
        math.floor(seconds / 60)

    local remaining =
        seconds % 60

    return tostring(minutes)
        .. "m "
        .. tostring(remaining)
        .. "s"
end

function HolyLivePetsFormatCountdown(seconds)

    seconds =
        math.max(
            0,
            math.floor(
                tonumber(seconds)
                or 0
            )
        )

    local minutes =
        math.floor(seconds / 60)

    local remaining =
        seconds % 60

    return string.format(
        "%02d:%02d",
        minutes,
        remaining
    )
end

function HolyLivePetsFormatMoney(value)

    value =
        math.max(
            0,
            tonumber(value)
            or 0
        )

    local text =
        tostring(
            math.floor(value)
        )

    local left,
        number,
        right =
        string.match(
            text,
            "^([^%d]*%d)(%d*)(.-)$"
        )

    if number then

        text =
            left
            .. number:reverse():gsub("(%d%d%d)", "%1,"):reverse()
            .. right
    end

    return "¢"
        .. text
end

function HolyLivePetsGetUuidFromRef(ref)

    if typeof(ref) ~= "Instance" then
        return ""
    end

    local uuid =
        tostring(ref.Name):match(
            "^WildPet_([%w%-]+)$"
        )
        or ""

    return uuid
end

function HolyLivePetsFindRefByKey(key)

    key =
        HolyCleanText(
            key
        )

    if key == "" then
        return nil
    end

    local root =
        HolySniperGetWildPetRefRoot()

    if typeof(root) ~= "Instance" then
        return nil
    end

    local direct =
        root:FindFirstChild(
            "WildPet_"
            .. key
        )

    if typeof(direct) == "Instance" then
        return direct
    end

    for _, child in ipairs(root:GetChildren()) do

        if tostring(child.Name):find(
            key,
            1,
            true
        ) then

            return child
        end
    end

    return nil
end

function HolyLivePetsFindModelForRef(ref)

    local uuid =
        HolyLivePetsGetUuidFromRef(
            ref
        )

    if uuid == "" then
        return nil
    end

    local root =
        HolySniperGetWildPetRoot()

    if typeof(root) ~= "Instance" then
        return nil
    end

    for _, child in ipairs(root:GetChildren()) do

        if child:IsA("Model")
        and tostring(child.Name):find(
            uuid,
            1,
            true
        ) then

            return child
        end
    end

    return nil
end

function HolyLivePetsGetPosition(ref, model)

    if typeof(ref) == "Instance"
    and ref:IsA("BasePart") then

        return ref.Position
    end

    if typeof(model) == "Instance" then

        return HolySniperGetModelPosition(
            model
        )
    end

    return nil
end

function HolyLivePetsGetDistance(position)

    local root =
        HolySniperGetCharacterRoot()

    if typeof(position) ~= "Vector3"
    or typeof(root) ~= "Instance"
    or root:IsA("BasePart") ~= true then

        return nil
    end

    return (
        root.Position
        - position
    ).Magnitude
end

function HolyLivePetsReadSize(ref, model)

    local raw =
        HolyLivePetsReadAttr(
            ref,
            {
                "PetSize",
                "Size",
                "DisplaySize",
                "ScaleType",
                "WildPetSize",
            }
        )

    if raw ~= "" then
        return HolySniperNormalizeSizeName(
            raw
        )
    end

    raw =
        HolySniperReadModelAttribute(
            model,
            {
                "PetSize",
                "Size",
                "DisplaySize",
                "ScaleType",
                "WildPetSize",
            }
        )

    if raw ~= "" then
        return HolySniperNormalizeSizeName(
            raw
        )
    end

    if typeof(model) == "Instance" then

        return HolySniperReadLiveSize(
            model
        )
    end

    return "Normal"
end

function HolyLivePetsReadVariant(ref, model)

    local raw =
        HolyLivePetsReadAttr(
            ref,
            {
                "PetType",
                "Type",
                "Variant",
                "PetVariant",
                "Mutation",
                "WildPetType",
            }
        )

    if raw == "" then

        raw =
            HolySniperReadModelAttribute(
                model,
                {
                    "PetType",
                    "Type",
                    "Variant",
                    "PetVariant",
                    "Mutation",
                    "WildPetType",
                }
            )
    end

    raw =
        HolySniperNormalizeVariantName(
            raw
        )

    if raw ~= ""
    and raw ~= "Normal" then
        return raw
    end

    local modelName =
        tostring(
            model
            and model.Name
            or ""
        )
        :lower()

    if modelName:find("rainbow", 1, true) then
        return "Rainbow"
    end

    return "Normal"
end

function HolyLivePetsBuildDisplayName(petName, sizeName, variantName)

    local parts =
        {}

    sizeName =
        HolySniperNormalizeSizeName(
            sizeName
        )

    variantName =
        HolySniperNormalizeVariantName(
            variantName
        )

    if sizeName ~= ""
    and sizeName ~= "Normal"
    and sizeName ~= "Any" then

        table.insert(
            parts,
            sizeName
        )
    end

    if variantName ~= ""
    and variantName ~= "Normal"
    and variantName ~= "Any" then

        table.insert(
            parts,
            variantName
        )
    end

    table.insert(
        parts,
        tostring(petName or "?")
    )

    return table.concat(
        parts,
        " "
    )
end

function HolyLivePetsRarityRank(rarity)

    rarity =
        HolyCleanText(
            rarity
        )

    local ranks = {
        Super = 7,
        Mythic = 6,
        Legendary = 5,
        Epic = 4,
        Rare = 3,
        Uncommon = 2,
        Common = 1,
    }

    return ranks[rarity]
        or 0
end

function HolyLivePetsFilterMatches(entry)

    local watchlist =
        type(HOLY_SNIPER_STATE.Watchlist) == "table"
        and HOLY_SNIPER_STATE.Watchlist
        or {}

    if #watchlist <= 0 then
        return false
    end

    for _, rawFilter in ipairs(watchlist) do

        local filter =
            HolySniperNormalizeFilter(
                rawFilter
            )

        if filter.Enabled ~= false then

            local entryPet =
                HolySniperPetAliasKey(
                    entry.PetKey
                    or entry.Pet
                )

            local filterPet =
                HolySniperPetAliasKey(
                    filter.PetKey
                    or filter.Pet
                )

            if entryPet == filterPet then

                local sizeOk =
                    HolySniperSelectionHasAny(
                        filter.Sizes
                    )
                    or HolySniperSelectionContains(
                        filter.Sizes,
                        entry.Size
                    )

                local variantOk =
                    HolySniperSelectionHasAny(
                        filter.Variants
                    )
                    or HolySniperSelectionContains(
                        filter.Variants,
                        entry.Variant
                    )

                if sizeOk == true
                and variantOk == true then
                    return true
                end
            end
        end
    end

    return false
end

function HolyLivePetsBuildEntryFromRef(ref)

    if typeof(ref) ~= "Instance" then
        return nil
    end

    local petName =
        HolyLivePetsReadAttr(
            ref,
            {
                "PetName",
                "Pet",
                "DisplayName",
                "Name",
            }
        )

    if petName == "" then
        return nil
    end

    petName =
        HolySniperResolvePetDisplay(
            petName
        )

    local petKey =
        HolySniperResolvePetKey(
            petName
        )

    local uuid =
        HolyLivePetsGetUuidFromRef(
            ref
        )

    if uuid == "" then
        uuid =
            tostring(ref.Name)
    end

    local spawnedAt =
        HolyLivePetsReadNumber(
            ref,
            {
                "SpawnedAt",
                "SpawnTime",
                "CreatedAt",
            }
        )

    local lifetime =
        HolyLivePetsReadNumber(
            ref,
            {
                "Lifetime",
                "LifeTime",
                "Duration",
            }
        )

    local timeLeft =
        lifetime > 0
        and spawnedAt > 0
        and (
            spawnedAt
            + lifetime
            - os.time()
        )
        or 0

    if lifetime > 0
    and timeLeft <= -4 then

        return nil
    end

    local ownerUserId =
        HolyLivePetsReadNumber(
            ref,
            {
                "OwnerUserId",
                "OwnerUserID",
                "Owner",
                "UserId",
                "UserID",
            }
        )

    local ownerName =
        HolyLivePetsReadAttr(
            ref,
            {
                "OwnerName",
                "OwnerDisplayName",
            }
        )

    local rawState =
        HolyLivePetsReadAttr(
            ref,
            {
                "State",
                "PetState",
            }
        )

    local lowerState =
        rawState:lower()

    local model =
        HolyLivePetsFindModelForRef(
            ref
        )

    local prompt =
        model
        and HolySniperFindBuyPrompt(
            model
        )
        or nil

    local size =
        HolyLivePetsReadSize(
            ref,
            model
        )

    local variant =
        HolyLivePetsReadVariant(
            ref,
            model
        )

    local rarity =
        HolyLivePetsReadAttr(
            ref,
            {
                "Rarity",
                "PetRarity",
            }
        )

    local price =
        HolyLivePetsReadNumber(
            ref,
            {
                "Price",
                "Cost",
                "TameCost",
            }
        )

    if price <= 0 then
        price =
            HolySniperGetBasePrice({
                Pet =
                    petName,

                PetKey =
                    petKey,
            })
    end

    local position =
        HolyLivePetsGetPosition(
            ref,
            model
        )

    local distance =
        HolyLivePetsGetDistance(
            position
        )

    local handledEntry = {
        UUID = uuid,
        Key = uuid,
    }

    local handled =
        HolySniperIsHandled(
            handledEntry
        )

    local cooling =
        HolySniperIsFailedCooling(
            handledEntry
        )

    local owned =
        ownerUserId ~= 0
        or ownerName ~= ""

    if owned == true
    and handled ~= true then

        return nil
    end

    if lowerState:find("owned", 1, true)
    or lowerState:find("collected", 1, true)
    or lowerState:find("tamed", 1, true) then

        if handled ~= true then
            return nil
        end
    end

    local entry = {
        Key =
            uuid,

        UUID =
            uuid,

        Ref =
            ref,

        Model =
            model,

        Prompt =
            prompt,

        Pet =
            petName,

        PetKey =
            petKey,

        Size =
            size,

        Variant =
            variant,

        Rarity =
            rarity,

        Price =
            price,

        SpawnedAt =
            spawnedAt,

        Lifetime =
            lifetime,

        TimeLeft =
            timeLeft,

        Distance =
            distance,

        Position =
            position,

        RawState =
            rawState,
    }

    local match =
        HolyLivePetsFilterMatches(
            entry
        )

    local displayName =
        HolyLivePetsBuildDisplayName(
            petName,
            size,
            variant
        )

    local priceText =
        HolyLivePetsFormatMoney(
            price
        )

    local distanceText =
        distance
        and (
            tostring(math.floor(distance + 0.5))
            .. " studs"
        )
        or "? studs"

    local timeText =
        lifetime > 0
        and HolyLivePetsFormatTime(timeLeft)
        or "? left"

    local metaParts =
        {}

    if rarity ~= "" then
        table.insert(
            metaParts,
            rarity
        )
    end

    table.insert(
        metaParts,
        priceText
    )

    table.insert(
        metaParts,
        distanceText
    )

    local rowState =
        "ready"

    local badge =
        "BUY"

    local clickable =
        true

    if handled == true then

        rowState =
            "sent"

        badge =
            "SENT"

        clickable =
            false

    elseif cooling == true then

        rowState =
            "blocked"

        badge =
            "WAIT"

        clickable =
            false

    elseif model == nil
    or prompt == nil then

        badge =
            "WAIT"

        clickable =
            true
    end

    return {
        Key =
            uuid,

        UUID =
            uuid,

        DisplayName =
            displayName,

        Pet =
            petName,

        PetKey =
            petKey,

        Size =
            size,

        Variant =
            variant,

        Rarity =
            rarity,

        RarityRank =
            HolyLivePetsRarityRank(
                rarity
            ),

        PriceNumber =
            tonumber(price)
            or 0,

        Price =
            priceText,

        SpawnedAt =
            tonumber(spawnedAt)
            or 0,

        Lifetime =
            tonumber(lifetime)
            or 0,

        DistanceNumber =
            tonumber(distance)
            or 999999,

        Distance =
            distanceText,

        TimeLeftNumber =
            tonumber(timeLeft)
            or 0,

        Timer =
            timeText,

        Meta =
            table.concat(
                metaParts,
                " · "
            ),

        Match =
            match == true,

        Badge =
            badge,

        State =
            rowState,

        Clickable =
            clickable,

        RawState =
            rawState,

        Ref =
            ref,
    }
end

function HolyLivePetsScanRows()

    local rows =
        {}

    local refRoot =
        HolySniperGetWildPetRefRoot()

    if typeof(refRoot) ~= "Instance" then
        return rows
    end

    for _, ref in ipairs(refRoot:GetChildren()) do

        local row =
            HolyLivePetsBuildEntryFromRef(
                ref
            )

        if row then

            table.insert(
                rows,
                row
            )
        end
    end

    table.sort(rows, function(a, b)

        if a.Match ~= b.Match then
            return a.Match == true
        end

        if a.RarityRank ~= b.RarityRank then
            return a.RarityRank > b.RarityRank
        end

        if a.PriceNumber ~= b.PriceNumber then
            return a.PriceNumber > b.PriceNumber
        end

        if a.TimeLeftNumber ~= b.TimeLeftNumber then
            return a.TimeLeftNumber < b.TimeLeftNumber
        end

        return a.DistanceNumber < b.DistanceNumber
    end)

    return rows
end

function HolyLivePetsBuildTimer(rows)

    rows =
        rows
        or HolyLivePetsScanRows()

    HOLY_LIVE_PETS_RUNTIME =
        type(HOLY_LIVE_PETS_RUNTIME) == "table"
        and HOLY_LIVE_PETS_RUNTIME
        or {}

    HOLY_LIVE_PETS_RUNTIME.SpawnSequence =
        type(HOLY_LIVE_PETS_RUNTIME.SpawnSequence) == "table"
        and HOLY_LIVE_PETS_RUNTIME.SpawnSequence
        or {}

    local clean =
        {}

    for _, row in ipairs(rows) do

        local spawnedAt =
            tonumber(row.SpawnedAt)
            or 0

        if spawnedAt > 0 then

            table.insert(
                clean,
                row
            )
        end
    end

    table.sort(clean, function(a, b)

        return tonumber(a.SpawnedAt or 0)
            < tonumber(b.SpawnedAt or 0)
    end)

    if #clean > 0 then

        local latest =
            clean[#clean]

        local latestSpawnedAt =
            tonumber(latest.SpawnedAt)
            or 0

        local latestPet =
            tostring(latest.Pet or "None")

        local latestKey =
            tostring(latestSpawnedAt)
            .. "|"
            .. latestPet

        if latestSpawnedAt > 0
        and latestKey ~= tostring(HOLY_LIVE_PETS_RUNTIME.LastSpawnKey or "") then

            HOLY_LIVE_PETS_RUNTIME.LastSpawnedAt =
                latestSpawnedAt

            HOLY_LIVE_PETS_RUNTIME.LastSpawnKey =
                latestKey

            HOLY_LIVE_PETS_RUNTIME.LastPet =
                latestPet

            table.insert(
                HOLY_LIVE_PETS_RUNTIME.SpawnSequence,
                latestPet
            )

            while #HOLY_LIVE_PETS_RUNTIME.SpawnSequence > 4 do

                table.remove(
                    HOLY_LIVE_PETS_RUNTIME.SpawnSequence,
                    1
                )
            end
        end
    end

    local lastSpawnedAt =
        tonumber(
            HOLY_LIVE_PETS_RUNTIME.LastSpawnedAt
        )
        or 0

    local lastPet =
        HolyCleanText(
            HOLY_LIVE_PETS_RUNTIME.LastPet
            or "None"
        )

    if lastSpawnedAt <= 0 then

        return {
            NextText = "--:--",
            Active = #rows,
            Last = "None",
            Sequence = "None",
        }
    end

    local nextSpawn =
        lastSpawnedAt + 100

    while nextSpawn <= os.time() - 3 do

        nextSpawn =
            nextSpawn + 100
    end

    local sequence =
        "None"

    if #HOLY_LIVE_PETS_RUNTIME.SpawnSequence > 0 then

        sequence =
            table.concat(
                HOLY_LIVE_PETS_RUNTIME.SpawnSequence,
                " > "
            )
    end

    return {
        NextText =
            HolyLivePetsFormatCountdown(
                nextSpawn - os.time()
            ),

        Active =
            #rows,

        Last =
            lastPet ~= ""
            and lastPet
            or "None",

        Sequence =
            sequence,
    }
end

function HolyLivePetsBuildSummary(rows)

    local timer =
        HolyLivePetsBuildTimer(
            rows
        )

    return "Next Spawn: "
        .. tostring(timer.NextText)
        .. " | Active: "
        .. tostring(timer.Active)
        .. " | Last: "
        .. tostring(timer.Last)
end

function HolyLivePetsBuildModeText()

    local movement =
        HolySniperNormalizeMovementMode(
            HOLY_SNIPER_STATE.MovementMode
            or "Walk"
        )

    local buy =
        HolySniperNormalizeBuyMode(
            HOLY_SNIPER_STATE.BuyMode
            or "Instant"
        )

    return "Mode: "
        .. movement
        .. " · "
        .. buy
        .. " | Click a pet to buy"
end

function HolyLivePetsRefreshUI()

    local list =
        HOLY_SNIPER_UI
        and HOLY_SNIPER_UI.LivePetsList
        or nil

    if type(list) ~= "table" then
        return false
    end

    local rows =
        HolyLivePetsScanRows()

    HOLY_LIVE_PETS_RUNTIME.LastRows =
        rows

    if type(list.SetSummary) == "function" then

        list:SetSummary(
            HolyLivePetsBuildSummary(
                rows
            )
        )
    end

    if type(list.SetModeText) == "function" then

        list:SetModeText(
            HolyLivePetsBuildModeText()
        )
    end

    if type(list.SetRows) == "function" then

        list:SetRows(
            rows
        )
    end

    return true
end

function HolyLivePetsResolveEntryForBuy(rowData)

    rowData =
        type(rowData) == "table"
        and rowData
        or {}

    local key =
        HolyCleanText(
            rowData.Key
            or rowData.UUID
            or ""
        )

    if key == "" then
        return nil, "missing key"
    end

    local deadline =
        os.clock() + 3

    while os.clock() <= deadline do

        local ref =
            HolyLivePetsFindRefByKey(
                key
            )

        if typeof(ref) ~= "Instance" then

            return nil,
                "pet gone"
        end

        local model =
            HolyLivePetsFindModelForRef(
                ref
            )

        if typeof(model) == "Instance"
        and model:IsA("Model") then

            local entry =
                HolySniperBuildLiveEntry(
                    model
                )

            if type(entry) == "table" then

                return entry,
                    "ok"
            end
        end

        task.wait(
            0.05
        )
    end

    return nil,
        "prompt missing"
end

function HolyLivePetsMakeManualFilter(entry)

    entry =
        type(entry) == "table"
        and entry
        or {}

    return HolySniperNormalizeFilter({
        Pet =
            entry.Pet
            or "Raccoon",

        Sizes = {
            entry.Size
            or "Any",
        },

        Variants = {
            entry.Variant
            or "Any",
        },

        Amount =
            999,

        Priority =
            "High",

        Enabled =
            true,
    })
end

function HolyLivePetsManualBuy(rowData)

    if type(rowData) ~= "table" then
        return false
    end

    if HOLY_SNIPER_RUNTIME.Buying == true
    or HOLY_SNIPER_RUNTIME.Returning == true then

        if type(HolyNotify) == "function" then

            HolyNotify(
                "HOLY Live Pets",
                "Already buying or returning.",
                3
            )
        end

        return false
    end

    local key =
        HolyCleanText(
            rowData.Key
            or rowData.UUID
            or ""
        )

    local list =
        HOLY_SNIPER_UI
        and HOLY_SNIPER_UI.LivePetsList
        or nil

    if type(list) == "table"
    and type(list.SetStateByKey) == "function"
    and key ~= "" then

        list:SetStateByKey(
            key,
            "buying"
        )
    end

    local token =
        {}

    HOLY_SNIPER_RUNTIME.ManualBuying =
        true

    HOLY_SNIPER_RUNTIME.ManualToken =
        token

    local success =
        false

    local reason =
        "unknown"

    local ok,
        err =
        pcall(function()

            local entry,
                resolveReason =
                HolyLivePetsResolveEntryForBuy(
                    rowData
                )

            if type(entry) ~= "table" then

                reason =
                    resolveReason
                    or "target missing"

                return
            end

            local filter =
                HolyLivePetsMakeManualFilter(
                    entry
                )

            local match = {
                Entry =
                    entry,

                Filter =
                    filter,

                FilterIndex =
                    0,

                Manual =
                    true,
            }

            HolySniperSetStatus(
                "Manual buy: "
                .. HolySniperDescribeEntry(entry)
            )

            local executeReason =
                nil

            success,
                executeReason =
                HolySniperExecuteMatch(
                    match,
                    token
                )

            reason =
                executeReason
                or (
                    success == true
                    and "bought"
                    or "buy failed"
                )
        end)

    if ok ~= true then

        reason =
            tostring(err)
    end

    HOLY_SNIPER_RUNTIME.ManualBuying =
        false

    HOLY_SNIPER_RUNTIME.ManualToken =
        nil

    if type(list) == "table"
    and type(list.SetStateByKey) == "function"
    and key ~= "" then

        list:SetStateByKey(
            key,
            success == true
            and "sent"
            or "ready"
        )
    end

    HolyLivePetsRefreshUI()

    if success == true then

        if type(HolyNotify) == "function" then

            HolyNotify(
                "HOLY Live Pets",
                "Bought "
                .. tostring(rowData.DisplayName or rowData.Pet or "pet")
                .. ".",
                3
            )
        end

    else

        if type(HolyNotify) == "function" then

            HolyNotify(
                "HOLY Live Pets",
                "Buy failed: "
                .. tostring(reason),
                4
            )
        end
    end

    return success
end

function HolyLivePetsCopySnapshot()

    local rows =
        HolyLivePetsScanRows()

    local lines =
        {}

    local function add(line)

        table.insert(
            lines,
            tostring(line or "")
        )
    end

    add("========== HOLY LIVE WILD PETS ==========")
    add("PlaceId: " .. tostring(game.PlaceId))
    add("JobId: " .. tostring(game.JobId))
    add(HolyLivePetsBuildSummary(rows))
    add("Mode: " .. HolySniperNormalizeMovementMode(HOLY_SNIPER_STATE.MovementMode) .. " / " .. HolySniperNormalizeBuyMode(HOLY_SNIPER_STATE.BuyMode))
    add("")

    if #rows <= 0 then

        add("No active wild pets.")

    else

        for index, row in ipairs(rows) do

            add(
                tostring(index)
                .. ". "
                .. tostring(row.DisplayName)
                .. " | "
                .. tostring(row.Meta)
                .. " | "
                .. tostring(row.Timer)
                .. " | "
                .. tostring(row.Badge)
            )
        end
    end

    local text =
        table.concat(
            lines,
            "\n"
        )

    if HolyCopyText(text) == true then

        if type(HolyNotify) == "function" then

            HolyNotify(
                "HOLY Live Pets",
                "Copied live pets.",
                3
            )
        end

        return true
    end

    if type(HolyNotify) == "function" then

        HolyNotify(
            "HOLY Live Pets",
            "Clipboard unsupported.",
            4
        )
    end

    return false
end

function HolyLivePetsDisconnect()

    local connections =
        HOLY_LIVE_PETS_RUNTIME
        and HOLY_LIVE_PETS_RUNTIME.Connections
        or nil

    if type(connections) == "table" then

        for _, connection in ipairs(connections) do

            pcall(function()

                connection:Disconnect()
            end)
        end
    end

    HOLY_LIVE_PETS_RUNTIME.Connections =
        {}
end

function HolyLivePetsStart()

    HOLY_LIVE_PETS_RUNTIME =
        type(HOLY_LIVE_PETS_RUNTIME) == "table"
        and HOLY_LIVE_PETS_RUNTIME
        or {}

    if HOLY_LIVE_PETS_RUNTIME.Running == true then
        return false
    end

    HolyLivePetsDisconnect()

    HOLY_LIVE_PETS_RUNTIME.Running =
        true

    local token =
        {}

    HOLY_LIVE_PETS_RUNTIME.Token =
        token

    local function connectRoot(root)

        if typeof(root) ~= "Instance" then
            return
        end

        table.insert(
            HOLY_LIVE_PETS_RUNTIME.Connections,
            root.ChildAdded:Connect(function()

                task.defer(
                    HolyLivePetsRefreshUI
                )
            end)
        )

        table.insert(
            HOLY_LIVE_PETS_RUNTIME.Connections,
            root.ChildRemoved:Connect(function()

                task.defer(
                    HolyLivePetsRefreshUI
                )
            end)
        )
    end

    connectRoot(
        HolySniperGetWildPetRefRoot()
    )

    connectRoot(
        HolySniperGetWildPetRoot()
    )

    task.spawn(function()

        while HOLY_LIVE_PETS_RUNTIME.Token == token do

            HolyLivePetsRefreshUI()

            task.wait(
                0.35
            )
        end

        if HOLY_LIVE_PETS_RUNTIME.Token == token then

            HOLY_LIVE_PETS_RUNTIME.Running =
                false
        end
    end)

    return true
end

function HolyLivePetsStop(reason)

    HOLY_LIVE_PETS_RUNTIME =
        type(HOLY_LIVE_PETS_RUNTIME) == "table"
        and HOLY_LIVE_PETS_RUNTIME
        or {}

    HOLY_LIVE_PETS_RUNTIME.Token =
        nil

    HOLY_LIVE_PETS_RUNTIME.Running =
        false

    HolyLivePetsDisconnect()

    return true
end

function HolySniperAutoHopReset(reason)

    HOLY_SNIPER_RUNTIME.NoMatchSince =
        0

    HOLY_SNIPER_RUNTIME.NoMatchScans =
        0
end

function HolySniperAutoHopDataReady()

    local wildRoot =
        HolySniperGetWildPetRoot()

    local refRoot =
        HolySniperGetWildPetRefRoot()

    return typeof(wildRoot) == "Instance"
        and typeof(refRoot) == "Instance"
end

function HolySniperAutoHopCanRun()

    if HOLY_SNIPER_STATE.ActivateSniper ~= true then

        HolySniperAutoHopReset(
            "sniper off"
        )

        return false
    end

    if HOLY_SNIPER_STATE.AutoHop ~= true then

        HolySniperAutoHopReset(
            "auto hop off"
        )

        return false
    end

    if HOLY_SNIPER_RUNTIME.AutoHopInProgress == true then
        return false
    end

    if HolySniperServerSwitchBlocked(
        "Auto Hop",
        false
    ) == true then

        HolySniperAutoHopReset(
            "sniper protection"
        )

        return false
    end

    if HOLY_SNIPER_RUNTIME.Buying == true
    or HOLY_SNIPER_RUNTIME.Returning == true then

        return false
    end

    if HOLY_SNIPER_RUNTIME.BatchActive == true then
        return false
    end

    if type(HOLY_SNIPER_STATE.Watchlist) ~= "table"
    or #HOLY_SNIPER_STATE.Watchlist <= 0 then

        HolySniperAutoHopReset(
            "no watchlist"
        )

        return false
    end

    if HolySniperGetCharacterRoot() == nil then
        return false
    end

    return true
end

function HolySniperBeginAutoHop(reason, token)

    if HolySniperStillActive(token) ~= true then
        return false
    end

    if HolySniperServerSwitchBlocked(
        "Auto Hop",
        false
    ) == true then

        return false
    end

    if HOLY_SNIPER_RUNTIME.AutoHopInProgress == true then
        return false
    end

    HOLY_SNIPER_RUNTIME.AutoHopInProgress =
        true

    HOLY_SNIPER_RUNTIME.LastHopAt =
        os.clock()

    HolySniperSetStatus(
        "Auto Hop: finding server..."
    )

    local queued,
        queueReason =
        HolyQueueSmartServerHop(
            tostring(reason or "auto hop"),
            function(_ok, errorText)

                HOLY_SNIPER_RUNTIME.AutoHopInProgress =
                    false

                HOLY_SNIPER_RUNTIME.HopFailureBackoffUntil =
                    os.clock() + 4

                HolySniperSetStatus(
                    "Auto Hop failed: "
                    .. tostring(errorText)
                )
            end
        )

    if queued ~= true then

        HOLY_SNIPER_RUNTIME.AutoHopInProgress =
            false

        HOLY_SNIPER_RUNTIME.HopFailureBackoffUntil =
            os.clock() + 4

        HolySniperSetStatus(
            "Auto Hop failed: "
            .. tostring(queueReason)
        )

        return false
    end

    return true
end

function HolySniperAutoHopEvaluate(matches, phase, token)

    phase =
        tostring(phase or "Safe")

    local phaseLabel =
        phase == "Fast"
        and "Fast Hop"
        or "Safe Hop"

    if HolySniperAutoHopCanRun() ~= true then
        return false
    end

    if HolySniperAutoHopDataReady() ~= true then

        HolySniperAutoHopReset(
            "pet data missing"
        )

        HolySniperSetStatus(
            phaseLabel
            .. ": waiting for pet data"
        )

        return false
    end

    matches =
        type(matches) == "table"
        and matches
        or {}

    if #matches > 0 then

        HolySniperAutoHopReset(
            "match found"
        )

        return false
    end

    local now =
        os.clock()

    local backoffUntil =
        tonumber(
            HOLY_SNIPER_RUNTIME.HopFailureBackoffUntil
        )
        or 0

    if now < backoffUntil then

        HolySniperSetStatus(
            phaseLabel
            .. ": retry in "
            .. HolySniperFormatDelay(
                backoffUntil - now
            )
            .. "s"
        )

        return false
    end

    local startClock =
        tonumber(
            HOLY_SNIPER_RUNTIME.StartClock
        )
        or now

    local minimumServerAge =
        tonumber(
            HOLY_SNIPER_RUNTIME.AutoHopMinimumServerAge
        )
        or 8

    if now - startClock < minimumServerAge then

        HolySniperSetStatus(
            phaseLabel
            .. ": waiting for save data..."
        )

        return false
    end

    if (
        tonumber(
            HOLY_SNIPER_RUNTIME.NoMatchSince
        )
        or 0
    ) <= 0 then

        HOLY_SNIPER_RUNTIME.NoMatchSince =
            now

        HOLY_SNIPER_RUNTIME.NoMatchScans =
            0
    end

    HOLY_SNIPER_RUNTIME.NoMatchScans =
        (
            tonumber(
                HOLY_SNIPER_RUNTIME.NoMatchScans
            )
            or 0
        )
        + 1

    local requiredScans =
        phase == "Fast"
        and (
            tonumber(
                HOLY_SNIPER_RUNTIME.EarlyHopRequiredScans
            )
            or 3
        )
        or (
            tonumber(
                HOLY_SNIPER_RUNTIME.SafeHopRequiredScans
            )
            or 2
        )

    if phase == "Fast" then

        local minimumSeconds =
            tonumber(
                HOLY_SNIPER_RUNTIME.EarlyHopMinimumSeconds
            )
            or 8

        if now - startClock < minimumSeconds then

            HolySniperSetStatus(
                phaseLabel
                .. ": confirming server..."
            )

            return false
        end
    end

    if HOLY_SNIPER_RUNTIME.NoMatchScans < requiredScans then

        HolySniperSetStatus(
            phaseLabel
            .. ": confirming no match..."
        )

        return false
    end

    local delay =
        HolySniperReadHopDelay(
            HOLY_SNIPER_STATE.HopDelay
        )

    local elapsed =
        now
        - (
            tonumber(
                HOLY_SNIPER_RUNTIME.NoMatchSince
            )
            or now
        )

    local remaining =
        math.max(
            0,
            delay - elapsed
        )

    if remaining > 0.05 then

        HolySniperSetStatus(
            phaseLabel
            .. ": no match, hopping in "
            .. HolySniperFormatDelay(remaining)
            .. "s"
        )

        return false
    end

    return HolySniperBeginAutoHop(
        phaseLabel
        .. " no match",
        token
    )
end

function HolySniperEarlyAutoHopTick(token)

    if HolySniperNormalizeAutoHopTiming(
        HOLY_SNIPER_STATE.AutoHopTiming
    ) ~= "Fast - During Loading" then

        return false
    end

    if HolySniperAutoHopCanRun() ~= true then
        return false
    end

    if HolySniperAutoHopDataReady() ~= true then

        HolySniperAutoHopReset(
            "early data missing"
        )

        HolySniperSetStatus(
            "Fast Hop: waiting for pet data"
        )

        return false
    end

    local matches =
        HolySniperRunScan()

    if #matches > 0 then

        HolySniperAutoHopReset(
            "early match found"
        )

        HolySniperSetStatus(
            "Fast Hop: match found, waiting loading"
        )

        return false
    end

    return HolySniperAutoHopEvaluate(
        matches,
        "Fast",
        token
    )
end

function HolySniperTick(token)

    if HOLY_SNIPER_RUNTIME.Buying == true
    or HOLY_SNIPER_RUNTIME.Returning == true then

        return false
    end

    if HolySniperPetBuyProtectionBlocks(
        "Sniper",
        false
    ) == true then

        return false
    end

    HolySniperClearHeldToolForMovement(
        "scan"
    )

    local matches =
        HolySniperRunScan()

    if #matches <= 0 then

        local returned =
            HolySniperMaybeReturnAfterBatchNoMatches(
                token
            )

        if returned == true then

            HolySniperAutoHopReset(
                "returned"
            )

            return true
        end

        local phase =
            HolySniperNormalizeAutoHopTiming(
                HOLY_SNIPER_STATE.AutoHopTiming
            ) == "Fast - During Loading"
            and "Fast"
            or "Safe"

        return HolySniperAutoHopEvaluate(
            matches,
            phase,
            token
        )
    end

    HolySniperAutoHopReset(
        "match found"
    )

    HOLY_SNIPER_RUNTIME.BatchEmptySince =
        0

    return HolySniperExecuteMatch(
        matches[1],
        token
    )
end

function HolySniperStop(reason)

    HOLY_SNIPER_RUNTIME =
        type(HOLY_SNIPER_RUNTIME) == "table"
        and HOLY_SNIPER_RUNTIME
        or {}

    HOLY_SNIPER_RUNTIME.Token =
        nil

    HOLY_SNIPER_RUNTIME.Running =
        false

    HOLY_SNIPER_RUNTIME.AutoHopInProgress =
        false

    if HOLY_SERVER_STATE then

        HOLY_SERVER_STATE.Hopping =
            false
    end

    HOLY_SNIPER_RUNTIME.NoMatchSince =
        0

    HOLY_SNIPER_RUNTIME.NoMatchScans =
        0

    HOLY_SNIPER_RUNTIME.Buying =
        false

    HOLY_SNIPER_RUNTIME.Returning =
        false

    HOLY_SNIPER_RUNTIME.LastManualMoveInputAt =
        0

    HolySniperStartManualInputWatcher()

    HOLY_SNIPER_RUNTIME.BatchActive =
        false

    HOLY_SNIPER_RUNTIME.BatchBoughtCount =
        0

    HOLY_SNIPER_RUNTIME.BatchEmptySince =
        0

    HOLY_SNIPER_RUNTIME.CurrentTarget =
        nil

    HOLY_SNIPER_RUNTIME.CurrentTargetKey =
        ""

    HolySniperClearTargetLock(
        "sniper stopped"
    )

    HolySniperSetStatus(
        tostring(reason or "Ready")
    )
end

function HolySniperStart(reason)

    HOLY_SNIPER_RUNTIME =
        type(HOLY_SNIPER_RUNTIME) == "table"
        and HOLY_SNIPER_RUNTIME
        or {}

    if HOLY_SNIPER_RUNTIME.Running == true then
        return false
    end

    HOLY_SNIPER_RUNTIME.Running =
        true

    HOLY_SNIPER_RUNTIME.LoadingReady =
        false

    HOLY_SNIPER_RUNTIME.StartClock =
        os.clock()

    HOLY_SNIPER_RUNTIME.AutoHopInProgress =
        false

    HOLY_SNIPER_RUNTIME.HopFailureBackoffUntil =
        0

    HOLY_SNIPER_RUNTIME.NoMatchSince =
        0

    HOLY_SNIPER_RUNTIME.NoMatchScans =
        0

    HOLY_SNIPER_RUNTIME.Buying =
        false

    HOLY_SNIPER_RUNTIME.Returning =
        false

    HOLY_SNIPER_RUNTIME.BatchActive =
        false

    HOLY_SNIPER_RUNTIME.BatchBoughtCount =
        0

    HOLY_SNIPER_RUNTIME.BatchEmptySince =
        0

    HolySniperClearTargetLock(
        "sniper start"
    )

    local startRoot =
        HolySniperGetCharacterRoot()

    HOLY_SNIPER_RUNTIME.ReturnActivationCFrame =
        startRoot
        and startRoot:IsA("BasePart")
        and startRoot.CFrame
        or nil

    HOLY_SNIPER_RUNTIME.FarmCenterCFrame =
        nil

    HOLY_SNIPER_RUNTIME.FarmCenterLastScanAt =
        0

    HolySniperGetFarmCenterCFrame(
        true
    )

    HOLY_SNIPER_RUNTIME.Handled =
        type(HOLY_SNIPER_RUNTIME.Handled) == "table"
        and HOLY_SNIPER_RUNTIME.Handled
        or {}

    HOLY_SNIPER_RUNTIME.FailedUntil =
        type(HOLY_SNIPER_RUNTIME.FailedUntil) == "table"
        and HOLY_SNIPER_RUNTIME.FailedUntil
        or {}

    HOLY_SNIPER_RUNTIME.BoughtCounts =
        type(HOLY_SNIPER_RUNTIME.BoughtCounts) == "table"
        and HOLY_SNIPER_RUNTIME.BoughtCounts
        or {}

    local token =
        {}

    HOLY_SNIPER_RUNTIME.Token =
        token

    HolySniperSetStatus(
        "Waiting for loading"
    )

    task.spawn(function()

        while HOLY_SNIPER_RUNTIME.Token == token
        and HOLY_SNIPER_STATE.ActivateSniper == true do

            if HolySniperLoadingGateReady() ~= true then

                if HOLY_SNIPER_STATE.AutoHop == true
                and HolySniperNormalizeAutoHopTiming(
                    HOLY_SNIPER_STATE.AutoHopTiming
                ) == "Fast - During Loading" then

                    local hopOk,
                        hopErr =
                        pcall(function()

                            HolySniperEarlyAutoHopTick(
                                token
                            )
                        end)

                    if hopOk ~= true then

                        HolySniperSetStatus(
                            "Fast Hop error: "
                            .. tostring(hopErr)
                        )

                        task.wait(
                            1
                        )

                    else

                        task.wait(
                            0.22
                        )
                    end

                else

                    HolySniperAutoHopReset(
                        "waiting loading"
                    )

                    HolySniperSetStatus(
                        "Waiting for loading"
                    )

                    task.wait(
                        0.25
                    )
                end

            else

                HOLY_SNIPER_RUNTIME.LoadingReady =
                    true

                local ok,
                    err =
                    pcall(function()

                        HolySniperTick(
                            token
                        )
                    end)

                if ok ~= true then

                    HolySniperSetStatus(
                        "Sniper error: "
                        .. tostring(err)
                    )

                    task.wait(
                        1
                    )
                end

                task.wait(
                    0.18
                )
            end
        end

        if HOLY_SNIPER_RUNTIME.Token == token then

            HOLY_SNIPER_RUNTIME.Running =
                false
        end
    end)

    return true
end

function HolySniperEnsureRunning()

    if HOLY_SNIPER_STATE.ActivateSniper == true then

        return HolySniperStart(
            "enabled"
        )
    end

    HolySniperStop(
        "Ready"
    )

    return false
end

function HolySaveSniperSettings()

    if HolyCanUseFiles() ~= true then
        return false
    end

    HolyEnsureFolder()

    local payload = {
        ActivateSniper =
            HOLY_SNIPER_STATE.ActivateSniper == true,

        AutoHop =
            HOLY_SNIPER_STATE.AutoHop == true,

        HopDelay =
            HolySniperReadHopDelay(
                HOLY_SNIPER_STATE.HopDelay
            ),

        AutoHopTiming =
            HolySniperNormalizeAutoHopTiming(
                HOLY_SNIPER_STATE.AutoHopTiming
            ),

        MovementMode =
            HolySniperNormalizeMovementMode(
                HOLY_SNIPER_STATE.MovementMode
            ),

        BuyMode =
            HolySniperNormalizeBuyMode(
                HOLY_SNIPER_STATE.BuyMode
            ),

        ReturnEnabled =
            HOLY_SNIPER_STATE.ReturnEnabled == true,

        ReturnTiming =
            HolySniperNormalizeReturnTiming(
                HOLY_SNIPER_STATE.ReturnTiming
            ),

        ReturnMode =
            HolySniperNormalizeReturnMode(
                HOLY_SNIPER_STATE.ReturnMode
            ),

        ReturnDestination =
            HolySniperNormalizeReturnDestination(
                HOLY_SNIPER_STATE.ReturnDestination
            ),

        SavedReturnCFrameData =
            HOLY_SNIPER_STATE.SavedReturnCFrameData,

        DefendBoughtPets =
            HOLY_SNIPER_STATE.DefendBoughtPets == true,

        DefendGear =
            HolyDefenseNormalizeGear(
                HOLY_SNIPER_STATE.DefendGear
            ),

        DefendMovement =
            HolyDefenseNormalizeMovement(
                HOLY_SNIPER_STATE.DefendMovement
            ),

        DefendRebuyIfStolen =
            HOLY_SNIPER_STATE.DefendRebuyIfStolen == true,

        BuilderPet =
            HolySniperResolvePetDisplay(
                HOLY_SNIPER_STATE.BuilderPet
                or HolySniperGetDefaultPetName()
            ),

        BuilderSizes =
            HolySniperNormalizeSizeSelection(
                HOLY_SNIPER_STATE.BuilderSizes
            ),

        BuilderVariants =
            HolySniperNormalizeVariantSelection(
                HOLY_SNIPER_STATE.BuilderVariants
            ),

        BuilderMaxPrice =
            tostring(
                HolySniperReadMaxPrice(
                    HOLY_SNIPER_STATE.BuilderMaxPrice
                    or "0"
                )
            ),

        BuilderAmount =
            "999",

        BuilderPriority =
            HolySniperNormalizePriority(
                HOLY_SNIPER_STATE.BuilderPriority
            ),

        Watchlist =
            HolySniperNormalizeWatchlist(
                HOLY_SNIPER_STATE.Watchlist
            ),
    }

    local encodeOk,
        encoded =
        pcall(function()

            return HttpService:JSONEncode(
                payload
            )
        end)

    if encodeOk ~= true
    or type(encoded) ~= "string" then

        return false
    end

    local writeOk =
        pcall(function()

            writefile(
                SNIPER_SETTINGS_FILE,
                encoded
            )
        end)

    return writeOk == true
end

function HolyLoadSniperSettings()

    if HolyCanUseFiles() ~= true then
        return false
    end

    local exists =
        false

    pcall(function()

        exists =
            isfile(
                SNIPER_SETTINGS_FILE
            )
    end)

    if exists ~= true then
        return false
    end

    local readOk,
        raw =
        pcall(function()

            return readfile(
                SNIPER_SETTINGS_FILE
            )
        end)

    if readOk ~= true
    or type(raw) ~= "string"
    or raw == "" then

        return false
    end

    local decodeOk,
        data =
        pcall(function()

            return HttpService:JSONDecode(
                raw
            )
        end)

    if decodeOk ~= true
    or type(data) ~= "table" then
        return false
    end

    HOLY_SNIPER_STATE.ActivateSniper =
        data.ActivateSniper == true

    HOLY_SNIPER_STATE.AutoHop =
        data.AutoHop == true

    HOLY_SNIPER_STATE.HopDelay =
        tostring(
            HolySniperReadHopDelay(
                data.HopDelay
                or HOLY_SNIPER_STATE.HopDelay
                or 5
            )
        )

    HOLY_SNIPER_STATE.AutoHopTiming =
        HolySniperNormalizeAutoHopTiming(
            data.AutoHopTiming
            or HOLY_SNIPER_STATE.AutoHopTiming
