    HOLY_SNIPER_STATE.ReturnTiming =
        HolySniperNormalizeReturnTiming(
            data.ReturnTiming
            or HOLY_SNIPER_STATE.ReturnTiming
            or "After Batch"
        )

    HOLY_SNIPER_STATE.ReturnMode =
        HolySniperNormalizeReturnMode(
