function HolyServerPruneRecentServers()

    local state =
        HolyServerNormalizeState()

    local now =
        os.time()

    for jobId, expiresAt in pairs(state.RecentServers) do

        if tonumber(expiresAt) == nil
        or tonumber(expiresAt) <= now then

            state.RecentServers[jobId] =
                nil
        end
    end
end

function HolyServerIsRecent(serverId)

    local state =
        HolyServerNormalizeState()

    if state.AvoidRecent ~= true then
        return false
    end

    serverId =
        HolyCleanText(
            serverId
        )

    if serverId == "" then
        return false
    end

    HolyServerPruneRecentServers()

    return tonumber(
        state.RecentServers[serverId]
    ) ~= nil
end

function HolyServerRememberRecent(serverId)

    local state =
        HolyServerNormalizeState()

    serverId =
        HolyCleanText(
            serverId
        )

    if serverId == "" then
        return false
    end

    local cooldown =
        tonumber(state.RecentCooldown)
        or 600

    if cooldown <= 0 then
        return false
    end

    state.RecentServers[serverId] =
        os.time() + cooldown

    return true
end

function HolyServerPruneFailedServers()

    local state =
        HolyServerNormalizeState()

    local now =
        os.time()

    for jobId, row in pairs(state.FailedServers or {}) do

        local expiresAt =
            0

        if type(row) == "table" then

            expiresAt =
                tonumber(row.ExpiresAt)
                or 0

        else

            expiresAt =
                tonumber(row)
                or 0
        end

        if expiresAt <= now then

            state.FailedServers[jobId] =
                nil
        end
    end
end

function HolyServerIsFailed(serverId)

    local state =
        HolyServerNormalizeState()

    serverId =
        HolyCleanText(
            serverId
        )

    if serverId == "" then
        return false
    end

    HolyServerPruneFailedServers()

    return state.FailedServers[serverId] ~= nil
end

function HolyServerRememberFailed(serverId, reason)

    local state =
        HolyServerNormalizeState()

    serverId =
        HolyCleanText(
            serverId
        )

    if serverId == "" then
        return false
    end

    local cooldown =
        tonumber(state.FailedCooldown)
        or 120

    if cooldown <= 0 then
        return false
    end

    state.FailedServers[serverId] = {
        ExpiresAt =
            os.time() + cooldown,

        Reason =
            tostring(reason or "failed"),
    }

    state.LastFailed =
        tostring(reason or "failed")
        .. " | "
        .. serverId:sub(1, 8)

    return true
end

function HolyServerGetPublicSortOrders(stage)

    local state =
        HolyServerNormalizeState()

    local style =
        HolyServerNormalizePickStyle(
            state.PickStyle
        )

    local minPlayers =
        tonumber(
            stage
            and stage.MinPlayers
        )
        or state.MinPlayers

    if style == "Lowest Real Server" then

        return {
            "Asc",
            "Desc",
        }
    end

    if minPlayers >= math.max(
        3,
        math.floor(HolyServerGetPlayerLimit() * 0.45)
    ) then

        return {
            "Desc",
            "Asc",
        }
    end

    if style == "Random Spread" then

        if math.random(1, 2) == 1 then

            return {
                "Desc",
                "Asc",
            }
        end

        return {
            "Asc",
            "Desc",
        }
    end

    return {
        "Desc",
        "Asc",
    }
end

function HolyServerBuildPublicServerUrl(cursor, sortOrder)

    sortOrder =
        HolyCleanText(
            sortOrder
        )

    if sortOrder ~= "Asc"
    and sortOrder ~= "Desc" then

        sortOrder =
            "Desc"
    end

    local url =
        "https://games.roblox.com/v1/games/"
        .. tostring(game.PlaceId)
        .. "/servers/Public?sortOrder="
        .. sortOrder
        .. "&limit=100&excludeFullGames=true"

    cursor =
        HolyCleanText(
            cursor
        )

    if cursor ~= "" then

        url =
            url
            .. "&cursor="
            .. HttpService:UrlEncode(
                cursor
            )
    end

    return url
end

function HolyServerRowAllowed(server, seen, stage)

    if type(server) ~= "table" then
        return false
    end

    local state =
        HolyServerNormalizeState()

    stage =
        type(stage) == "table"
        and stage
        or {}

    local serverId =
        HolyCleanText(
            server.id
        )

    if serverId == ""
    or serverId == tostring(game.JobId) then

        return false
    end

    if type(seen) == "table"
    and seen[serverId] == true then

        return false
    end

    local playing =
        tonumber(server.playing)
        or 0

    local maxPlayers =
        tonumber(server.maxPlayers)
        or 0

    if maxPlayers <= 0 then
        return false
    end

    if playing >= maxPlayers then
        return false
    end

    local minPlayers =
        tonumber(stage.MinPlayers)
        or state.MinPlayers

    local maxAllowedPlayers =
        tonumber(stage.MaxPlayers)
        or state.MaxPlayers

    if state.PickStyle == "Lowest Real Server"
    and stage.AllowLowReal ~= true then

        minPlayers =
            math.max(
                minPlayers,
                2
            )
    end

    if playing < minPlayers then
        return false
    end

    if playing > maxAllowedPlayers then
        return false
    end

    if stage.AllowRecent ~= true
    and HolyServerIsRecent(serverId) == true then

        return false
    end

    if stage.AllowFailed ~= true
    and HolyServerIsFailed(serverId) == true then

        return false
    end

    return true
end

function HolyServerGetCandidatePoolTarget()

    local state =
        HolyServerNormalizeState()

    local style =
        HolyServerNormalizePickStyle(
            state.PickStyle
        )

    if style == "Random Spread" then
        return 44
    end

    if style == "Random in Range" then
        return 28
    end

    if style == "Recommended" then
        return 24
    end

    if style == "Balanced" then
        return 22
    end

    if style == "Fullest Under Max" then
        return 18
    end

    if style == "Lowest Real Server" then
        return 18
    end

    return math.max(
        12,
        tonumber(SERVER_HOP_FAST_CANDIDATES)
        or 24
    )
end

function HolyServerAutoPageLimit(stage)

    local state =
        HolyServerNormalizeState()

    if state.SearchPages > 0 then
        return state.SearchPages
    end

    local style =
        HolyServerNormalizePickStyle(
            state.PickStyle
        )

    local stageName =
        tostring(
            stage
            and stage.Name
            or ""
        )

    if stageName == "Any Under Max" then
        return 2
    end

    if style == "Random Spread" then
        return 5
    end

    if style == "Recommended" then
        return 4
    end

    if style == "Balanced" then
        return 4
    end

    return 3
end

function HolyServerBuildSearchStages(forceAllowRecent)

    local state =
        HolyServerNormalizeState()

    local stages =
        {}

    local seen =
        {}

    local function addStage(name, minPlayers, maxPlayers, allowRecent, allowLowReal)

        minPlayers =
            math.clamp(
                math.floor(
                    tonumber(minPlayers)
                    or 0
                ),
                0,
                HolyServerGetPlayerLimit()
            )

        maxPlayers =
            math.clamp(
                math.floor(
                    tonumber(maxPlayers)
                    or HolyServerGetPlayerLimit()
                ),
                0,
                HolyServerGetPlayerLimit()
            )

        if maxPlayers < minPlayers then
            maxPlayers =
                minPlayers
        end

        local key =
            tostring(minPlayers)
            .. "|"
            .. tostring(maxPlayers)
            .. "|"
            .. tostring(allowRecent == true)
            .. "|"
            .. tostring(allowLowReal == true)

        if seen[key] == true then
            return
        end

        seen[key] =
            true

        table.insert(
            stages,
            {
                Name =
                    tostring(name or "Stage"),

                MinPlayers =
                    minPlayers,

                MaxPlayers =
                    maxPlayers,

                AllowRecent =
                    allowRecent == true,

                AllowLowReal =
                    allowLowReal == true,

                AllowFailed =
                    false,
            }
        )
    end

    addStage(
        "Strict",
        state.MinPlayers,
        state.MaxPlayers,
        forceAllowRecent == true,
        false
    )

    if state.MinPlayers > 0 then

        addStage(
            "Relaxed -1",
            state.MinPlayers - 1,
            state.MaxPlayers,
            forceAllowRecent == true,
            false
        )
    end

    if state.AvoidRecent == true
    and forceAllowRecent ~= true then

        addStage(
            "Allow Recent",
            state.MinPlayers,
            state.MaxPlayers,
            true,
            false
        )
    end

    addStage(
        "Any Under Max",
        0,
        state.MaxPlayers,
        true,
        true
    )

    return stages
end

function HolyServerFetchCandidates(allowRecent)

    local state =
        HolyServerNormalizeState()

    local candidates =
        {}

    local seenServers =
        {}

    local totalPagesRead =
        0

    local poolTarget =
        math.max(
            1,
            math.floor(
                tonumber(HolyServerGetCandidatePoolTarget())
                or 24
            )
        )

    local lastReason =
        "no servers scanned"

    local stages =
        HolyServerBuildSearchStages(
            allowRecent == true
        )

    for _, stage in ipairs(stages) do

        local stageCandidates =
            {}

        for _, sortOrder in ipairs(HolyServerGetPublicSortOrders(stage)) do

            local cursor =
                ""

            local seenCursors =
                {}

            local pagesReadThisSort =
                0

            local pageLimit =
                HolyServerAutoPageLimit(
                    stage
                )

            while true do

                if state.Hopping ~= true then
                    break
                end

                if pagesReadThisSort >= pageLimit then
                    break
                end

                pagesReadThisSort =
                    pagesReadThisSort + 1

                totalPagesRead =
                    totalPagesRead + 1

                HOLY_SERVER_STATE.LastPagesRead =
                    totalPagesRead

                HOLY_SERVER_STATE.LastCandidates =
                    #candidates

                HOLY_SERVER_STATE.LastFallbackStage =
                    stage.Name

                HOLY_SERVER_STATE.LastSortOrder =
                    sortOrder

                HolyServerSetStatus(
                    tostring(stage.Name)
                    .. " "
                    .. tostring(sortOrder)
                    .. " p"
                    .. tostring(pagesReadThisSort)
                    .. " · "
                    .. tostring(#candidates)
                    .. " found"
                )

                local body,
                    requestError =
                    HolyHttpGet(
                        HolyServerBuildPublicServerUrl(
                            cursor,
                            sortOrder
                        )
                    )

                if type(body) ~= "string"
                or body == "" then

                    lastReason =
                        "server list failed: "
                        .. tostring(requestError)

                    break
                end

                local decodeOk,
                    data =
                    pcall(function()

                        return HttpService:JSONDecode(
                            body
                        )
                    end)

                if decodeOk ~= true
                or type(data) ~= "table" then

                    lastReason =
                        "server list decode failed"

                    break
                end

                for _, server in ipairs(data.data or {}) do

                    local serverId =
                        HolyCleanText(
                            server.id
                        )

                    if HolyServerRowAllowed(
                        server,
                        seenServers,
                        stage
                    ) == true then

                        seenServers[serverId] =
                            true

                        local playing =
                            tonumber(server.playing)
                            or 0

                        local maxPlayers =
                            tonumber(server.maxPlayers)
                            or 0

                        server.FreeSlots =
                            math.max(
                                0,
                                maxPlayers - playing
                            )

                        server.HolyStage =
                            stage.Name

                        server.HolySortOrder =
                            sortOrder

                        server.HolyRandom =
                            math.random(
                                1,
                                1000000
                            )

                        table.insert(
                            candidates,
                            server
                        )

                        table.insert(
                            stageCandidates,
                            server
                        )

                        if #stageCandidates >= poolTarget then

                            HOLY_SERVER_STATE.LastCandidates =
                                #candidates

                            HOLY_SERVER_STATE.LastPagesRead =
                                totalPagesRead

                            HOLY_SERVER_STATE.LastFallbackStage =
                                stage.Name

                            HOLY_SERVER_STATE.LastSortOrder =
                                sortOrder

                            return stageCandidates,
                                "ok"
                        end
                    end
                end

                cursor =
                    HolyCleanText(
                        data.nextPageCursor
                    )

                if cursor == "" then
                    break
                end

                if seenCursors[cursor] == true then
                    break
                end

                seenCursors[cursor] =
                    true

                task.wait()
            end
        end

        if #stageCandidates > 0 then

            HOLY_SERVER_STATE.LastCandidates =
                #stageCandidates

            HOLY_SERVER_STATE.LastPagesRead =
                totalPagesRead

            HOLY_SERVER_STATE.LastFallbackStage =
                stage.Name

            return stageCandidates,
                "ok"
        end
    end

    HOLY_SERVER_STATE.LastCandidates =
        0

    HOLY_SERVER_STATE.LastPagesRead =
        totalPagesRead

    return {},
        "no servers found after smart search: "
        .. tostring(lastReason)
end

function HolyServerShuffleServers(servers)

    servers =
        type(servers) == "table"
        and servers
        or {}

    for index = #servers, 2, -1 do

        local swapIndex =
            math.random(
                1,
                index
            )

        servers[index],
            servers[swapIndex] =
            servers[swapIndex],
            servers[index]
    end

    return servers
end

function HolyServerPickFromTop(servers, limit)

    if type(servers) ~= "table"
    or #servers <= 0 then

        return nil
    end

    limit =
        math.min(
            #servers,
            math.max(
                1,
                math.floor(
                    tonumber(limit)
                    or 8
                )
            )
        )

    return servers[
        math.random(
            1,
            limit
        )
    ]
end

function HolyServerIdealTargetPlayers(state)

    state =
        state
        or HolyServerNormalizeState()

    local playerLimit =
        HolyServerGetPlayerLimit()

    local target =
        tonumber(state.TargetPlayers)
        or math.floor(
            (
                tonumber(state.MinPlayers)
                + tonumber(state.MaxPlayers)
            ) / 2
        )

    target =
        math.clamp(
            math.floor(target),
            tonumber(state.MinPlayers)
            or 0,
            tonumber(state.MaxPlayers)
            or playerLimit
        )

    if target >= playerLimit then
        target =
            playerLimit - 1
    end

    return math.max(
        0,
        target
    )
end

function HolyServerRecommendedScore(server, state)

    state =
        state
        or HolyServerNormalizeState()

    local playing =
        tonumber(server.playing)
        or 0

    local maxPlayers =
        tonumber(server.maxPlayers)
        or HolyServerGetPlayerLimit()

    local freeSlots =
        math.max(
            0,
            maxPlayers - playing
        )

    local ideal =
        HolyServerIdealTargetPlayers(
            state
        )

    local score =
        0

    score =
        score
        - math.abs(playing - ideal) * 120

    score =
        score
        + playing * 12

    score =
        score
        + freeSlots * 8

    if playing >= tonumber(state.MinPlayers)
    and playing <= tonumber(state.MaxPlayers) then

        score =
            score + 300
    end

    if playing == maxPlayers - 1 then

        score =
            score + 80
    end

    if tostring(server.HolyStage or "") == "Strict" then

        score =
            score + 200

    elseif tostring(server.HolyStage or "") == "Relaxed -1" then

        score =
            score + 100

    elseif tostring(server.HolyStage or "") == "Any Under Max" then

        score =
            score - 180
    end

    score =
        score
        + math.random(
            1,
            100
        ) / 100

    return score
end

function HolyServerPickTarget(servers)

    if type(servers) ~= "table"
    or #servers <= 0 then

        return nil
    end

    local state =
        HolyServerNormalizeState()

    local style =
        HolyServerNormalizePickStyle(
            state.PickStyle
        )

    HolyServerShuffleServers(
        servers
    )

    if style == "Random Spread"
    or style == "Random in Range" then

        return servers[
            math.random(
                1,
                #servers
            )
        ]
    end

    if style == "Fullest Under Max" then

        table.sort(servers, function(a, b)

            local playingA =
                tonumber(a.playing)
                or 0

            local playingB =
                tonumber(b.playing)
                or 0

            if playingA ~= playingB then
                return playingA > playingB
            end

            local freeA =
                tonumber(a.FreeSlots)
                or 0

            local freeB =
                tonumber(b.FreeSlots)
                or 0

            if freeA ~= freeB then
                return freeA < freeB
            end

            return tonumber(a.HolyRandom or 0)
                > tonumber(b.HolyRandom or 0)
        end)

        return HolyServerPickFromTop(
            servers,
            8
        )
    end

    if style == "Lowest Real Server" then

        table.sort(servers, function(a, b)

            local playingA =
                tonumber(a.playing)
                or 0

            local playingB =
                tonumber(b.playing)
                or 0

            local realA =
                playingA >= 2

            local realB =
                playingB >= 2

            if realA ~= realB then
                return realA == true
            end

            if playingA ~= playingB then
                return playingA < playingB
            end

            return tonumber(a.FreeSlots or 0)
                > tonumber(b.FreeSlots or 0)
        end)

        return HolyServerPickFromTop(
            servers,
            6
        )
    end

    if style == "Balanced" then

        local target =
            HolyServerIdealTargetPlayers(
                state
            )

        table.sort(servers, function(a, b)

            local playingA =
                tonumber(a.playing)
                or 0

            local playingB =
                tonumber(b.playing)
                or 0

            local distanceA =
                math.abs(
                    playingA - target
                )

            local distanceB =
                math.abs(
                    playingB - target
                )

            if distanceA ~= distanceB then
                return distanceA < distanceB
            end

            return tonumber(a.FreeSlots or 0)
                > tonumber(b.FreeSlots or 0)
        end)

        return HolyServerPickFromTop(
            servers,
            8
        )
    end

    table.sort(servers, function(a, b)

        local scoreA =
            HolyServerRecommendedScore(
                a,
                state
            )

        local scoreB =
            HolyServerRecommendedScore(
                b,
                state
            )

        if scoreA ~= scoreB then
            return scoreA > scoreB
        end

        return tonumber(a.HolyRandom or 0)
            > tonumber(b.HolyRandom or 0)
    end)

    return HolyServerPickFromTop(
        servers,
        10
    )
end

function HolyRememberServerTarget(target)

    if type(target) ~= "table" then
        return
    end

    HOLY_SERVER_STATE.LastTarget =
        tostring(target.playing or "?")
        .. "/"
        .. tostring(target.maxPlayers or "?")
        .. " | "
        .. tostring(
            target.id
            or "?"
        ):sub(
            1,
            8
        )
        .. " | "
        .. tostring(
            target.HolyStage
            or "Stage"
        )

    HOLY_SERVER_STATE.LastSortOrder =
        tostring(
            target.HolySortOrder
            or HOLY_SERVER_STATE.LastSortOrder
            or "None"
        )

    HOLY_SERVER_STATE.LastFallbackStage =
        tostring(
            target.HolyStage
            or HOLY_SERVER_STATE.LastFallbackStage
            or "None"
        )

    HolyServerRefreshUI()
end

function HolyQueueSmartServerHop(reason, failCallback)

    if HolySniperServerSwitchBlocked(
        "Server Hop",
        true
    ) == true then

        return false,
            "sniper protection"
    end

    local state =
        HolyServerNormalizeState()

    state.HopToken =
        (
            tonumber(state.HopToken)
            or 0
        )
        + 1

    local token =
        state.HopToken

    state.Hopping =
        true

    state.HopAttempt =
        0

    reason =
        tostring(reason or "server hop")

    HolyServerSetStatus(
        "Starting smart server search..."
    )

    task.spawn(function()

        while state.Hopping == true
        and state.HopToken == token do

            if HolySniperServerSwitchBlocked(
                "Server Hop",
                false
            ) == true then

                state.Hopping =
                    false

                if type(failCallback) == "function" then

                    pcall(
                        failCallback,
                        false,
                        "sniper protection"
                    )
                end

                return
            end

            state.HopAttempt =
                (
                    tonumber(state.HopAttempt)
                    or 0
                )
                + 1

            HolyServerSetStatus(
                "Finding "
                .. tostring(state.MinPlayers)
                .. "-"
                .. tostring(state.MaxPlayers)
                .. " · try "
                .. tostring(state.HopAttempt)
            )

            local servers,
                fetchReason =
                HolyServerFetchCandidates(
                    false
                )

            if state.Hopping ~= true
            or state.HopToken ~= token then
                return
            end

            if type(servers) ~= "table"
            or #servers <= 0 then

                HolyServerSetStatus(
                    tostring(fetchReason)
                    .. ". Retrying..."
                )

                task.wait(
                    state.RetryDelay
                )

                continue
            end

            local target =
                HolyServerPickTarget(
                    servers
                )

            if not target then

                HolyServerSetStatus(
                    "No server target. Retrying..."
                )

                task.wait(
                    state.RetryDelay
                )

                continue
            end

            if HolySniperServerSwitchBlocked(
                "Server Hop",
                false
            ) == true then

                state.Hopping =
                    false

                if type(failCallback) == "function" then

                    pcall(
                        failCallback,
                        false,
                        "sniper protection"
                    )
                end

                return
            end

            HolyRememberServerTarget(
                target
            )

            HolyServerRememberRecent(
                target.id
            )

            HolyServerSetStatus(
                "Joining "
                .. tostring(target.playing)
                .. "/"
                .. tostring(target.maxPlayers)
                .. "..."
            )

            local startedJobId =
                tostring(game.JobId)

            local ok,
                err =
                pcall(function()

                    TeleportService:TeleportToPlaceInstance(
                        game.PlaceId,
                        target.id,
                        LocalPlayer
                    )
                end)

            if ok == true then

                HolyServerSetStatus(
                    "Teleport queued to "
                    .. tostring(target.playing)
                    .. "/"
                    .. tostring(target.maxPlayers)
                    .. "."
                )

                local timeout =
                    tonumber(state.TeleportTimeout)
                    or 3

                if timeout <= 0 then

                    state.Hopping =
                        false

                    return
                end

                local startedAt =
                    os.clock()

                while state.Hopping == true
                and state.HopToken == token
                and os.clock() - startedAt < timeout do

                    if tostring(game.JobId) ~= startedJobId then
                        return
                    end

                    task.wait(
                        0.25
                    )
                end

                if state.Hopping ~= true
                or state.HopToken ~= token then
                    return
                end

                if tostring(game.JobId) == startedJobId then

                    HolyServerRememberFailed(
                        target.id,
                        "teleport timeout"
                    )

                    HolyServerSetStatus(
                        "Teleport timed out. Blocking target and retrying..."
                    )

                    task.wait(
                        state.RetryDelay
                    )

                    continue
                end

                return
            end

            HolyServerRememberFailed(
                target.id,
                "teleport failed"
            )

            HolyServerSetStatus(
                "Teleport failed. Blocking target and retrying..."
            )

            warn(
                "[HOLY PREMIUM SERVER HOP]",
                tostring(err)
            )

            task.wait(
                state.RetryDelay
            )
        end

        if state.HopToken == token then

            state.Hopping =
                false
        end
    end)

    return true,
        "queued"
end

function HolyCancelServerHop(reason)

    HOLY_SERVER_STATE =
        type(HOLY_SERVER_STATE) == "table"
        and HOLY_SERVER_STATE
        or {}

    HOLY_SERVER_STATE.HopToken =
        (
            tonumber(HOLY_SERVER_STATE.HopToken)
            or 0
        )
        + 1

    HOLY_SERVER_STATE.Hopping =
        false

    HOLY_SERVER_STATE.HopAttempt =
        0

    if type(HOLY_SNIPER_RUNTIME) == "table" then

        HOLY_SNIPER_RUNTIME.AutoHopInProgress =
            false

        HOLY_SNIPER_RUNTIME.HopFailureBackoffUntil =
            os.clock() + 2
    end

    HolyServerSetStatus(
        tostring(reason or "Hop cancelled.")
    )
end

function HolyRejoin()

