function HolyAntiAfkSetOverride()

    if not LocalPlayer then
        return false
    end

    local ok =
        pcall(function()

            LocalPlayer:SetAttribute(
                "AntiAfkIdleOverride",
                999999999
            )
        end)

    return ok == true
