    pcall(function()

        inputManager:SendKeyEvent(
            true,
            Enum.KeyCode.RightControl,
            false,
            game
        )
    end)

    task.wait(
        0.055
    )

    pcall(function()

        inputManager:SendKeyEvent(
            false,
            Enum.KeyCode.RightControl,
            false,
            game
        )
    end)

    return true
