end

function HolyDailyDealFormatDecimal(value)

    local number =
        tonumber(value)

    if number == nil then
        return "0"
    end

    local text =
        string.format(
            "%.4f",
            number
        )

    text =
        text:gsub(
            "0+$",
            ""
        )

    text =
        text:gsub(
            "%.$",
            ""
        )

    if text == "" then
        text = "0"
    end

    return text
end

function HolyDailyDealFormatMoney(value)

    value =
        math.max(
            0,
            math.floor(
                tonumber(value)
                or 0
            )
        )

    if value >= 1000000000000 then

        return string.format(
            "%.2fT¢",
            value / 1000000000000
        )
    end

    if value >= 1000000000 then

        return string.format(
            "%.2fB¢",
            value / 1000000000
        )
    end

    if value >= 1000000 then

        return string.format(
            "%.2fM¢",
            value / 1000000
        )
    end

    if value >= 1000 then

        return string.format(
            "%.2fK¢",
            value / 1000
        )
    end

    return tostring(value)
        .. "¢"
end

function HolyDailyDealFormatDuration(seconds)

    seconds =
        math.max(
            0,
            math.floor(
                tonumber(seconds)
                or 0
            )
        )

    local hours =
        math.floor(seconds / 3600)

    local minutes =
        math.floor((seconds % 3600) / 60)

    local remaining =
        seconds % 60

    if hours > 0 then

        return tostring(hours)
            .. "h "
            .. tostring(minutes)
            .. "m"
    end

    if minutes > 0 then

        return tostring(minutes)
            .. "m "
            .. tostring(remaining)
            .. "s"
    end

    return tostring(remaining)
        .. "s"
end

