function HolyDailyDealGetInputError()

    HolyDailyDealEnsureState()

    local order = {
        "MinStockMultiplier",
        "MinFriendBoost",
        "MinInventoryValue",
        "MinValue",
    }

    for _, key in ipairs(order) do

        local message =
            HOLY_DAILY_DEAL_RUNTIME.InputErrors[key]

        if message ~= nil then

            return tostring(message)
        end
    end

    for _, message in pairs(HOLY_DAILY_DEAL_RUNTIME.InputErrors) do

        return tostring(message)
    end

    return ""
end

function HolyDailyDealStrictNumber(value, minValue, maxValue, allowPercent)

    local text =
        HolyCleanText(
            value
        )

    if text == "" then
        return nil, "empty"
    end

    text =
        text:gsub(
            "%s+",
            ""
        )

    if allowPercent == true
    and text:sub(-1) == "%" then

        text =
            text:sub(1, #text - 1)
    end

    if text:find("%%", 1, true) then
        return nil, "bad percent"
    end

    if text:find(",", 1, true) then
        return nil, "commas not allowed"
    end

    local lower =
        text:lower()

    if lower:find("nan", 1, true)
    or lower:find("inf", 1, true) then

        return nil, "bad number"
    end

    if text:match("^%d+%.?%d*$") == nil then
        return nil, "numbers only"
    end

    local _,
        dotCount =
        text:gsub(
            "%.",
            ""
        )

    if dotCount > 1 then
        return nil, "too many decimals"
    end

    local number =
        tonumber(text)

    if number == nil then
        return nil, "bad number"
    end

    if minValue ~= nil
    and number < minValue then

        return nil,
            "minimum "
            .. tostring(minValue)
    end

    if maxValue ~= nil
    and number > maxValue then

        return nil,
            "maximum "
            .. tostring(maxValue)
    end

    return number,
        nil
end

function HolyDailyDealMoneySuffixMultiplier(suffix)

    suffix =
        HolyCleanText(
            suffix
        )
        :lower()

    local multipliers = {
        [""] = 1,

        k = 1000,
        thousand = 1000,

        m = 1000000,
        mil = 1000000,
        million = 1000000,

        b = 1000000000,
        bil = 1000000000,
        billion = 1000000000,

        t = 1000000000000,
        tril = 1000000000000,
        trillion = 1000000000000,

        q = 1000000000000000,
        qa = 1000000000000000,
        quad = 1000000000000000,
        quadrillion = 1000000000000000,
    }

    return multipliers[suffix]
end

function HolyDailyDealStrictMoney(value, minValue, maxValue)

    local text =
        HolyCleanText(
            value
        )

    if text == "" then
        return nil, "empty"
    end

    text =
        text:gsub(
            "%s+",
            ""
        )

    text =
        text:gsub("¢", "")
            :gsub("%$", "")

    if text:find(",", 1, true) then
        return nil, "commas not allowed"
    end

    local lower =
        text:lower()

    if lower:find("nan", 1, true)
    or lower:find("inf", 1, true)
    or lower:find("-", 1, true) then

        return nil, "bad number"
    end

    local numberText,
        suffix =
        lower:match(
            "^(%d+%.?%d*)([a-z]*)$"
        )

    if numberText == nil then
        return nil, "bad format"
    end

    local _,
        dotCount =
        numberText:gsub(
            "%.",
            ""
        )

    if dotCount > 1 then
        return nil, "too many decimals"
    end

    local number =
        tonumber(numberText)

    if number == nil then
        return nil, "bad number"
    end

    local multiplier =
        HolyDailyDealMoneySuffixMultiplier(
            suffix
        )

    if multiplier == nil then

        return nil,
            "bad suffix"
    end

    local final =
        number * multiplier

    if minValue ~= nil
    and final < minValue then

        return nil,
            "minimum "
            .. tostring(minValue)
    end

    if maxValue ~= nil
    and final > maxValue then

        return nil,
            "maximum "
            .. tostring(maxValue)
    end

    return final,
        nil
end

