function HolyDailyDealStockMultiplier(entries, fruitName)

    fruitName =
        HolyCleanText(
            fruitName
        )

    if fruitName == ""
    or type(entries) ~= "table" then

        return 0,
            "",
            ""
    end

    local direct =
        entries[fruitName]

    if type(direct) == "table" then

        return tonumber(direct.multiplier)
            or 0,
            fruitName,
            tostring(direct.tier or "")
    end

    local wantedKey =
        HolySellKey(
            fruitName
        )

    for stockFruitName, row in pairs(entries) do

        if HolySellKey(stockFruitName) == wantedKey
        and type(row) == "table" then

            return tonumber(row.multiplier)
                or 0,
                tostring(stockFruitName),
                tostring(row.tier or "")
        end
    end

    return 0,
        "",
        ""
end

function HolyDailyDealSelectionAllows(fruitName)

    HolyDailyDealEnsureState()

    fruitName =
        HolyCleanText(
            fruitName
        )

    if fruitName == "" then
        return false
    end

    local selected =
        HolyShopSelectionArray(
            HOLY_SHOP_STATE.DailyDealTriggerFruits
        )

    if #selected <= 0 then
        return true
    end

    for _, selectedFruit in ipairs(selected) do

        if selectedFruit == "All" then
            return true
        end

        if HolySellKey(selectedFruit) == HolySellKey(fruitName) then
            return true
        end
    end

    return false
end

function HolyDailyDealFindBestTrigger(entries)

    HolyDailyDealEnsureState()

    if type(entries) ~= "table" then

        return nil,
            "Waiting for stock data"
    end

    local selected =
        HolyShopSelectionArray(
            HOLY_SHOP_STATE.DailyDealTriggerFruits
            or {
                "All",
            }
        )

    if #selected <= 0 then

        selected = {
            "All",
        }
    end

    local useAll =
        false

    for _, fruitName in ipairs(selected) do

        if fruitName == "All" then

            useAll =
                true

            break
        end
    end

    local best =
        nil

    local function consider(stockFruitName, row)

        if type(row) ~= "table" then
            return
        end

        local multiplier =
            tonumber(row.multiplier)
            or 0

        local candidate = {
            Fruit =
                tostring(stockFruitName),

            StockName =
                tostring(stockFruitName),

            Multiplier =
                multiplier,

            Tier =
                tostring(row.tier or ""),
        }

        if best == nil
        or candidate.Multiplier > best.Multiplier then

            best =
                candidate
        end
    end

    if useAll == true then

        for stockFruitName, row in pairs(entries) do

            consider(
                stockFruitName,
                row
            )
        end

    else

        for _, selectedFruitName in ipairs(selected) do

            selectedFruitName =
                HolyCleanText(
                    selectedFruitName
                )

            if selectedFruitName ~= ""
            and selectedFruitName ~= "All" then

                local multiplier,
                    stockName,
                    tier =
                    HolyDailyDealStockMultiplier(
                        entries,
                        selectedFruitName
                    )

                if stockName ~= "" then

                    local candidate = {
                        Fruit =
                            selectedFruitName,

                        StockName =
                            stockName,

                        Multiplier =
                            tonumber(multiplier)
                            or 0,

                        Tier =
                            tostring(tier or ""),
                    }

                    if best == nil
                    or candidate.Multiplier > best.Multiplier then

                        best =
                            candidate
                    end
                end
            end
        end
    end

    if best == nil then

        return nil,
            "Waiting for selected stock"
    end

    return best,
        "ok"
end

function HolyDailyDealOtherSystemBlocked()

    if HOLY_SHOP_STATE.AutoSellFruits == true then

        return "Auto Sell Fruits is ON"
    end

    if HOLY_SHOP_STATE.AutoDoubleOrNothing == true
    or HOLY_SHOP_STATE.DoubleWorkerRunning == true
    or HOLY_SHOP_STATE.DoubleManualBusy == true then

        return "Gamble is busy"
    end

    local sniper =
        type(HOLY_SNIPER_RUNTIME) == "table"
        and HOLY_SNIPER_RUNTIME
        or {}

    if sniper.Buying == true
    or sniper.Returning == true
    or sniper.AutoHopInProgress == true then

        return "Sniper/server hop busy"
    end

    return ""
end

function HolyDailyDealExpectedValue(preview)

    preview =
        type(preview) == "table"
        and preview
        or {}

    local base =
        tonumber(preview.TotalBaseValue)
        or tonumber(preview.TotalValue)
        or 0

    local multiplier =
        HolyDailyDealGetDailyMultiplier()

    local expected =
        math.floor(
            base * multiplier
        )

    return expected,
        base,
        multiplier
end

function HolyDailyDealSetNextWait(seconds)

    HOLY_DAILY_DEAL_RUNTIME.NextWait =
        math.clamp(
            tonumber(seconds)
            or 10,
            3,
            60
        )

    return HOLY_DAILY_DEAL_RUNTIME.NextWait
end

function HolyDailyDealGetNextWait()

    return math.clamp(
        tonumber(HOLY_DAILY_DEAL_RUNTIME.NextWait)
        or 10,
        3,
        60
    )
end

function HolyDailyDealEvaluate(mode)

    HolyDailyDealEnsureState()

    mode =
        tostring(mode or "check")

    HolyDailyDealSetNextWait(
        10
    )

    if mode == "auto"
    and HolyDailyDealTextBoxFocused() == true then

        HolyDailyDealSetStatus(
            "Paused while typing"
        )

        HolyDailyDealSetNextWait(
            3
        )

        return false,
            "typing"
    end

    local settingsOk,
        settings =
        HolyDailyDealValidateSettings()

    if settingsOk ~= true then

        HolyDailyDealSetStatus(
            "⚠️ "
            .. tostring(settings)
        )

        HolyDailyDealSetNextWait(
            3
        )

        return false,
            tostring(settings)
    end

    if mode ~= "check" then

        local blocked =
            HolyDailyDealOtherSystemBlocked()

        if blocked ~= "" then

            HolyDailyDealSetStatus(
                "Blocked: "
                .. blocked
            )

            HolyDailyDealSetNextWait(
                8
            )

            return false,
                blocked
        end
    end

    HolyDailyDealSetStatus(
        "Checking stock..."
    )

    local stockResult,
        stockOk,
        stockReason =
        HolyDailyDealFireFruitStockRequest()

    if stockOk ~= true
    or type(stockResult) ~= "table"
    or type(stockResult.entries) ~= "table" then

        HolyDailyDealSetStatus(
            "Stock check failed"
        )

        HolyDailyDealSetStockText(
            "Stock: "
            .. tostring(stockReason or "missing")
        )

        return false,
            "stock failed"
    end

    local best,
        triggerReason =
        HolyDailyDealFindBestTrigger(
            stockResult.entries
        )

    if best == nil then

        HolyDailyDealSetStatus(
            tostring(triggerReason)
        )

        HolyDailyDealSetStockText(
            "Stock: no trigger fruit"
        )

        return false,
            tostring(triggerReason)
    end

    HolyDailyDealSetStockText(
        "Stock: "
        .. tostring(best.StockName)
        .. " X"
        .. HolyDailyDealFormatDecimal(best.Multiplier)
        .. " / Need X"
        .. HolyDailyDealFormatDecimal(settings.MinStockMultiplier)
    )

    if tonumber(best.Multiplier) < tonumber(settings.MinStockMultiplier) then

        HolyDailyDealSetStatus(
            "Waiting stock X"
            .. HolyDailyDealFormatDecimal(settings.MinStockMultiplier)
        )

        local waitSeconds =
            30

        if tonumber(stockResult.nextRefreshUnix)
        and tonumber(stockResult.server_now_unix) then

            waitSeconds =
                tonumber(stockResult.nextRefreshUnix)
                - tonumber(stockResult.server_now_unix)
        end

        HolyDailyDealSetNextWait(
            waitSeconds
        )

        return false,
            "stock too low"
    end

    local boost,
        boostText =
        HolyDailyDealReadFriendBoost()

    if boost < settings.MinFriendBoost then

        HolyDailyDealSetStatus(
            "Waiting boost "
            .. HolyDailyDealFormatDecimal(settings.MinFriendBoost)
            .. "%"
        )

        HolyDailyDealSetNextWait(
            20
        )

        return false,
            "boost too low"
    end

    HolyDailyDealSetStatus(
        "Checking availability..."
    )

    local checkResult,
        checkOk,
        checkReason =
        HolyDailyDealFireNpcPacket(
            "CheckDailyDeal"
        )

    if checkOk ~= true
    or type(checkResult) ~= "table" then

        HolyDailyDealSetStatus(
            "Daily check failed"
        )

        return false,
            tostring(checkReason or "check failed")
    end

    if checkResult.Available ~= true then

        local remaining =
            tonumber(checkResult.TimeRemaining)
            or 0

        HolyDailyDealSetStatus(
            "Cooldown "
            .. HolyDailyDealFormatDuration(
                remaining
            )
        )

        HolyDailyDealSetPreviewText(
            "Preview: skipped, cooldown"
        )

        HolyDailyDealSetNextWait(
            remaining
        )

        return false,
            "cooldown"
    end

    HolyDailyDealSetStatus(
        "Checking preview..."
    )

    local preview,
        previewOk,
        previewReason =
        HolyDailyDealFireNpcPacket(
            "PreviewSellAll"
        )

    if previewOk ~= true
    or type(preview) ~= "table" then

        HolyDailyDealSetStatus(
            "Preview failed"
        )

        HolyDailyDealSetPreviewText(
            "Preview: "
            .. tostring(previewReason or "failed")
        )

        return false,
            "preview failed"
    end

    local fruitCount =
        tonumber(preview.FruitCount)
        or 0

    local expectedDaily,
        baseValue,
        dailyMultiplier =
        HolyDailyDealExpectedValue(
            preview
        )

    HolyDailyDealSetPreviewText(
        "Preview: "
        .. tostring(fruitCount)
        .. " fruits | Inv "
        .. HolyDailyDealFormatMoney(
            baseValue
        )
        .. " → Daily "
        .. HolyDailyDealFormatMoney(
            expectedDaily
        )
    )

    if fruitCount <= 0 then

        HolyDailyDealSetStatus(
            "Preview has no fruit"
        )

        return false,
            "no preview fruit"
    end

    if settings.MinInventoryValue > 0
    and baseValue < settings.MinInventoryValue then

        HolyDailyDealSetStatus(
            "Inventory too low"
        )

        HolyDailyDealSetNextWait(
            20
        )

        return false,
            "inventory too low"
    end

    if settings.MinValue > 0
    and expectedDaily < settings.MinValue then

        HolyDailyDealSetStatus(
            "Daily payout too low"
        )

        HolyDailyDealSetNextWait(
            20
        )

        return false,
            "daily payout too low"
    end

    HolyDailyDealSetStatus(
        "Ready"
    )

    return true,
        "ready",
        {
            Settings =
                settings,

            Stock =
                stockResult,

            Best =
                best,

            FriendBoost =
                boost,

            FriendBoostText =
                boostText,

            Check =
                checkResult,

            Preview =
                preview,

            ExpectedDaily =
                expectedDaily,

            BaseValue =
                baseValue,

            DailyMultiplier =
                dailyMultiplier,
        }
end

function HolyDailyDealSyncAutoToggle()

    local options =
        HOLY_DEV_LIBRARY
        and HOLY_DEV_LIBRARY.Options
        or Options

    local toggle =
        type(options) == "table"
        and options.HolyShopAutoDailyDealAll
        or nil

    if type(toggle) == "table"
    and type(toggle.SetValue) == "function" then

        pcall(function()

            toggle:SetValue(
                HOLY_SHOP_STATE.AutoDailyDealAll == true,
                true
            )
        end)
    end

    return true
end

function HolyDailyDealRunUseAll(source)

    HolyDailyDealEnsureState()

    source =
        tostring(source or "manual")

    if HOLY_SHOP_STATE.DailyDealManualBusy == true then

        HolyDailyDealSetStatus(
            "Busy"
        )

        return false,
            "busy"
    end

    HOLY_SHOP_STATE.DailyDealManualBusy =
        true

    local success =
        false

    local reason =
        "unknown"

    local ok,
        err =
        pcall(function()

            local ready,
                readyReason,
                context =
                HolyDailyDealEvaluate(
                    source == "auto"
                    and "auto"
                    or "manual"
                )

            if ready ~= true then

                reason =
                    tostring(readyReason or "not ready")

                return
            end

            HolyDailyDealSetStatus(
                "Ready → selling"
            )

            local beforeMoney =
                type(HolySniperReadSheckles) == "function"
                and HolySniperReadSheckles()
                or nil

            local result,
                fireOk,
                fireReason =
                HolyDailyDealFireNpcPacket(
                    "UseDailyDealAll"
                )

            task.wait(
                0.25
            )

            local afterMoney =
                type(HolySniperReadSheckles) == "function"
                and HolySniperReadSheckles()
                or nil

            local moneyDelta =
                beforeMoney ~= nil
                and afterMoney ~= nil
                and afterMoney - beforeMoney
                or 0

            result =
                type(result) == "table"
                and result
                or {}

            local soldCount =
                tonumber(result.SoldCount)
                or 0

            local sellPrice =
                tonumber(result.SellPrice)
                or moneyDelta
                or 0

            if fireOk == true
            and (
                result.Success == true
                or soldCount > 0
                or moneyDelta > 0
            ) then

                success =
                    true

                reason =
                    "sold"

                HolyDailyDealSetLastText(
                    "Last: Sold "
                    .. tostring(soldCount)
                    .. " for "
                    .. HolyDailyDealFormatMoney(
                        sellPrice
                    )
                )

                if HOLY_SHOP_STATE.DailyDealAutoDisable == true then

                    HOLY_SHOP_STATE.AutoDailyDealAll =
                        false

                    HOLY_SHOP_STATE.DailyDealToken =
                        nil

                    HOLY_SHOP_STATE.DailyDealWorkerRunning =
                        false

                    HolySaveShopSettings()

                    HolyDailyDealSyncAutoToggle()
                end

                HolyDailyDealSetStatus(
                    "Sold "
                    .. tostring(soldCount)
                    .. " for "
                    .. HolyDailyDealFormatMoney(
                        sellPrice
                    )
                )

                if type(HolyNotify) == "function" then

                    HolyNotify(
                        "HOLY Daily Deal",
                        "Sold "
                        .. tostring(soldCount)
                        .. " fruit(s) for "
                        .. HolyDailyDealFormatMoney(sellPrice)
                        .. ".",
                        4
                    )
                end

            else

                reason =
                    tostring(fireReason or "sale failed")

                HolyDailyDealSetStatus(
                    "Failed: "
                    .. reason
                )

                HolyDailyDealSetLastText(
                    "Last: failed"
                )
            end
        end)

    if ok ~= true then

        reason =
            tostring(err)

        HolyDailyDealSetStatus(
            "Error: "
            .. reason
        )
    end

    HOLY_SHOP_STATE.DailyDealManualBusy =
        false

    return success,
        reason
end

function HolyDailyDealCheckNow()

    task.spawn(function()

        local ready,
            reason =
            HolyDailyDealEvaluate(
                "check"
            )

        if ready == true then

            HolyDailyDealSetStatus(
                "Ready / check only"
            )

        else

            HolyDailyDealSetLastText(
                "Last check: "
                .. tostring(reason)
            )
        end
    end)

    return true
end

function HolyDailyDealUseOnce()

    task.spawn(function()

        HolyDailyDealRunUseAll(
            "manual"
        )
    end)

    return true
end

function HolyDailyDealStopWorker(reason)

    HolyDailyDealEnsureState()

    HOLY_SHOP_STATE.AutoDailyDealAll =
        false

    HOLY_SHOP_STATE.DailyDealToken =
        nil

    HOLY_SHOP_STATE.DailyDealWorkerRunning =
        false

    HolySaveShopSettings()

    HolyDailyDealSetStatus(
        tostring(reason or "Off")
    )

    return true
end

function HolyDailyDealStartWorker(reason)

    HolyDailyDealEnsureState()

    if HOLY_SHOP_STATE.AutoDailyDealAll ~= true then
        return false
    end

    if HOLY_SHOP_STATE.DailyDealWorkerRunning == true then
        return false
    end

    local token =
        {}

    HOLY_SHOP_STATE.DailyDealToken =
        token

    HOLY_SHOP_STATE.DailyDealWorkerRunning =
        true

    HolyDailyDealSetStatus(
        "Starting..."
    )

    task.spawn(function()

        while HOLY_SHOP_STATE.AutoDailyDealAll == true
        and HOLY_SHOP_STATE.DailyDealToken == token do

            local ok,
                err =
                pcall(function()

                    HolyDailyDealRunUseAll(
                        "auto"
                    )
                end)

            if ok ~= true then

                HolyDailyDealSetStatus(
                    "Error: "
                    .. tostring(err)
                )

                HolyDailyDealSetNextWait(
                    10
                )
            end

            if HOLY_SHOP_STATE.AutoDailyDealAll ~= true then
                break
            end

            task.wait(
                HolyDailyDealGetNextWait()
            )
        end

        if HOLY_SHOP_STATE.DailyDealToken == token then

            HOLY_SHOP_STATE.DailyDealWorkerRunning =
                false

            HOLY_SHOP_STATE.DailyDealToken =
                nil
        end
    end)

    return true
end

function HolyDailyDealSetAutoEnabled(value, reason)

    HolyDailyDealEnsureState()

    HOLY_SHOP_STATE.AutoDailyDealAll =
        value == true

    HolySaveShopSettings()

    if HOLY_SHOP_STATE.AutoDailyDealAll == true then

        return HolyDailyDealStartWorker(
            reason or "toggle on"
        )
    end

    return HolyDailyDealStopWorker(
        reason or "Off"
    )
end

--==================================================
-- [2.61] AUTO DOUBLE OR NOTHING CORE
--==================================================

HOLY_DOUBLE_HUD =
    type(HOLY_DOUBLE_HUD) == "table"
    and HOLY_DOUBLE_HUD
    or {}

function HolyDoubleEnsureState()

    HOLY_SHOP_STATE =
        type(HOLY_SHOP_STATE) == "table"
        and HOLY_SHOP_STATE
        or {}

    HOLY_SHOP_UI =
        type(HOLY_SHOP_UI) == "table"
        and HOLY_SHOP_UI
        or {}

    HOLY_SHOP_STATE.DoubleStatus =
        tostring(
            HOLY_SHOP_STATE.DoubleStatus
            or "Ready"
        )

    HOLY_SHOP_STATE.DoubleTargetWins =
        tostring(
            HOLY_SHOP_STATE.DoubleTargetWins
            or "1"
        )

    HOLY_SHOP_STATE.DoubleBustFavDelay =
        tostring(
            HOLY_SHOP_STATE.DoubleBustFavDelay
            or "0.10"
        )

    HOLY_SHOP_STATE.DoubleUnfavoriteDelay =
        tostring(
            HOLY_SHOP_STATE.DoubleUnfavoriteDelay
            or "1.00"
        )

    HOLY_SHOP_STATE.DoubleTouchedRows =
        type(HOLY_SHOP_STATE.DoubleTouchedRows) == "table"
        and HOLY_SHOP_STATE.DoubleTouchedRows
        or {}

    HOLY_SHOP_STATE.DoubleLastPot =
        tonumber(HOLY_SHOP_STATE.DoubleLastPot)
        or 0

    HOLY_SHOP_STATE.DoubleLastWins =
        tonumber(HOLY_SHOP_STATE.DoubleLastWins)
        or 0

    HOLY_SHOP_STATE.DoubleLastMultiplier =
        tonumber(HOLY_SHOP_STATE.DoubleLastMultiplier)
        or 1

    HOLY_SHOP_STATE.DoubleLastStakeCount =
        tonumber(HOLY_SHOP_STATE.DoubleLastStakeCount)
        or 0

    HOLY_SHOP_STATE.DoubleLastResult =
        tostring(
            HOLY_SHOP_STATE.DoubleLastResult
            or "Ready"
        )

    return HOLY_SHOP_STATE
end

function HolyDoubleReadTargetWins(value)

    local text =
        HolyCleanText(
            value
            or HOLY_SHOP_STATE.DoubleTargetWins
            or "1"
        )

    local number =
        tonumber(
            text:match("%d+")
        )
        or 1

    number =
        math.floor(
            number
        )

    if number < 1 then

        number =
            1
    end

    return number
end

function HolyDoubleReadDelay(value, fallback, maxValue)

    local text =
        HolyCleanText(
            value
            or fallback
            or "0"
        )

    text =
        text:gsub(
            "[sS]",
            ""
        )

    local number =
        tonumber(
            text:match("%d+%.?%d*")
        )

    if number == nil then

        number =
            tonumber(fallback)
            or 0
    end

    return math.clamp(
        number,
        0,
        tonumber(maxValue)
        or 10
    )
end

function HolyDoubleFormatDelay(value, fallback)

    local number =
        HolyDoubleReadDelay(
            value,
            fallback or 0,
            10
        )

    local text =
        string.format(
            "%.2f",
            number
        )

    text =
        text:gsub(
            "0+$",
            ""
        )

    text =
        text:gsub(
            "%.$",
            ""
        )

    if text == "" then
        text = "0"
    end

    return text
end

function HolyDoubleFormatNumber(value)

    value =
        math.floor(
            tonumber(value)
            or 0
        )

    local text =
        tostring(value)

    while true do

        local newText =
            text:gsub(
                "^(-?%d+)(%d%d%d)",
                "%1,%2"
            )

        if newText == text then
            break
        end

        text =
            newText
    end

    return text
end

function HolyDoubleBuildStatusText()

    HolyDoubleEnsureState()

    return "🎲 Status: "
        .. tostring(
            HOLY_SHOP_STATE.DoubleStatus
            or "Ready"
        )
end

function HolyDoubleUpdateHud()

    HolyDoubleEnsureState()

    local hud =
        HOLY_DOUBLE_HUD

    if type(hud) ~= "table"
    or typeof(hud.Holder) ~= "Instance"
    or hud.Holder.Parent == nil then

        return false
    end

    local targetWins =
        HolyDoubleReadTargetWins()

    local wins =
        tonumber(
            HOLY_SHOP_STATE.DoubleLastWins
        )
        or 0

    local pot =
        tonumber(
            HOLY_SHOP_STATE.DoubleLastPot
        )
        or 0

    local nextPot =
        pot > 0
        and pot * 2
        or 0

    if hud.PotLabel then

        hud.PotLabel.Text =
            "💰 Pot: "
            .. HolyDoubleFormatNumber(
                pot
            )
    end

    if hud.WinsLabel then

        hud.WinsLabel.Text =
            "🏆 Wins: "
            .. tostring(wins)
            .. " / "
            .. tostring(targetWins)
    end

    if hud.NextLabel then

        hud.NextLabel.Text =
            "⏭️ Next: "
            .. (
                nextPot > 0
                and HolyDoubleFormatNumber(nextPot)
                or "--"
            )
    end

    if hud.StateLabel then

        hud.StateLabel.Text =
            "⚡ "
            .. tostring(
                HOLY_SHOP_STATE.DoubleStatus
                or "Ready"
            )
    end

    return true
end

function HolyDoubleRefreshUI()

    HolyDoubleEnsureState()

    if type(HolySniperSetLabel) == "function" then

        HolySniperSetLabel(
            HOLY_SHOP_UI.DoubleStatusLabel,
            HolyDoubleBuildStatusText()
        )
    end

    HolyDoubleUpdateHud()

    return true
end

