function HolyDoubleStillActive(token)

    HolyDoubleEnsureState()

    if HOLY_SHOP_STATE.AutoDoubleOrNothing ~= true then
        return false
    end

    if token ~= nil
    and HOLY_SHOP_STATE.DoubleToken ~= token then

        return false
    end

