function HolyDoubleFirePacket(packetName, ...)

    local packet =
        HolySellResolvePacket(
            packetName
        )

    if type(packet) ~= "table"
    or type(packet.Fire) ~= "function" then

        return nil,
            false,
            "packet missing: "
            .. tostring(packetName)
    end

    local ok,
        result =
        pcall(function(...)

            return packet:Fire(...)

        end, ...)

    if ok ~= true then

        return nil,
            false,
            tostring(result)
    end

    return result,
        true,
        "ok"
end

function HolyDoubleFavoritePacketIsValid(packet)

    return type(packet) == "table"
        and type(packet.Fire) == "function"
end

function HolyDoubleFavoritePacketNameMatches(key, value)

    local keyText =
        tostring(key or "")
        :lower()

    local nameText =
        ""

    if type(value) == "table" then

        for _, nameKey in ipairs({
            "Name",
            "PacketName",
            "RemoteName",
            "EventName",
            "_name",
            "__name",
        }) do

            local raw =
                value[nameKey]

            if raw ~= nil then

                nameText =
                    nameText
                    .. " "
                    .. tostring(raw)
            end
        end
    end

    local haystack =
        keyText
        .. " "
        .. nameText:lower()

    if haystack:find("setfruitfavorite", 1, true) then
        return true
    end

    if haystack:find("backpacksetfruitfavorite", 1, true) then
        return true
    end

    if haystack:find("fruit", 1, true)
    and haystack:find("favorite", 1, true) then

        return true
    end

    return false
end

function HolyDoubleFavoritePacketFromPath(root, pathParts)

    local current =
        root

    for _, part in ipairs(pathParts or {}) do

        if type(current) ~= "table" then
            return nil
        end

        current =
            current[part]
    end

    return current
end

function HolyDoubleFindFavoritePacketDeep(root, pathText, depth, seen)

    if type(root) ~= "table" then
        return nil, ""
    end

    depth =
        math.floor(
            tonumber(depth)
            or 0
        )

    if depth <= 0 then
        return nil, ""
    end

    seen =
        type(seen) == "table"
        and seen
        or {}

    if seen[root] == true then
        return nil, ""
    end

    seen[root] =
        true

    local foundPacket =
        nil

    local foundPath =
        ""

    pcall(function()

        for key, value in pairs(root) do

            if foundPacket ~= nil then
                return
            end

            local childPath =
                tostring(pathText or "Networking")
                .. "."
                .. tostring(key)

            if HolyDoubleFavoritePacketIsValid(value) == true
            and HolyDoubleFavoritePacketNameMatches(key, value) == true then

                foundPacket =
                    value

                foundPath =
                    childPath

                return
            end

            if type(value) == "table" then

                local nestedPacket,
                    nestedPath =
                    HolyDoubleFindFavoritePacketDeep(
                        value,
                        childPath,
                        depth - 1,
                        seen
                    )

                if HolyDoubleFavoritePacketIsValid(nestedPacket) == true then

                    foundPacket =
                        nestedPacket

                    foundPath =
                        nestedPath

                    return
                end
            end
        end
    end)

    return foundPacket,
        foundPath
end

function HolyDoubleResolveFavoritePacket(forceRefresh)

    HolyDoubleEnsureState()

    if forceRefresh == true then

        HOLY_SHOP_STATE.DoubleFavoritePacketCache =
            nil

        HOLY_SHOP_STATE.DoubleFavoritePacketPath =
            ""

        HOLY_SHOP_STATE.DoubleFavoritePacketLastError =
            ""
    end

    local cached =
        HOLY_SHOP_STATE.DoubleFavoritePacketCache

    if HolyDoubleFavoritePacketIsValid(cached) == true then

        return cached
    end

    HOLY_SHOP_STATE.DoubleFavoritePacketCache =
        nil

    local networking =
        HolyShopRequireModule(
            "SharedModules.Networking"
        )

    if type(networking) ~= "table" then

        HOLY_SHOP_STATE.DoubleFavoritePacketLastError =
            "SharedModules.Networking missing"

        return nil
    end

    local exactPaths = {
        {
            "Backpack",
            "SetFruitFavorite",
        },

        {
            "Backpack",
            "BackpackSetFruitFavorite",
        },

        {
            "BackpackSetFruitFavorite",
        },

        {
            "SetFruitFavorite",
        },

        {
            "Fruits",
            "SetFruitFavorite",
        },

        {
            "Fruit",
            "SetFruitFavorite",
        },

        {
            "Inventory",
            "SetFruitFavorite",
        },

        {
            "Tools",
            "SetFruitFavorite",
        },

        {
            "NPCS",
            "SetFruitFavorite",
        },
    }

    for _, pathParts in ipairs(exactPaths) do

        local packet =
            HolyDoubleFavoritePacketFromPath(
                networking,
                pathParts
            )

        if HolyDoubleFavoritePacketIsValid(packet) == true then

            HOLY_SHOP_STATE.DoubleFavoritePacketCache =
                packet

            HOLY_SHOP_STATE.DoubleFavoritePacketPath =
                "Networking."
                .. table.concat(
                    pathParts,
                    "."
                )

            HOLY_SHOP_STATE.DoubleFavoritePacketLastError =
                "ok"

            return packet
        end
    end

    local packet,
        packetPath =
        HolyDoubleFindFavoritePacketDeep(
            networking,
            "Networking",
            5,
            {}
        )

    if HolyDoubleFavoritePacketIsValid(packet) == true then

        HOLY_SHOP_STATE.DoubleFavoritePacketCache =
            packet

        HOLY_SHOP_STATE.DoubleFavoritePacketPath =
            tostring(packetPath or "Networking.?")

        HOLY_SHOP_STATE.DoubleFavoritePacketLastError =
            "ok"

        return packet
    end

    HOLY_SHOP_STATE.DoubleFavoritePacketCache =
        nil

    HOLY_SHOP_STATE.DoubleFavoritePacketPath =
        ""

    HOLY_SHOP_STATE.DoubleFavoritePacketLastError =
        "SetFruitFavorite not found"

    return nil
end

function HolyDoublePreviewNumbers(preview)

    preview =
        type(preview) == "table"
        and preview
        or {}

    local fruitCount =
        tonumber(preview.FruitCount)
        or 0

    local totalValue =
        tonumber(
            preview.TotalValue
            or preview.TotalBaseValue
            or preview.TotalSellValue
        )
        or 0

    return fruitCount,
        totalValue
end

function HolyDoubleDisableAutoSell()

    if HOLY_SHOP_STATE.AutoSellFruits ~= true then
        return false
    end

    HOLY_SHOP_STATE.AutoSellFruits =
        false

    if type(HolySellStopWorker) == "function" then

        HolySellStopWorker()
    end

    local library =
        type(HOLY_DEV_LIBRARY) == "table"
        and HOLY_DEV_LIBRARY
        or nil

    local toggles =
        library
        and type(library.Toggles) == "table"
        and library.Toggles
        or nil

    local toggle =
        toggles
        and toggles.HolyShopAutoSellFruits
        or nil

    if type(toggle) == "table"
    and type(toggle.SetValue) == "function" then

        pcall(function()

            toggle:SetValue(
                false
            )
        end)
    end

    HolySaveShopSettings()

    return true
end

function HolyDoubleToolIsFavorite(tool)

    if typeof(tool) ~= "Instance" then
        return false
    end

    local attrs =
        HolySellGetToolAttributes(
            tool
        )

    return attrs.IsFavorite == true
        or attrs.Favorite == true
        or attrs.Favorited == true
end

function HolyDoubleGetFruitRows()

    local rows =
        {}

    local seen =
        {}

    for _, tool in ipairs(HolySellGetFruitTools()) do

        local fruitId =
            HolySellResolveFruitId(
                tool
            )

        if fruitId ~= ""
        and seen[fruitId] ~= true then

            seen[fruitId] =
                true

            table.insert(
                rows,
                {
                    Id =
                        fruitId,

                    Tool =
                        tool,

                    Name =
                        HolySellGetToolFruitName(
                            tool
                        ),

                    WasFavorite =
                        HolyDoubleToolIsFavorite(
                            tool
                        ),

                    TouchedAt =
                        os.clock(),
                }
            )
        end
    end

    return rows
end

function HolyDoubleRememberTouchedRows(rows)

    HolyDoubleEnsureState()

    for _, row in ipairs(rows or {}) do

        local fruitId =
            HolyCleanText(
                row
                and row.Id
                or ""
            )

        if fruitId ~= "" then

            HOLY_SHOP_STATE.DoubleTouchedRows[fruitId] =
                row
        end
    end

    return true
end

function HolyDoubleForgetTouchedRows(rows)

    HolyDoubleEnsureState()

    for _, row in ipairs(rows or {}) do

        local fruitId =
            HolyCleanText(
                row
                and row.Id
                or ""
            )

        if fruitId ~= "" then

            HOLY_SHOP_STATE.DoubleTouchedRows[fruitId] =
                nil
        end
    end

    return true
end

function HolyDoublePruneTouchedRows()

    HolyDoubleEnsureState()

    local now =
        os.clock()

    for fruitId, row in pairs(HOLY_SHOP_STATE.DoubleTouchedRows) do

        local touchedAt =
            tonumber(
                row
                and row.TouchedAt
            )
            or 0

        if touchedAt <= 0
        or now - touchedAt > 45 then

            HOLY_SHOP_STATE.DoubleTouchedRows[fruitId] =
                nil
        end
    end

    return true
end

function HolyDoubleGetTouchedRows()

    HolyDoublePruneTouchedRows()

    local rows =
        {}

    for _, row in pairs(HOLY_SHOP_STATE.DoubleTouchedRows or {}) do

        if type(row) == "table"
        and HolyCleanText(row.Id) ~= "" then

            table.insert(
                rows,
                row
            )
        end
    end

    return rows
end

function HolyDoubleSetRowsFavorite(rows, favorite, reason)

    HolyDoubleEnsureState()

    rows =
        type(rows) == "table"
        and rows
        or {}

    if #rows <= 0 then

        HolyDoubleSetStatus(
            "🛡️ Fav skipped: no fruits"
        )

        return 0
    end

    local packet =
        HolyDoubleResolveFavoritePacket(
            false
        )

    if HolyDoubleFavoritePacketIsValid(packet) ~= true then

        task.wait(
            0.05
        )

        packet =
            HolyDoubleResolveFavoritePacket(
                true
            )
    end

    if HolyDoubleFavoritePacketIsValid(packet) ~= true then

        HolyDoubleSetStatus(
            "⚠️ Favorite packet missing: "
            .. tostring(
                HOLY_SHOP_STATE.DoubleFavoritePacketLastError
                or "not found"
            )
        )

        return 0
    end

    favorite =
        favorite == true

    if favorite == true then

        HolyDoubleRememberTouchedRows(
            rows
        )
    end

    local completed =
        0

    local success =
        0

    local total =
        0

    for _, row in ipairs(rows) do

        local fruitId =
            HolyCleanText(
                row
                and row.Id
                or ""
            )

        if fruitId ~= "" then

            total =
                total + 1

            task.spawn(function()

                local ok,
                    result =
                    pcall(function()

                        return packet:Fire(
                            fruitId,
                            favorite
                        )
                    end)

                if ok == true
                and result ~= false then

                    success =
                        success + 1
                end

                completed =
                    completed + 1
            end)
        end
    end

    if total <= 0 then

        HolyDoubleSetStatus(
            "🛡️ Fav skipped: no fruit IDs"
        )

        return 0
    end

    local startedAt =
        os.clock()

    while completed < total
    and os.clock() - startedAt <= 2.5 do

        task.wait(
            0.02
        )
    end

    if favorite ~= true then

        HolyDoubleForgetTouchedRows(
            rows
        )
    end

    local actionText =
        favorite == true
        and "Fav"
        or "Unfav"

    local actionIcon =
        favorite == true
        and "🛡️"
        or "🔓"

    local packetPath =
        HolyCleanText(
            HOLY_SHOP_STATE.DoubleFavoritePacketPath
            or ""
        )

    if packetPath == "" then

        packetPath =
            "favorite packet"
    end

    HolyDoubleSetStatus(
        actionIcon
        .. " "
        .. actionText
        .. " sent: "
        .. tostring(success)
        .. "/"
        .. tostring(total)
    )

    return success
end

function HolyDoubleReleaseRows(rows, reason, delayOverride)

    rows =
        type(rows) == "table"
        and rows
        or {}

    if #rows <= 0 then
        return 0
    end

    local delaySeconds =
        delayOverride

    if delaySeconds == nil then

        delaySeconds =
            HolyDoubleReadDelay(
                HOLY_SHOP_STATE.DoubleUnfavoriteDelay,
                1.00,
                10
            )
    end

    delaySeconds =
        math.max(
            0,
            tonumber(delaySeconds)
            or 0
        )

    if delaySeconds > 0 then

        task.wait(
            delaySeconds
        )
    end

    return HolyDoubleSetRowsFavorite(
        rows,
        false,
        reason or "release"
    )
end

function HolyDoubleUnfavoriteTouchedRows(reason)

    local touchedRows =
        HolyDoubleGetTouchedRows()

    if #touchedRows <= 0 then
        return 0
    end

    return HolyDoubleReleaseRows(
        touchedRows,
        reason or "restore touched",
        0
    )
end

function HolyDoubleUpdateFromRollResult(result)

    HolyDoubleEnsureState()

    result =
        type(result) == "table"
        and result
        or {}

    if result.Won == true then

        HOLY_SHOP_STATE.DoubleLastResult =
            "Won"

        HOLY_SHOP_STATE.DoubleLastWins =
            tonumber(result.Wins)
            or HOLY_SHOP_STATE.DoubleLastWins
            or 0

        HOLY_SHOP_STATE.DoubleLastPot =
            tonumber(result.Pot)
            or HOLY_SHOP_STATE.DoubleLastPot
            or 0

        HOLY_SHOP_STATE.DoubleLastMultiplier =
            tonumber(result.Multiplier)
            or HOLY_SHOP_STATE.DoubleLastMultiplier
            or 1

        HOLY_SHOP_STATE.DoubleLastStakeCount =
            tonumber(result.StakeCount)
            or HOLY_SHOP_STATE.DoubleLastStakeCount
            or 0

    elseif result.Busted == true then

        HOLY_SHOP_STATE.DoubleLastResult =
            "Busted"

        HOLY_SHOP_STATE.DoubleLastWins =
            tonumber(result.Wins)
            or 0

        HOLY_SHOP_STATE.DoubleLastPot =
            0

        HOLY_SHOP_STATE.DoubleLastStakeCount =
            tonumber(result.LostCount)
            or HOLY_SHOP_STATE.DoubleLastStakeCount
            or 0
    end

    HolyDoubleUpdateHud()
end

function HolyDoubleUpdateFromCashout(result)

    HolyDoubleEnsureState()

    result =
        type(result) == "table"
        and result
        or {}

    HOLY_SHOP_STATE.DoubleLastResult =
        "Cashed"

    HOLY_SHOP_STATE.DoubleLastWins =
        tonumber(result.Wins)
        or HOLY_SHOP_STATE.DoubleLastWins
        or 0

    HOLY_SHOP_STATE.DoubleLastPot =
        0

    HOLY_SHOP_STATE.DoubleLastStakeCount =
        tonumber(result.SoldCount)
        or HOLY_SHOP_STATE.DoubleLastStakeCount
        or 0

    HolyDoubleUpdateHud()
end

function HolyDoubleRollWithFavoriteRace(token, rollIndex, targetWins, requireActive)

    if requireActive == true
    and HolyDoubleStillActive(token) ~= true then

        return nil,
            false,
            "stopped",
            {}
    end

    local snapshotRows =
        HolyDoubleGetFruitRows()

    local favoriteDelay =
        HolyDoubleReadDelay(
            HOLY_SHOP_STATE.DoubleBustFavDelay,
            0.10,
            5
        )

    local rollDone =
        false

    local favoriteBusy =
        false

    local favoriteRows =
        nil

    local result =
        nil

    local rollOk =
        false

    local rollReason =
        "not started"

    task.spawn(function()

        result,
            rollOk,
            rollReason =
            HolyDoubleFirePacket(
                "DoubleOrNothing"
            )

        rollDone =
            true
    end)

    if #snapshotRows > 0 then

        task.delay(favoriteDelay, function()

            if rollDone == true then
                return
            end

            favoriteRows =
                snapshotRows

            favoriteBusy =
                true

            HolyDoubleSetRowsFavorite(
                snapshotRows,
                true,
                "roll race"
            )

            favoriteBusy =
                false
        end)
    end

    local deadline =
        os.clock() + 12

    while rollDone ~= true
    and os.clock() <= deadline do

        if requireActive == true
        and HolyDoubleStillActive(token) ~= true then

            rollDone =
                true

            return nil,
                false,
                "stopped",
                favoriteRows or {}
        end

        task.wait(
            0.02
        )
    end

    if rollDone ~= true then

        rollDone =
            true

        return nil,
            false,
            "roll timeout",
            favoriteRows or {}
    end

    local favoriteDeadline =
        os.clock() + 1.5

    while favoriteBusy == true
    and os.clock() <= favoriteDeadline do

        task.wait(
            0.02
        )
    end

    return result,
        rollOk,
        rollReason,
        favoriteRows or {}
end

function HolyDoubleDoOneRoll(token, rollIndex, targetWins, requireActive)

    HolyDoubleSetStatus(
        "🎲 Roll "
        .. tostring(rollIndex)
        .. "/"
        .. tostring(targetWins)
    )

    local result,
        rollOk,
        rollReason,
        favoriteRows =
        HolyDoubleRollWithFavoriteRace(
            token,
            rollIndex,
            targetWins,
            requireActive == true
        )

    if rollOk ~= true
    or type(result) ~= "table" then

        if #favoriteRows > 0 then

            HolyDoubleReleaseRows(
                favoriteRows,
                "roll failed restore"
            )
        end

        HolyDoubleSetStatus(
            "⚠️ Roll failed: "
            .. tostring(rollReason)
        )

        return false,
            result,
            "failed"
    end

    if result.Success == false then

        if #favoriteRows > 0 then

            HolyDoubleReleaseRows(
                favoriteRows,
                "blocked restore"
            )
        end

        HolyDoubleSetStatus(
            "⛔ Blocked: "
            .. tostring(result.Reason or "server")
        )

        return false,
            result,
            "blocked"
    end

    if result.Busted == true then

        HolyDoubleUpdateFromRollResult(
            result
        )

        HolyDoubleSetStatus(
            "💥 Busted: lost "
            .. tostring(result.LostCount or "?")
            .. " fruit(s)"
        )

        if #favoriteRows > 0 then

            HolyDoubleReleaseRows(
                favoriteRows,
                "busted restore"
            )
        end

        return true,
            result,
            "busted"
    end

    if result.Won == true then

        HolyDoubleUpdateFromRollResult(
            result
        )

        HolyDoubleSetStatus(
            "✅ Won "
            .. tostring(result.Wins or rollIndex)
            .. " | 💰 Pot "
            .. HolyDoubleFormatNumber(
                result.Pot or 0
            )
        )

        if #favoriteRows > 0 then

            HolyDoubleReleaseRows(
                favoriteRows,
                "won restore"
            )
        end

        return true,
            result,
            "won"
    end

    if #favoriteRows > 0 then

        HolyDoubleReleaseRows(
            favoriteRows,
            "unknown restore"
        )
    end

    HolyDoubleSetStatus(
        "⚠️ Unknown roll result"
    )

    return false,
        result,
        "unknown"
end

function HolyDoubleCashoutCurrent(requireActive, token)

    if requireActive == true
    and HolyDoubleStillActive(token) ~= true then

        return false
    end

    HolyDoubleSetStatus(
        "🔓 Restoring favorites..."
    )

    HolyDoubleUnfavoriteTouchedRows(
        "cashout restore"
    )

    task.wait(
        0.25
    )

    if requireActive == true
    and HolyDoubleStillActive(token) ~= true then

        return false
    end

    HolyDoubleSetStatus(
        "💰 Cashing out..."
    )

    local cashout,
        cashoutOk,
        cashoutReason =
        HolyDoubleFirePacket(
            "CashOutDoubleOrNothing"
        )

    if cashoutOk ~= true
    or type(cashout) ~= "table" then

        HolyDoubleSetStatus(
            "⚠️ Cashout failed: "
            .. tostring(cashoutReason)
        )

        return false
    end

    if cashout.Success == false then

        HolyDoubleSetStatus(
            "⛔ Cashout blocked: "
            .. tostring(cashout.Reason or "server")
        )

        return false
    end

    HolyDoubleUpdateFromCashout(
        cashout
    )

    HolyDoubleSetStatus(
        "💰 Cashed: +"
        .. HolyDoubleFormatNumber(
            cashout.SellPrice or 0
        )
        .. " | "
        .. tostring(cashout.SoldCount or "?")
        .. " fruit(s)"
    )

    return true
end

function HolyDoubleRunOnce(token)

    if HolyDoubleStillActive(token) ~= true then
        return false
    end

    local preview,
        previewOk,
        previewReason =
        HolyDoubleFirePacket(
            "PreviewSellAll"
        )

    if previewOk ~= true
    or type(preview) ~= "table" then

        HolyDoubleSetStatus(
            "⚠️ Preview failed: "
            .. tostring(previewReason)
        )

        return false
    end

    local fruitCount,
        totalValue =
        HolyDoublePreviewNumbers(
            preview
        )

    if fruitCount <= 0 then

        HolyDoubleSetStatus(
            "⏳ Waiting for fruits"
        )

        return false
    end

    local targetWins =
        HolyDoubleReadTargetWins()

    HolyDoubleSetStatus(
        "🎲 Rolling "
        .. tostring(fruitCount)
        .. " fruit(s) | 🎯 "
        .. tostring(targetWins)
        .. " win(s)"
    )

    local currentWins =
        0

    for rollIndex = 1, targetWins do

        if HolyDoubleStillActive(token) ~= true then
            return false
        end

        task.wait(
            rollIndex == 1
            and 0.15
            or 0.65
        )

        local rollSuccess,
            result,
            mode =
            HolyDoubleDoOneRoll(
                token,
                rollIndex,
                targetWins,
                true
            )

        if rollSuccess ~= true then
            return false
        end

        if mode == "busted" then
            return true
        end

        if mode == "won" then

            currentWins =
                tonumber(
                    result
                    and result.Wins
                )
                or rollIndex

            if currentWins >= targetWins then
                break
            end
        end
    end

    if currentWins < targetWins then

        HolyDoubleSetStatus(
            "⚠️ Stopped at "
            .. tostring(currentWins)
            .. " win(s)"
        )

        return false
    end

    if HolyDoubleStillActive(token) ~= true then
        return false
    end

    task.wait(
        0.35
    )

    return HolyDoubleCashoutCurrent(
        true,
        token
    )
end

function HolyDoubleManualDouble()

    HolyDoubleEnsureState()

    if HOLY_SHOP_STATE.DoubleWorkerRunning == true then

        HolyDoubleSetStatus(
            "⚠️ Manual blocked: auto running"
        )

        return false
    end

    if HOLY_SHOP_STATE.DoubleManualBusy == true then

        HolyDoubleSetStatus(
            "⏳ Manual busy"
        )

        return false
    end

    HOLY_SHOP_STATE.DoubleManualBusy =
        true

    task.spawn(function()

        local ok,
            err =
            pcall(function()

                HolyDoubleDisableAutoSell()

                local targetWins =
                    HolyDoubleReadTargetWins()

                local preview =
                    select(
                        1,
                        HolyDoubleFirePacket(
                            "PreviewSellAll"
                        )
                    )

                local fruitCount =
                    0

                if type(preview) == "table" then

                    fruitCount =
                        tonumber(preview.FruitCount)
                        or 0
                end

                if fruitCount <= 0 then

                    HolyDoubleSetStatus(
                        "⏳ No fruits to double"
                    )

                    return
                end

                HolyDoubleDoOneRoll(
                    nil,
                    1,
                    targetWins,
                    false
                )
            end)

        if ok ~= true then

            HolyDoubleSetStatus(
                "⚠️ Manual error: "
                .. tostring(err)
            )
        end

        HOLY_SHOP_STATE.DoubleManualBusy =
            false
    end)

    return true
end

function HolyDoubleManualCashout()

    HolyDoubleEnsureState()

    if HOLY_SHOP_STATE.DoubleWorkerRunning == true then

        HolyDoubleSetStatus(
            "⚠️ Manual blocked: auto running"
        )

        return false
    end

    if HOLY_SHOP_STATE.DoubleManualBusy == true then

        HolyDoubleSetStatus(
            "⏳ Manual busy"
        )

        return false
    end

    HOLY_SHOP_STATE.DoubleManualBusy =
        true

    task.spawn(function()

        local ok,
            err =
            pcall(function()

                HolyDoubleCashoutCurrent(
                    false,
                    nil
                )
            end)

        if ok ~= true then

            HolyDoubleSetStatus(
                "⚠️ Cashout error: "
                .. tostring(err)
            )
        end

        HOLY_SHOP_STATE.DoubleManualBusy =
            false
    end)

    return true
end

function HolyDoubleGetHudRoot()

    local library =
        type(HOLY_DEV_LIBRARY) == "table"
        and HOLY_DEV_LIBRARY
        or nil

    if library
    and typeof(library.ScreenGui) == "Instance" then

        return library.ScreenGui,
            nil
    end

    local screenGui =
        HOLY_DOUBLE_HUD
        and HOLY_DOUBLE_HUD.ScreenGui
        or nil

    if typeof(screenGui) == "Instance"
    and screenGui.Parent ~= nil then

        return screenGui,
            screenGui
    end

    screenGui =
        Instance.new(
            "ScreenGui"
        )

    screenGui.Name =
        "HolyDoubleOrNothingHudGui"

    screenGui.ResetOnSpawn =
        false

    screenGui.IgnoreGuiInset =
        true

    screenGui.ZIndexBehavior =
        Enum.ZIndexBehavior.Sibling

    screenGui.Parent =
        CoreGui

    return screenGui,
        screenGui
end

function HolyDoubleReadHudPosition()

    local position =
        HOLY_SHOP_STATE.DoubleHudPosition

    if type(position) == "table" then

        local x =
            tonumber(
                position.X
                or position.x
                or position[1]
            )

        local y =
            tonumber(
                position.Y
                or position.y
                or position[2]
            )

        if x
        and y then

            return UDim2.fromOffset(
                math.floor(x + 0.5),
                math.floor(y + 0.5)
            )
        end
    end

    return UDim2.fromOffset(
        18,
        180
    )
end

function HolyDoubleSaveHudPosition()

    local holder =
        HOLY_DOUBLE_HUD
        and HOLY_DOUBLE_HUD.Holder
        or nil

    if typeof(holder) ~= "Instance" then
        return false
    end

    HOLY_SHOP_STATE.DoubleHudPosition = {
        X =
            math.floor(
                holder.Position.X.Offset + 0.5
            ),

        Y =
            math.floor(
                holder.Position.Y.Offset + 0.5
            ),
    }

    HolySaveShopSettings()

    return true
end

function HolyDoubleMakeHudLabel(parent, text, y, size, transparency)

    local label =
        Instance.new(
            "TextLabel"
        )

    label.BackgroundTransparency =
        1

    label.Position =
        UDim2.fromOffset(
            10,
            y
        )

    label.Size =
        UDim2.new(
            1,
            -20,
            0,
            size
        )

    label.Text =
        tostring(text or "")

    label.TextSize =
        size

    label.TextTransparency =
        transparency or 0.08

    label.TextXAlignment =
        Enum.TextXAlignment.Left

    label.TextYAlignment =
        Enum.TextYAlignment.Center

    label.TextTruncate =
        Enum.TextTruncate.AtEnd

    local scheme =
        HOLY_DEV_LIBRARY
        and HOLY_DEV_LIBRARY.Scheme
        or {}

    label.TextColor3 =
        scheme.FontColor
        or Color3.fromRGB(
            245,
            245,
            247
        )

    label.FontFace =
        scheme.Font
        or Font.fromEnum(
            Enum.Font.GothamMedium
        )

    label.ZIndex =
        parent.ZIndex + 2

    label.Parent =
        parent

    return label
end

function HolyDoubleMakeHudDraggable(holder)

    if typeof(holder) ~= "Instance" then
        return false
    end

    local dragging =
        false

    local dragInput =
        nil

    local dragStart =
        nil

    local startPosition =
        nil

    HOLY_DOUBLE_HUD.Connections =
        HOLY_DOUBLE_HUD.Connections
        or {}

    table.insert(
        HOLY_DOUBLE_HUD.Connections,
        holder.InputBegan:Connect(function(input)

            if input.UserInputType == Enum.UserInputType.MouseButton1
            or input.UserInputType == Enum.UserInputType.Touch then

                dragging =
                    true

                dragStart =
                    input.Position

                startPosition =
                    holder.Position

                input.Changed:Connect(function()

                    if input.UserInputState == Enum.UserInputState.End then

                        dragging =
                            false

                        HolyDoubleSaveHudPosition()
                    end
                end)
            end
        end)
    )

    table.insert(
        HOLY_DOUBLE_HUD.Connections,
        holder.InputChanged:Connect(function(input)

            if input.UserInputType == Enum.UserInputType.MouseMovement
            or input.UserInputType == Enum.UserInputType.Touch then

                dragInput =
                    input
            end
        end)
    )

    table.insert(
        HOLY_DOUBLE_HUD.Connections,
        UserInputService.InputChanged:Connect(function(input)

            if input ~= dragInput
            or dragging ~= true
            or dragStart == nil
            or startPosition == nil then

                return
            end

            local delta =
                input.Position - dragStart

            holder.Position =
                UDim2.fromOffset(
                    startPosition.X.Offset + delta.X,
                    startPosition.Y.Offset + delta.Y
                )
        end)
    )

    return true
end

function HolyDoubleDestroyHud()

    if type(HOLY_DOUBLE_HUD) == "table"
    and type(HOLY_DOUBLE_HUD.Connections) == "table" then

        for _, connection in ipairs(HOLY_DOUBLE_HUD.Connections) do

            pcall(function()

                connection:Disconnect()
            end)
        end
    end

    if type(HOLY_DOUBLE_HUD) == "table"
    and typeof(HOLY_DOUBLE_HUD.Holder) == "Instance" then

        pcall(function()

            HOLY_DOUBLE_HUD.Holder:Destroy()
        end)
    end

    if type(HOLY_DOUBLE_HUD) == "table"
    and typeof(HOLY_DOUBLE_HUD.ScreenGui) == "Instance" then

        pcall(function()

            HOLY_DOUBLE_HUD.ScreenGui:Destroy()
        end)
    end

    HOLY_DOUBLE_HUD =
        {}

    return true
end

function HolyDoubleCreateHud()

    if type(HOLY_DOUBLE_HUD) == "table"
    and typeof(HOLY_DOUBLE_HUD.Holder) == "Instance"
    and HOLY_DOUBLE_HUD.Holder.Parent ~= nil then

        HolyDoubleUpdateHud()

        return HOLY_DOUBLE_HUD
    end

    HolyDoubleDestroyHud()

    local parent,
        ownedScreenGui =
        HolyDoubleGetHudRoot()

    local scheme =
        HOLY_DEV_LIBRARY
        and HOLY_DEV_LIBRARY.Scheme
        or {}

    local holder =
        Instance.new(
            "Frame"
        )

    holder.Name =
        "HolyDoubleOrNothingHud"

    holder.Active =
        true

    holder.BackgroundColor3 =
        scheme.BackgroundColor
        or Color3.fromRGB(
            12,
            13,
            16
        )

    holder.BackgroundTransparency =
        0.36

    holder.BorderSizePixel =
        0

    holder.Position =
        HolyDoubleReadHudPosition()

    holder.Size =
        UDim2.fromOffset(
            172,
            90
        )

    holder.ZIndex =
        9300

    holder.Parent =
        parent

    local corner =
        Instance.new(
            "UICorner"
        )

    corner.CornerRadius =
        UDim.new(
            0,
            8
        )

    corner.Parent =
        holder

    local stroke =
        Instance.new(
            "UIStroke"
        )

    stroke.Color =
        scheme.OutlineColor
        or Color3.fromRGB(
            45,
            20,
            25
        )

    stroke.Transparency =
        0.42

    stroke.Thickness =
        1

    stroke.Parent =
        holder

    local accent =
        Instance.new(
            "Frame"
        )

    accent.BackgroundColor3 =
        scheme.AccentColor
        or Color3.fromRGB(
            232,
            45,
            67
        )

    accent.BackgroundTransparency =
        0.05

    accent.BorderSizePixel =
        0

    accent.Position =
        UDim2.fromOffset(
            0,
            0
        )

    accent.Size =
        UDim2.new(
            0,
            3,
            1,
            0
        )

    accent.ZIndex =
        holder.ZIndex + 1

    accent.Parent =
        holder

    local accentCorner =
        Instance.new(
            "UICorner"
        )

    accentCorner.CornerRadius =
        UDim.new(
            1,
            0
        )

    accentCorner.Parent =
        accent

    HOLY_DOUBLE_HUD = {
        Holder =
            holder,

        ScreenGui =
            ownedScreenGui,

        Connections =
            {},

        TitleLabel =
            HolyDoubleMakeHudLabel(
                holder,
                "🎲 Gamble",
                5,
                13,
                0.02
            ),

        PotLabel =
            HolyDoubleMakeHudLabel(
                holder,
                "💰 Pot: --",
                27,
                12,
                0.15
            ),

        WinsLabel =
            HolyDoubleMakeHudLabel(
                holder,
                "🏆 Wins: 0 / 1",
                44,
                12,
                0.15
            ),

        NextLabel =
            HolyDoubleMakeHudLabel(
                holder,
                "⏭️ Next: --",
                61,
                12,
                0.22
            ),

        StateLabel =
            HolyDoubleMakeHudLabel(
                holder,
                "⚡ Ready",
                75,
                11,
                0.28
            ),
    }

    HolyDoubleMakeHudDraggable(
        holder
    )

    HolyDoubleUpdateHud()

    return HOLY_DOUBLE_HUD
end

function HolyDoubleSetHudVisible(value)

    HolyDoubleEnsureState()

    HOLY_SHOP_STATE.DoubleHudEnabled =
        value == true

    HolySaveShopSettings()

    if HOLY_SHOP_STATE.DoubleHudEnabled == true then

        HolyDoubleCreateHud()

    else

        HolyDoubleDestroyHud()
    end

    return true
end

function HolyDoubleStartWorker(reason)

    HolyDoubleEnsureState()

    HOLY_SHOP_STATE.AutoDoubleOrNothing =
        true

    HolySaveShopSettings()

    HolyDoubleDisableAutoSell()

    if HOLY_SHOP_STATE.DoubleWorkerRunning == true then
        return false
    end

    local token =
        {}

    HOLY_SHOP_STATE.DoubleToken =
        token

    HOLY_SHOP_STATE.DoubleWorkerRunning =
        true

    HolyDoubleSetStatus(
        "🚀 Starting..."
    )

    task.spawn(function()

        while HolyDoubleStillActive(token) == true do

            local ok,
                err =
                pcall(function()

                    HolyDoubleRunOnce(
                        token
                    )
                end)

            if ok ~= true then

                HolyDoubleSetStatus(
                    "⚠️ Error: "
                    .. tostring(err)
                )

                task.wait(
                    1.25
                )

            else

                task.wait(
                    0.75
                )
            end
        end

        if HOLY_SHOP_STATE.DoubleToken == token then

            HOLY_SHOP_STATE.DoubleToken =
                nil
        end

        HOLY_SHOP_STATE.DoubleWorkerRunning =
            false

        if HOLY_SHOP_STATE.AutoDoubleOrNothing ~= true then

            HolyDoubleSetStatus(
                "Off"
            )
        end
    end)

    return true
end

function HolyDoubleStopWorker(reason)

    HolyDoubleEnsureState()

    HOLY_SHOP_STATE.AutoDoubleOrNothing =
        false

    HOLY_SHOP_STATE.DoubleToken =
        nil

    HOLY_SHOP_STATE.DoubleWorkerRunning =
        false

    HolySaveShopSettings()

    HolyDoubleSetStatus(
        tostring(reason or "Off")
    )

    return true
end

function HolySellAllOnce()

    HolySellFirePacket(
        "PreviewSellAll"
    )

    task.wait(
        0.05
    )

    return HolySellFirePacket(
        "SellAll"
    )
end

function HolySellGetToolAttributes(tool)

    local attrs =
        {}

    if typeof(tool) ~= "Instance" then
        return attrs
    end

    pcall(function()

        attrs =
            tool:GetAttributes()
    end)

    return type(attrs) == "table"
        and attrs
        or {}
end

function HolySellKey(value)

    return HolyCleanText(
        value
    )
        :lower()
        :gsub("[%s_%-%[%]%(%)%.]", "")
end

function HolySellFruitNameCandidates(fruitName)

    fruitName =
        HolyCleanText(
            fruitName
        )

    local candidates =
        {}

    local seen =
        {}

    local function add(value)

        value =
            HolyCleanText(
                value
            )

        if value == ""
        or seen[value] == true then
            return
        end

        seen[value] =
            true

        table.insert(
            candidates,
            value
        )
    end

    add(
        fruitName
    )

    local prefixes = {
        "Baby ",
        "Big ",
        "Huge ",
        "Mega ",
        "Small ",
        "Large ",
        "Giant ",
        "Gold ",
        "Golden ",
        "Rainbow ",
    }

    for _, prefix in ipairs(prefixes) do

        if fruitName:sub(1, #prefix):lower() == prefix:lower() then

            add(
                fruitName:sub(
                    #prefix + 1
                )
            )
        end
    end

    return candidates
end

function HolySellBuildRarityMap()

    if type(HOLY_SHOP_STATE.SellRarityMap) == "table" then

        return HOLY_SHOP_STATE.SellRarityMap
    end

    local map =
        {}

    local data =
        HolyShopRequireModule(
            "SharedModules.SeedData"
        )

    if type(data) == "table" then

        for _, row in pairs(data) do

            if type(row) == "table" then

                local seedName =
                    HolyCleanText(
                        row.SeedName
                        or row.Name
                        or row.FruitName
                        or row.CropName
                    )

                local rarity =
                    HolyCleanText(
                        row.Rarity
                        or row.SeedRarity
                        or row.FruitRarity
                        or ""
                    )

                if seedName ~= ""
                and rarity ~= "" then

                    map[
                        HolySellKey(
                            seedName
                        )
                    ] =
                        rarity
                end
            end
        end
    end

    HOLY_SHOP_STATE.SellRarityMap =
        map

    return map
end

function HolySellListInsertSorted(map, value)

    value =
        HolyCleanText(
            value
        )

    if value == "" then
        return
    end

    map[value] =
        true
end

function HolySellMapToValues(map, includeAll, includeNone)

    local values =
        {}

    if includeAll == true then

        table.insert(
            values,
            "All"
        )
    end

    if includeNone == true then

        table.insert(
            values,
            "None"
        )
    end

    local sorted =
        {}

    for value in pairs(map or {}) do

        if value ~= "All"
        and value ~= "None" then

            table.insert(
                sorted,
                value
            )
        end
    end

    table.sort(sorted, function(a, b)

        return tostring(a) < tostring(b)
    end)

    for _, value in ipairs(sorted) do

        table.insert(
            values,
            value
        )
    end

    return values
end

function HolySellAppendValue(values, seen, value)

    value =
        HolyCleanText(
            value
        )

    if value == ""
    or seen[value] == true then
        return
    end

    seen[value] =
        true

    table.insert(
        values,
        value
    )
end

function HolySellGetFruitDropdownValues()

    local values = {
        "All",
    }

    local seen = {
        All = true,
    }

    local data =
        HolyShopRequireModule(
            "SharedModules.SeedData"
        )

    local rows =
        {}

    if type(data) == "table" then

        for _, row in pairs(data) do

            if type(row) == "table"
            and row.MutationSeed ~= true then

                local fruitName =
                    HolyCleanText(
                        row.FruitName
                        or row.SeedName
                        or row.CropName
                        or row.Name
                    )

                if fruitName ~= "" then

                    table.insert(
                        rows,
                        fruitName
                    )
                end
            end
        end
    end

    table.sort(rows, function(a, b)

        return tostring(a) < tostring(b)
    end)

    for _, fruitName in ipairs(rows) do

        HolySellAppendValue(
            values,
            seen,
            fruitName
        )
    end

    return values
end

