function HolyPerformanceDisconnectConnections()

    HOLY_PERFORMANCE_STATE =
        type(HOLY_PERFORMANCE_STATE) == "table"
        and HOLY_PERFORMANCE_STATE
        or {}

    HolyPerformanceDisconnectConnectionMap(
        HOLY_PERFORMANCE_STATE.Connections
    )

    HolyPerformanceDisconnectConnectionMap(
