function HolyApplyUIScale(value)

    local scale =
        HolyParseScale(
            value
        )

    HOLY_DEV_UI_STATE.DPIScale =
        scale

    if Library
    and type(Library.SetDPIScale) == "function" then

        pcall(function()

            Library:SetDPIScale(
                scale
            )
        end)
    end

    return true
end

Library.ForceCheckbox =
