local function HolySniperOnlyDummy()

    if HOLY_SNIPER_ONLY_DUMMY_CONTROL ~= nil then
        return HOLY_SNIPER_ONLY_DUMMY_CONTROL
    end

    local dummy = {}

    local methodNames = {
        AddLeftGroupbox = true,
        AddRightGroupbox = true,
        AddLeftCollapsibleGroupbox = true,
        AddRightCollapsibleGroupbox = true,
        AddTab = true,
        AddLabel = true,
        AddButton = true,
        AddToggle = true,
        AddCheckbox = true,
        AddDropdown = true,
        AddInput = true,
        AddSlider = true,
        AddDivider = true,
        AddTable = true,
        AddPetMarketList = true,
        AddSniperWatchlist = true,
        AddActionRow = true,
        AddTopNavigation = true,
        AddTopSegmentedControl = true,
        AddDependencyBox = true,
        AddDependencyGroupbox = true,
        OnChanged = true,
        SetValue = true,
        SetValues = true,
        SetText = true,
        SetRows = true,
        SetSummary = true,
        SetModeText = true,
        SetStateByKey = true,
        SetScale = true,
        SetAutoJoinMode = true,
        SetDisabled = true,
        SetSelected = true,
        RefreshSides = true,
        Resize = true,
        Hide = true,
        Show = true,
        Destroy = true,
    }

    setmetatable(dummy, {
        __index = function(_, key)

            if key == "GetSelectedData" then

                return function()
                    return nil
                end
            end

            if methodNames[key] == true then

                return function()
                    return dummy
                end
            end

            return nil
        end,
    })

    HOLY_SNIPER_ONLY_DUMMY_CONTROL = dummy

    return dummy
end

local function HolySniperOnlyDummyTab()

    return HolySniperOnlyDummy()
