function HolyServerFinderBuildSavePayload()

    HolyServerFinderEnsureAutoJoinState()

    return {
        Enabled =
            HOLY_SERVER_FINDER_STATE.Enabled == true,

        AutoRefresh =
            HOLY_SERVER_FINDER_STATE.AutoRefresh == true,

        RefreshDelay =
            math.clamp(
                tonumber(HOLY_SERVER_FINDER_STATE.RefreshDelay)
                or 5,
                1,
                60
            ),

        HideFull =
            HOLY_SERVER_FINDER_STATE.HideFull ~= false,

        HudScale =
            HolyServerFinderGetHudScale(),

        SelectedPets =
            HolyServerFinderArrayFromMap(
                HOLY_SERVER_FINDER_STATE.SelectedPets
            ),

        SelectedRarities =
            HolyServerFinderArrayFromMap(
                HOLY_SERVER_FINDER_STATE.SelectedRarities
            ),

        SelectedSizes =
            HolyServerFinderArrayFromMap(
                HOLY_SERVER_FINDER_STATE.SelectedSizes
            ),

        SelectedVariants =
            HolyServerFinderArrayFromMap(
                HOLY_SERVER_FINDER_STATE.SelectedVariants
            ),

        AutoJoinMode =
            HolyServerFinderNormalizeAutoJoinMode(
                HOLY_SERVER_FINDER_STATE.AutoJoinMode
            ),

        AutoJoinMinLife =
            tonumber(
                HOLY_SERVER_FINDER_STATE.AutoJoinMinLife
            )
            or 30,

        AutoJoinCooldown =
            tonumber(
                HOLY_SERVER_FINDER_STATE.AutoJoinCooldown
            )
            or 10,

        AutoJoinHoldLoadGrace =
            tonumber(
                HOLY_SERVER_FINDER_STATE.AutoJoinHoldLoadGrace
            )
            or 22,

        AutoJoinHold =
            HolyServerFinderNormalizeAutoJoinHold(
                HOLY_SERVER_FINDER_STATE.AutoJoinHold
            ),

        AutoJoinSelectedRuleIndex =
            tonumber(
                HOLY_SERVER_FINDER_STATE.AutoJoinSelectedRuleIndex
            )
            or 1,

        AutoJoinRules =
            HolyServerFinderNormalizeAutoJoinRules(
                HOLY_SERVER_FINDER_STATE.AutoJoinRules
            ),

        Minimized =
            HOLY_SERVER_FINDER_STATE.Minimized == true,

        Position =
            HolyServerFinderReadPosition(
                HOLY_SERVER_FINDER_STATE.Position
            ),

        FilterPosition =
            HolyServerFinderReadPosition(
                HOLY_SERVER_FINDER_STATE.FilterPosition
            ),
    }
end

function HolySaveServerFinderSettings()

    if HolyCanUseFiles() ~= true then
        return false
    end

    HolyEnsureFolder()

    local encodeOk,
        encoded =
        pcall(function()

            return HttpService:JSONEncode(
                HolyServerFinderBuildSavePayload()
            )
        end)

    if encodeOk ~= true
    or type(encoded) ~= "string" then
        return false
    end

    local writeOk =
        pcall(function()

            writefile(
                SERVER_FINDER_SETTINGS_FILE,
                encoded
            )
        end)

    return writeOk == true
end

function HolyQueueSaveServerFinderSettings()

    HOLY_SERVER_FINDER_SAVE_TOKEN =
        (
            tonumber(
                HOLY_SERVER_FINDER_SAVE_TOKEN
            )
            or 0
        )
        + 1

    local token =
        HOLY_SERVER_FINDER_SAVE_TOKEN

    task.delay(0.35, function()

        if HOLY_SERVER_FINDER_SAVE_TOKEN ~= token then
            return
        end

        HolySaveServerFinderSettings()
    end)
end

function HolyLoadServerFinderSettings()

    if HolyCanUseFiles() ~= true then
        return false
    end

    local exists =
        false

    pcall(function()

        exists =
            isfile(
                SERVER_FINDER_SETTINGS_FILE
            )
    end)

    if exists ~= true then
        return false
    end

    local readOk,
        raw =
        pcall(function()

            return readfile(
                SERVER_FINDER_SETTINGS_FILE
            )
        end)

    if readOk ~= true
    or type(raw) ~= "string"
    or raw == "" then
        return false
    end

    local decodeOk,
        data =
        pcall(function()

            return HttpService:JSONDecode(
                raw
            )
        end)

    if decodeOk ~= true
    or type(data) ~= "table" then
        return false
    end

    HOLY_SERVER_FINDER_STATE.Enabled =
        data.Enabled == true

    HOLY_SERVER_FINDER_STATE.AutoRefresh =
        data.AutoRefresh == true

    HOLY_SERVER_FINDER_STATE.RefreshDelay =
        math.clamp(
            tonumber(data.RefreshDelay)
            or 5,
            1,
            60
        )

    HOLY_SERVER_FINDER_STATE.HideFull =
        data.HideFull ~= false

    HOLY_SERVER_FINDER_STATE.HudScale =
        HolyServerFinderReadHudScale(
            data.HudScale
            or data.Scale
            or HOLY_SERVER_FINDER_STATE.HudScale
            or 80
        )

    HOLY_SERVER_FINDER_STATE.SelectedPets =
        HolyServerFinderMapFromArray(
            data.SelectedPets
        )

    HOLY_SERVER_FINDER_STATE.SelectedRarities =
        HolyServerFinderMapFromArray(
            data.SelectedRarities
        )

    HOLY_SERVER_FINDER_STATE.SelectedSizes =
        HolyServerFinderSizeMapFromArray(
            data.SelectedSizes
        )

    HOLY_SERVER_FINDER_STATE.SelectedVariants =
        HolyServerFinderVariantMapFromArray(
            data.SelectedVariants
        )

    if next(HOLY_SERVER_FINDER_STATE.SelectedSizes) == nil
    and next(HOLY_SERVER_FINDER_STATE.SelectedVariants) == nil
    and type(data.SelectedTraits) == "table" then

        HOLY_SERVER_FINDER_STATE.SelectedSizes =
            HolyServerFinderSizeMapFromArray(
                data.SelectedTraits
            )

        HOLY_SERVER_FINDER_STATE.SelectedVariants =
            HolyServerFinderVariantMapFromArray(
                data.SelectedTraits
            )
    end

    HOLY_SERVER_FINDER_STATE.SelectedTraits =
        {}

    HOLY_SERVER_FINDER_STATE.Minimized =
        data.Minimized == true

    HOLY_SERVER_FINDER_STATE.Position =
        HolyServerFinderReadPosition(
            data.Position
        )

    HOLY_SERVER_FINDER_STATE.FilterPosition =
        HolyServerFinderReadPosition(
            data.FilterPosition
        )

    HOLY_SERVER_FINDER_STATE.AutoJoinMode =
        HolyServerFinderNormalizeAutoJoinMode(
            data.AutoJoinMode
            or HOLY_SERVER_FINDER_STATE.AutoJoinMode
            or "Off"
        )

    HOLY_SERVER_FINDER_STATE.AutoJoinMinLife =
        math.clamp(
            tonumber(
                data.AutoJoinMinLife
            )
            or 30,
            0,
            420
        )

    HOLY_SERVER_FINDER_STATE.AutoJoinCooldown =
        math.clamp(
            tonumber(
                data.AutoJoinCooldown
            )
            or 10,
            1,
            120
        )

    HOLY_SERVER_FINDER_STATE.AutoJoinHoldLoadGrace =
        math.clamp(
            tonumber(
                data.AutoJoinHoldLoadGrace
            )
            or 22,
            5,
            90
        )

    HOLY_SERVER_FINDER_STATE.AutoJoinHold =
        HolyServerFinderNormalizeAutoJoinHold(
            data.AutoJoinHold
        )

    HOLY_SERVER_FINDER_STATE.AutoJoinSelectedRuleIndex =
        tonumber(
            data.AutoJoinSelectedRuleIndex
        )
        or 1

    HOLY_SERVER_FINDER_STATE.AutoJoinRules =
        type(data.AutoJoinRules) == "table"
        and data.AutoJoinRules
        or HolyServerFinderGetDefaultAutoJoinRules()

    HolyServerFinderEnsureAutoJoinState()

    HolyServerSniperForceLockedOff(
        "saved Server Sniper settings",
        false
    )

    return true
end

HolyLoadServerFinderSettings()

function HolyServerFinderAddUniqueChoice(list, seen, value)

    value =
        HolyCleanText(
            value
        )

    if value == "" then
        return false
    end

    if value == "Mega" then
        value =
            "Huge"
    end

    if value == "Any" then
        return false
    end

    local key =
        value:lower()

    if seen[key] == true then
        return false
    end

    seen[key] =
        true

    table.insert(
        list,
        value
    )

    return true
end

function HolyServerFinderSortChoices(list)

    table.sort(list, function(a, b)

        return tostring(a):lower()
            < tostring(b):lower()
    end)

    return list
end

function HolyServerFinderBuildFilterOptions()

    local pets =
        {}

    local rarities =
        {}

    local sizes =
        {}

    local variants =
        {}

    local seenPets =
        {}

    local seenRarities =
        {}

    local seenSizes =
        {}

    local seenVariants =
        {}

    for _, petName in ipairs(HolySniperGetPetValues()) do

        HolyServerFinderAddUniqueChoice(
            pets,
            seenPets,
            petName
        )
    end

    local petData =
        HolySniperGetPetData()

    for key, row in pairs(petData) do

        if HolySniperIsPetDataRow(
            key,
            row
        ) == true then

            HolyServerFinderAddUniqueChoice(
                rarities,
                seenRarities,
                row.Rarity
            )
        end
    end

    for _, sizeName in ipairs({
        "Normal",
        "Big",
        "Huge",
    }) do

        HolyServerFinderAddUniqueChoice(
            sizes,
            seenSizes,
            sizeName
        )
    end

    for _, variantName in ipairs({
        "Regular",
        "Rainbow",
    }) do

        HolyServerFinderAddUniqueChoice(
            variants,
            seenVariants,
            variantName
        )
    end

    return {
        Pets =
            HolyServerFinderSortChoices(
                pets
            ),

        Rarities =
            HolyServerFinderSortChoices(
                rarities
            ),

        Sizes =
            sizes,

        Variants =
            variants,
    }
end

function HolyServerFinderApplyFilterOptions(hud)

    if type(hud) ~= "table"
    or type(hud.SetFilterOptions) ~= "function" then
        return false
    end

    hud:SetFilterOptions(
        HolyServerFinderBuildFilterOptions()
    )

    return true
end

function HolyServerFinderGetPlayerCounts()

    local playing =
        #Players:GetPlayers()

    local maxPlayers =
        8

    pcall(function()

        maxPlayers =
            tonumber(
                Players.MaxPlayers
            )
            or maxPlayers
    end)

    if maxPlayers <= 0 then
        maxPlayers =
            8
    end

    return playing,
        maxPlayers
end

function HolyServerFinderBuildRowName(row)

    row =
        type(row) == "table"
        and row
        or {}

    local displayName =
        HolyCleanText(
            row.DisplayName
        )

    if displayName ~= "" then
        return displayName
    end

    local parts =
        {}

    local size =
        HolyCleanText(
            row.Size
        )

    local variant =
        HolyCleanText(
            row.Variant
        )

    local pet =
        HolyCleanText(
            row.Pet
        )

    if size ~= ""
    and size ~= "Any"
    and size ~= "Normal"
    and size ~= "Regular" then

        table.insert(
            parts,
            size
        )
    end

    if variant ~= ""
    and variant ~= "Any"
    and variant ~= "Normal"
    and variant ~= "Regular" then

        table.insert(
            parts,
            variant
        )
    end

    if pet ~= "" then

        table.insert(
            parts,
            pet
        )
    end

    if #parts <= 0 then
        return "Unknown Pet"
    end

    return table.concat(
        parts,
        " "
    )
end

function HolyServerFinderRarityRank(rarity)

    rarity =
        HolyCleanText(
            rarity
        )

    local ranks = {
        Secret = 8,
        Super = 7,
        Mythic = 6,
        Legendary = 5,
        Epic = 4,
        Rare = 3,
        Uncommon = 2,
        Common = 1,
    }

    return ranks[rarity]
        or 0
end

function HolyServerFinderBuildLocalPetRow(row)

    row =
        type(row) == "table"
        and row
        or {}

    local state =
        tostring(
            row.State
            or ""
        )
        :lower()

    if state == "sent"
    or state == "bought"
    or state == "gone" then

        return nil
    end

    local timeLeft =
        tonumber(
            row.TimeLeftNumber
            or row.TimeLeft
        )
        or 0

    local lifetime =
        tonumber(
            row.Lifetime
        )
        or 0

    if lifetime > 0
    and timeLeft <= 0 then

        return nil
    end

    local petName =
        HolyCleanText(
            row.Pet
            or row.PetName
        )

    if petName == "" then

        petName =
            HolyServerFinderBuildRowName(
                row
            )
    end

    if petName == "" then
        return nil
    end

    local now =
        os.time()

    local spawnedAt =
        tonumber(
            row.SpawnedAt
        )
        or 0

    local expiresAt =
        0

    if spawnedAt > 0
    and lifetime > 0 then

        expiresAt =
            spawnedAt
            + lifetime

    elseif timeLeft > 0 then

        expiresAt =
            now
            + timeLeft
    end

    local displayName =
        HolyServerFinderBuildRowName(
            row
        )

    local rarity =
        HolyCleanText(
            row.Rarity
        )

    local size =
        HolyCleanText(
            row.Size
        )

    local variant =
        HolyCleanText(
            row.Variant
        )

    return {
        Key =
            tostring(row.Key or row.UUID or petName),

        UUID =
            tostring(row.UUID or row.Key or ""),

        DisplayName =
            displayName,

        Pet =
            petName,

        PetName =
            petName,

        Rarity =
            rarity,

        RarityRank =
            HolyServerFinderRarityRank(
                rarity
            ),

        Size =
            size,

        Variant =
            variant,

        Mutation =
            variant,

        SpawnedAt =
            spawnedAt,

        Lifetime =
            lifetime,

        ExpiresAt =
            expiresAt,

        TimeLeft =
            math.max(
                0,
                expiresAt > 0
                and expiresAt - now
                or timeLeft
            ),

        Price =
            row.PriceNumber
            or row.Price
            or 0,

        PriceNumber =
            tonumber(
                row.PriceNumber
                or row.Price
            )
            or 0,
    }
end

function HolyServerFinderAddUniqueText(list, seen, value)

    value =
        HolyCleanText(
            value
        )

    if value == ""
    or value == "Any"
    or value == "Regular" then

        return false
    end

    local key =
        value:lower()

    if seen[key] == true then
        return false
    end

    seen[key] =
        true

    table.insert(
        list,
        value
    )

    return true
end

function HolyServerFinderBuildPetSummary(pets, maxShown)

    pets =
        type(pets) == "table"
        and pets
        or {}

    maxShown =
        math.max(
            1,
            tonumber(maxShown)
            or 3
        )

    local order =
        {}

    local counts =
        {}

    local seen =
        {}

    for _, pet in ipairs(pets) do

        local name =
            HolyCleanText(
                pet.DisplayName
                or pet.Pet
                or pet.PetName
            )

        if name ~= "" then

            local key =
                name:lower()

            if seen[key] ~= true then

                seen[key] =
                    true

                table.insert(
                    order,
                    name
                )

                counts[key] =
                    0
            end

            counts[key] =
                (
                    tonumber(
                        counts[key]
                    )
                    or 0
                )
                + 1
        end
    end

    if #order <= 0 then
        return "Unknown Server"
    end

    local shown =
        {}

    for index, name in ipairs(order) do

        if index > maxShown then
            break
        end

        local count =
            tonumber(
                counts[name:lower()]
            )
            or 1

        if count > 1 then

            table.insert(
                shown,
                name
                .. " x"
                .. tostring(count)
            )

        else

            table.insert(
                shown,
                name
            )
        end
    end

    local text =
        table.concat(
            shown,
            ", "
        )

    local extra =
        #order - maxShown

    if extra > 0 then

        text =
            text
            .. " +"
            .. tostring(extra)
    end

    return text
end

function HolyServerFinderBuildUniquePetField(pets, fieldName)

    local output =
        {}

    local seen =
        {}

    for _, pet in ipairs(pets or {}) do

        HolyServerFinderAddUniqueText(
            output,
            seen,
            pet[fieldName]
        )
    end

    return table.concat(
        output,
        " "
    )
end

function HolyServerFinderBuildPetSearchBlob(pets)

    local parts =
        {}

    for _, pet in ipairs(pets or {}) do

        for _, value in ipairs({
            pet.DisplayName,
            pet.Pet,
            pet.PetName,
            pet.Rarity,
            pet.Size,
            pet.Variant,
            pet.Mutation,
        }) do

            value =
                HolyCleanText(
                    value
                )

            if value ~= "" then

                table.insert(
                    parts,
                    value
                )
            end
        end
    end

    return table.concat(
        parts,
        " "
    )
end

function HolyServerFinderBuildLocalRows()

    local liveRows =
        {}

    local ok,
        result =
        pcall(function()

            return HolyLivePetsScanRows()
        end)

    if ok == true
    and type(result) == "table" then

        liveRows =
            result
    end

    local pets =
        {}

    for _, row in ipairs(liveRows) do

        local pet =
            HolyServerFinderBuildLocalPetRow(
                row
            )

        if pet then

            table.insert(
                pets,
                pet
            )
        end
    end

    if #pets <= 0 then
        return {}
    end

    table.sort(pets, function(a, b)

        local rarityA =
            tonumber(a.RarityRank)
            or 0

        local rarityB =
            tonumber(b.RarityRank)
            or 0

        if rarityA ~= rarityB then
            return rarityA > rarityB
        end

        local priceA =
            tonumber(a.PriceNumber)
            or 0

        local priceB =
            tonumber(b.PriceNumber)
            or 0

        if priceA ~= priceB then
            return priceA > priceB
        end

        local timeA =
            tonumber(a.TimeLeft)
            or 0

        local timeB =
            tonumber(b.TimeLeft)
            or 0

        if timeA ~= timeB then
            return timeA < timeB
        end

        return tostring(a.DisplayName or "")
            < tostring(b.DisplayName or "")
    end)

    local playing,
        maxPlayers =
        HolyServerFinderGetPlayerCounts()

    local now =
        os.time()

    local minExpiresAt =
        nil

    local maxExpiresAt =
        nil

    for _, pet in ipairs(pets) do

        local expiresAt =
            tonumber(
                pet.ExpiresAt
            )
            or 0

        if expiresAt > now then

            if minExpiresAt == nil
            or expiresAt < minExpiresAt then

                minExpiresAt =
                    expiresAt
            end

            if maxExpiresAt == nil
            or expiresAt > maxExpiresAt then

                maxExpiresAt =
                    expiresAt
            end
        end
    end

    minExpiresAt =
        minExpiresAt
        or 0

    maxExpiresAt =
        maxExpiresAt
        or 0

    local bestPet =
        pets[1]
        or {}

    local serverKey =
        tostring(game.JobId)
        .. "|local-server"

    local displayName =
        HolyServerFinderBuildPetSummary(
            pets,
            3
        )

    local searchBlob =
        HolyServerFinderBuildPetSearchBlob(
            pets
        )

    return {
        {
            Key =
                serverKey,

            Id =
                serverKey,

            PlaceId =
                game.PlaceId,

            JobId =
                tostring(game.JobId),

            DisplayName =
                displayName,

            Name =
                searchBlob,

            Pet =
                displayName,

            PetName =
                displayName,

            BestPet =
                bestPet.Pet
                or bestPet.PetName
                or "",

            BestDisplayName =
                bestPet.DisplayName
                or bestPet.Pet
                or "",

            Rarity =
                bestPet.Rarity
                or "",

            Size =
                HolyServerFinderBuildUniquePetField(
                    pets,
                    "Size"
                ),

            Variant =
                HolyServerFinderBuildUniquePetField(
                    pets,
                    "Variant"
                ),

            Mutation =
                HolyServerFinderBuildUniquePetField(
                    pets,
                    "Mutation"
                ),

            Playing =
                playing,

            MaxPlayers =
                maxPlayers,

            ReportedAt =
                now,

            ExpiresAt =
                maxExpiresAt,

            MinExpiresAt =
                minExpiresAt,

            MaxExpiresAt =
                maxExpiresAt,

            TimeLeft =
                math.max(
                    0,
                    maxExpiresAt > 0
                    and maxExpiresAt - now
                    or 0
                ),

            PetCount =
                #pets,

            Pets =
                pets,

            Source =
                "Local",

            IsCurrentServer =
                true,
        },
    }
end

function HolyServerFinderBackendUrl(path)

    path =
        HolyCleanText(
            path
        )

    if path == "" then
        path =
            "/"
    end

    if path:sub(1, 1) ~= "/" then
        path =
            "/"
            .. path
    end

    return tostring(SERVER_FINDER_API_BASE or "")
        :gsub("/+$", "")
        .. path
end

function HolyServerFinderRequestJson(method, url, payload)

    local requestFunction =
        HolyGetRequestFunction()

    if type(requestFunction) ~= "function" then
        return nil,
            "request unsupported"
    end

    method =
        tostring(method or "GET")
            :upper()

    url =
        HolyCleanText(
            url
        )

    if url == "" then
        return nil,
            "missing url"
    end

    local requestOptions = {
        Url =
            url,

        Method =
            method,

        Headers = {
            ["Accept"] =
                "application/json",

            ["Content-Type"] =
                "application/json",

            ["x-api-key"] =
                tostring(SERVER_FINDER_API_KEY or ""),
        },
    }

    if payload ~= nil then

        local encodeOk,
            encoded =
            pcall(function()

                return HttpService:JSONEncode(
                    payload
                )
            end)

        if encodeOk ~= true
        or type(encoded) ~= "string" then

            return nil,
                "encode failed"
        end

        requestOptions.Body =
            encoded
    end

    local requestOk,
        response =
        pcall(function()

            return requestFunction(
                requestOptions
            )
        end)

    if requestOk ~= true then

        return nil,
            "request failed: "
            .. tostring(response)
    end

    local status =
        0

    local body =
        ""

    if type(response) == "table" then

        status =
            tonumber(
                response.StatusCode
                or response.Status
                or response.statusCode
                or response.status
            )
            or 0

        body =
            response.Body
            or response.body
            or response.ResponseBody
            or response.responseBody
            or ""

    elseif type(response) == "string" then

        body =
            response
    end

    if status > 0
    and (
        status < 200
        or status >= 300
    ) then

        return nil,
            "http "
            .. tostring(status)
            .. ": "
            .. tostring(body):sub(1, 180)
    end

    local decodeOk,
        data =
        pcall(function()

            return HttpService:JSONDecode(
                tostring(body or "")
            )
        end)

    if decodeOk ~= true
    or type(data) ~= "table" then

        return nil,
            "decode failed: "
            .. tostring(body):sub(1, 180)
    end

    if data.ok == false then

        return nil,
            tostring(data.error or "backend error")
    end

    return data,
        "ok"
end

function HolyServerFinderReadServerVersion()

    local roots = {
        workspace,
        ReplicatedStorage,
        game,
    }

    local names = {
        "ServerVersion",
        "Version",
        "GameVersion",
        "BuildVersion",
    }

    for _, root in ipairs(roots) do

        if typeof(root) == "Instance" then

            for _, name in ipairs(names) do

                local ok,
                    value =
                    pcall(function()

                        return root:GetAttribute(
                            name
                        )
                    end)

                value =
                    HolyCleanText(
                        ok == true
                        and value
                        or ""
                    )

                if value ~= "" then
                    return value
                end
            end
        end
    end

    return ""
end

function HolyServerFinderBuildReportPayload()

    local liveRows =
        {}

    local scanOk,
        scanResult =
        pcall(function()

            return HolyLivePetsScanRows()
        end)

    if scanOk == true
    and type(scanResult) == "table" then

        liveRows =
            scanResult
    end

    local pets =
        {}

    for _, row in ipairs(liveRows) do

        local pet =
            HolyServerFinderBuildLocalPetRow(
                row
            )

        if pet then

            table.insert(
                pets,
                {
                    Key =
                        pet.Key,

                    UUID =
                        pet.UUID,

                    Pet =
                        pet.Pet,

                    PetName =
                        pet.PetName,

                    Rarity =
                        pet.Rarity,

                    Size =
                        pet.Size,

                    Variant =
                        pet.Variant,

                    Mutation =
                        pet.Mutation,

                    SpawnedAt =
                        tonumber(pet.SpawnedAt)
                        or 0,

                    Lifetime =
                        tonumber(pet.Lifetime)
                        or 0,

                    ExpiresAt =
                        tonumber(pet.ExpiresAt)
                        or 0,

                    Price =
                        tonumber(pet.PriceNumber)
                        or 0,
                }
            )
        end
    end

    local playing,
        maxPlayers =
        HolyServerFinderGetPlayerCounts()

    return {
        Key =
            tostring(SERVER_FINDER_API_KEY or ""),

        PlaceId =
            game.PlaceId,

        JobId =
            tostring(game.JobId),

        Playing =
            playing,

        MaxPlayers =
            maxPlayers,

        ServerVersion =
            HolyServerFinderReadServerVersion(),

        Reporter =
            tostring(
                LocalPlayer
                and LocalPlayer.Name
                or "unknown"
            ),

        Pets =
            pets,
    }
end

function HolyRareAlertAlias(value)

    if type(HolySniperPetAliasKey) == "function" then

        return HolySniperPetAliasKey(
            value
        )
    end

    return HolyCleanText(
        value
    )
        :lower()
        :gsub("[%s_%-%[%]%(%)%.]", "")
end

function HolyRareAlertNormalizeSize(value)

    if type(HolySniperNormalizeSizeName) == "function" then

        return HolySniperNormalizeSizeName(
            value
        )
    end

    local text =
        HolyCleanText(
            value
        )

    if text == "" then
        return "Normal"
    end

    if text == "Mega" then
        return "Huge"
    end

    return text
end

function HolyRareAlertNormalizeVariant(value)

    if type(HolySniperNormalizeVariantName) == "function" then

        local normalized =
            HolySniperNormalizeVariantName(
                value
            )

        if normalized == "Regular" then
            return "Normal"
        end

        return normalized
    end

    local text =
        HolyCleanText(
            value
        )

    if text == ""
    or text == "Regular" then

        return "Normal"
    end

    return text
end

function HolyRareAlertIsSpecificPet(row)

    row =
        type(row) == "table"
        and row
        or {}

    local key =
        HolyRareAlertAlias(
            row.Pet
            or row.PetName
            or row.DisplayName
        )

    return key == "raccoon"
        or key == "unicorn"
        or key == "goldendragonfly"
        or key == "dragonfly"
end

function HolyRareAlertIsVariantPet(row)

    row =
        type(row) == "table"
        and row
        or {}

    local size =
        HolyRareAlertNormalizeSize(
            row.Size
        )

    local variant =
        HolyRareAlertNormalizeVariant(
            row.Variant
            or row.Mutation
        )

    if size == "Big"
    or size == "Huge" then

        return true
    end

    if variant ~= ""
    and variant ~= "Normal"
    and variant ~= "Regular"
    and variant ~= "Any" then

        return true
    end

    return false
end

function HolyRareAlertShouldReportRow(row)

    if type(row) ~= "table" then
        return false
    end

    local state =
        tostring(
            row.State
            or ""
        )
        :lower()

    if state == "sent"
    or state == "bought"
    or state == "gone" then

        return false
    end

    local lifetime =
        tonumber(
            row.Lifetime
        )
        or 0

    local timeLeft =
        tonumber(
            row.TimeLeftNumber
            or row.TimeLeft
        )
        or 0

    if lifetime > 0
    and timeLeft <= 0 then

        return false
    end

    if HolyRareAlertIsSpecificPet(row) == true then
        return true
    end

    if HolyRareAlertIsVariantPet(row) == true then
        return true
    end

    return false
end

function HolyRareAlertRowExpiresAt(row)

    row =
        type(row) == "table"
        and row
        or {}

    local spawnedAt =
        tonumber(
            row.SpawnedAt
        )
        or 0

    local lifetime =
        tonumber(
            row.Lifetime
        )
        or 0

    if spawnedAt > 0
    and lifetime > 0 then

        return spawnedAt + lifetime
    end

    local timeLeft =
        tonumber(
            row.TimeLeftNumber
            or row.TimeLeft
        )
        or 0

    if timeLeft > 0 then

        return os.time() + timeLeft
    end

    return os.time() + 300
end

function HolyRareAlertRowKey(row)

    row =
        type(row) == "table"
        and row
        or {}

    local key =
        HolyCleanText(
            row.UUID
            or row.Key
            or ""
        )

    if key == "" then

        key =
            table.concat({
                HolyRareAlertAlias(
                    row.Pet
                    or row.PetName
                    or row.DisplayName
                ),

                HolyRareAlertNormalizeSize(
                    row.Size
                ),

                HolyRareAlertNormalizeVariant(
                    row.Variant
                    or row.Mutation
                ),

                tostring(
                    tonumber(row.SpawnedAt)
                    or 0
                ),
            }, "_")
    end

    return table.concat({
        tostring(game.PlaceId),
        tostring(game.JobId),
        key,
    }, "|")
end

function HolyRareAlertPruneSent()

    HOLY_RARE_ALERT_STATE =
        type(HOLY_RARE_ALERT_STATE) == "table"
        and HOLY_RARE_ALERT_STATE
        or {}

    HOLY_RARE_ALERT_STATE.Sent =
        type(HOLY_RARE_ALERT_STATE.Sent) == "table"
        and HOLY_RARE_ALERT_STATE.Sent
        or {}

    local now =
        os.time()

    for key, expiresAt in pairs(HOLY_RARE_ALERT_STATE.Sent) do

        if tonumber(expiresAt) == nil
        or tonumber(expiresAt) <= now then

            HOLY_RARE_ALERT_STATE.Sent[key] =
                nil
        end
    end
end

function HolyRareAlertBuildPetPayload(row)

    row =
        type(row) == "table"
        and row
        or {}

    local expiresAt =
        HolyRareAlertRowExpiresAt(
            row
        )

    local timeLeft =
        math.max(
            0,
            expiresAt - os.time()
        )

    return {
        Key =
            HolyCleanText(
                row.Key
                or row.UUID
                or ""
            ),

        UUID =
            HolyCleanText(
                row.UUID
                or row.Key
                or ""
            ),

        Pet =
            HolyCleanText(
                row.Pet
                or row.PetName
                or ""
            ),

        PetName =
            HolyCleanText(
                row.Pet
                or row.PetName
                or ""
            ),

        DisplayName =
            HolyCleanText(
                row.DisplayName
                or ""
            ),

        Rarity =
            HolyCleanText(
                row.Rarity
                or ""
            ),

        Size =
            HolyRareAlertNormalizeSize(
                row.Size
            ),

        Variant =
            HolyRareAlertNormalizeVariant(
                row.Variant
                or row.Mutation
            ),

        Mutation =
            HolyRareAlertNormalizeVariant(
                row.Variant
                or row.Mutation
            ),

        SpawnedAt =
            tonumber(row.SpawnedAt)
            or 0,

        Lifetime =
            tonumber(row.Lifetime)
            or 0,

        ExpiresAt =
            expiresAt,

        TimeLeft =
            timeLeft,

        Price =
            tonumber(
                row.PriceNumber
                or row.Price
            )
            or 0,
    }
end

function HolyRareAlertBuildPayload()

    HolyRareAlertPruneSent()

    local rows =
        {}

    local ok,
        result =
        pcall(function()

            return HolyLivePetsScanRows()
        end)

    if ok == true
    and type(result) == "table" then

        rows =
            result
    end

    local pets =
        {}

    local sentKeys =
        {}

    for _, row in ipairs(rows) do

        if HolyRareAlertShouldReportRow(row) == true then

            local rowKey =
                HolyRareAlertRowKey(
                    row
                )

            if HOLY_RARE_ALERT_STATE.Sent[rowKey] ~= true
            and HOLY_RARE_ALERT_STATE.Sent[rowKey] == nil then

                table.insert(
                    pets,
                    HolyRareAlertBuildPetPayload(
                        row
                    )
                )

                table.insert(
                    sentKeys,
                    {
                        Key =
                            rowKey,

                        ExpiresAt =
                            HolyRareAlertRowExpiresAt(
                                row
                            ),
                    }
                )
            end
        end
    end

    if #pets <= 0 then
        return nil,
            sentKeys
    end

    local playing,
        maxPlayers =
        0,
        8

    if type(HolyServerFinderGetPlayerCounts) == "function" then

        playing,
            maxPlayers =
            HolyServerFinderGetPlayerCounts()

    else

        playing =
            #Players:GetPlayers()

        maxPlayers =
            tonumber(Players.MaxPlayers)
            or 8
    end

    return {
        Key =
            tostring(
                SERVER_FINDER_API_KEY
                or ""
            ),

        PlaceId =
            game.PlaceId,

        JobId =
            tostring(
                game.JobId
            ),

        Playing =
            playing,

        MaxPlayers =
            maxPlayers,

        ServerVersion =
            type(HolyServerFinderReadServerVersion) == "function"
            and HolyServerFinderReadServerVersion()
            or "",

        Reporter =
            tostring(
                LocalPlayer
                and LocalPlayer.Name
                or "unknown"
            ),

        Pets =
            pets,
    },
        sentKeys
end

function HolyRareAlertSendPayload(payload, sentKeys)

    if type(payload) ~= "table" then
        return false,
            "empty"
    end

    if type(HolyServerFinderRequestJson) ~= "function"
    or type(HolyServerFinderBackendUrl) ~= "function" then

        return false,
            "request helper missing"
    end

    local data,
        reason =
        HolyServerFinderRequestJson(
            "POST",
            HolyServerFinderBackendUrl(
                "/rare-alert"
            ),
            payload
        )

    if type(data) == "table"
    and data.ok == true then

        HOLY_RARE_ALERT_STATE.LastReportAt =
            os.time()

        HOLY_RARE_ALERT_STATE.LastStatus =
            "Reported "
            .. tostring(
                #(
                    payload.Pets
                    or {}
                )
            )
            .. " pet(s)"

        for _, row in ipairs(sentKeys or {}) do

            local key =
                HolyCleanText(
                    row.Key
                )

            if key ~= "" then

                HOLY_RARE_ALERT_STATE.Sent[key] =
                    tonumber(row.ExpiresAt)
                    or (
                        os.time() + 300
                    )
            end
        end

        return true,
            "ok"
    end

    HOLY_RARE_ALERT_STATE.LastError =
        tostring(reason or "request failed")

    return false,
        HOLY_RARE_ALERT_STATE.LastError
end

function HolyRareAlertTick()

    HOLY_RARE_ALERT_STATE.LastScanAt =
        os.time()

    local payload,
        sentKeys =
        HolyRareAlertBuildPayload()

    if type(payload) ~= "table" then
        return false
    end

    return HolyRareAlertSendPayload(
        payload,
        sentKeys
    )
end

function HolyRareAlertStart(reason)

    HOLY_RARE_ALERT_STATE =
        type(HOLY_RARE_ALERT_STATE) == "table"
        and HOLY_RARE_ALERT_STATE
        or {}

    if HOLY_RARE_ALERT_STATE.Running == true then
        return false
    end

    HOLY_RARE_ALERT_STATE.Running =
        true

    HOLY_RARE_ALERT_STATE.Sent =
        type(HOLY_RARE_ALERT_STATE.Sent) == "table"
        and HOLY_RARE_ALERT_STATE.Sent
        or {}

    local token =
        {}

    HOLY_RARE_ALERT_STATE.Token =
        token

    task.spawn(function()

        task.wait(
            1.25
        )

        while HOLY_RARE_ALERT_STATE.Token == token do

            pcall(function()

                HolyRareAlertTick()
            end)

            task.wait(
                tonumber(
                    HOLY_RARE_ALERT_STATE.ScanInterval
                )
                or 0.85
            )
        end

        if HOLY_RARE_ALERT_STATE.Token == token then

            HOLY_RARE_ALERT_STATE.Running =
                false
        end
    end)

    return true
end

function HolyRareAlertStop(reason)

    HOLY_RARE_ALERT_STATE =
        type(HOLY_RARE_ALERT_STATE) == "table"
        and HOLY_RARE_ALERT_STATE
        or {}

    HOLY_RARE_ALERT_STATE.Token =
        nil

    HOLY_RARE_ALERT_STATE.Running =
        false

    return true
end

function HolyServerFinderReportNow(reason)

    HOLY_SERVER_FINDER_REPORTER =
        type(HOLY_SERVER_FINDER_REPORTER) == "table"
        and HOLY_SERVER_FINDER_REPORTER
        or {}

    local payload =
        HolyServerFinderBuildReportPayload()

    local data,
        requestReason =
        HolyServerFinderRequestJson(
            "POST",
            HolyServerFinderBackendUrl(
                "/report"
            ),
            payload
        )

    HOLY_SERVER_FINDER_REPORTER.LastReportAt =
        os.time()

    if type(data) == "table"
    and data.ok == true then

        HOLY_SERVER_FINDER_REPORTER.LastReportStatus =
            data.deleted == true
            and "Deleted empty server"
            or (
                "Reported "
                .. tostring(data.petCount or 0)
                .. " pet(s)"
            )

        return true,
            HOLY_SERVER_FINDER_REPORTER.LastReportStatus
    end

    HOLY_SERVER_FINDER_REPORTER.LastReportStatus =
        tostring(requestReason or "report failed")

    return false,
        HOLY_SERVER_FINDER_REPORTER.LastReportStatus
end

function HolyServerFinderReportForRefresh(reason)

    HOLY_SERVER_FINDER_REPORTER =
        type(HOLY_SERVER_FINDER_REPORTER) == "table"
        and HOLY_SERVER_FINDER_REPORTER
        or {}

    if type(HolyGetRequestFunction()) ~= "function" then

        HOLY_SERVER_FINDER_REPORTER.LastReportStatus =
            "request unsupported"

        return false,
            "request unsupported"
    end

    if HOLY_SERVER_FINDER_REPORTER.RefreshReportRunning == true then

        return false,
            "report already running"
    end

    local nowClock =
        os.clock()

    if nowClock - (
        tonumber(
            HOLY_SERVER_FINDER_REPORTER.LastRefreshReportClock
        )
        or 0
    ) < 0.85 then

        return false,
            "refresh report cooldown"
    end

    HOLY_SERVER_FINDER_REPORTER.RefreshReportRunning =
        true

    HOLY_SERVER_FINDER_REPORTER.LastRefreshReportClock =
        nowClock

    local ok,
        success,
        status =
        pcall(function()

            return HolyServerFinderReportNow(
                reason or "refresh"
            )
        end)

    HOLY_SERVER_FINDER_REPORTER.RefreshReportRunning =
        false

    if ok == true then

        return success == true,
            tostring(status or HOLY_SERVER_FINDER_REPORTER.LastReportStatus or "reported")
    end

    HOLY_SERVER_FINDER_REPORTER.LastReportStatus =
        tostring(success or "report failed")

    return false,
        HOLY_SERVER_FINDER_REPORTER.LastReportStatus
end

function HolyServerFinderStartReporter()

    HOLY_SERVER_FINDER_REPORTER =
        type(HOLY_SERVER_FINDER_REPORTER) == "table"
        and HOLY_SERVER_FINDER_REPORTER
        or {}

    if HOLY_SERVER_FINDER_REPORTER.Running == true then
        return false
    end

    if type(HolyGetRequestFunction()) ~= "function" then

        HOLY_SERVER_FINDER_REPORTER.LastReportStatus =
            "request unsupported"

        return false
    end

    local token =
        {}

    HOLY_SERVER_FINDER_REPORTER.Token =
        token

    HOLY_SERVER_FINDER_REPORTER.Running =
        true

    task.spawn(function()

        while HOLY_SERVER_FINDER_REPORTER.Token == token do

            local interval =
                math.max(
                    3,
                    tonumber(SERVER_FINDER_REPORT_INTERVAL)
                    or 5
                )

            pcall(function()

                local lastReportAt =
                    tonumber(
                        HOLY_SERVER_FINDER_REPORTER.LastReportAt
                    )
                    or 0

                if os.time() - lastReportAt >= interval then

                    HolyServerFinderReportNow(
                        "loop"
                    )
                end
            end)

            task.wait(
                interval
            )
        end

        if HOLY_SERVER_FINDER_REPORTER.Token == token then

            HOLY_SERVER_FINDER_REPORTER.Running =
                false
        end
    end)

    return true
end

function HolyServerFinderNormalizeBackendPet(row)

    if type(row) ~= "table" then
        return nil
    end

    local petName =
        HolyCleanText(
            row.Pet
            or row.PetName
            or row.Name
        )

    if petName == "" then
        return nil
    end

    local size =
        HolySniperNormalizeSizeName(
            row.Size
            or row.size
            or "Normal"
        )

    local variant =
        HolySniperNormalizeVariantName(
            row.Variant
            or row.variant
            or row.Mutation
            or row.mutation
            or "Normal"
        )

    local spawnedAt =
        tonumber(
            row.SpawnedAt
            or row.spawnedAt
        )
        or 0

    local lifetime =
        tonumber(
            row.Lifetime
            or row.lifetime
        )
        or 0

    local expiresAt =
        tonumber(
            row.ExpiresAt
            or row.expiresAt
        )
        or 0

    if expiresAt <= 0
    and spawnedAt > 0
    and lifetime > 0 then

        expiresAt =
            spawnedAt
            + lifetime
    end

    local displayName =
        HolyLivePetsBuildDisplayName(
            petName,
            size,
            variant
        )

    return {
        Key =
            HolyCleanText(
                row.Key
                or row.UUID
                or row.Id
                or displayName
            ),

        UUID =
            HolyCleanText(
                row.UUID
                or row.Key
                or ""
            ),

        DisplayName =
            displayName,

        Pet =
            petName,

        PetName =
            petName,

        Rarity =
            HolyCleanText(
                row.Rarity
                or row.rarity
            ),

        RarityRank =
            HolyServerFinderRarityRank(
                row.Rarity
                or row.rarity
            ),

        Size =
            size,

        Variant =
            variant,

        Mutation =
            variant,

        SpawnedAt =
            spawnedAt,

        Lifetime =
            lifetime,

        ExpiresAt =
            expiresAt,

        TimeLeft =
            math.max(
                0,
                expiresAt - os.time()
            ),

        Price =
            row.Price
            or row.price
            or 0,

        PriceNumber =
            tonumber(
                row.Price
                or row.price
            )
            or 0,
    }
end

function HolyServerFinderNormalizeBackendRow(row)

    if type(row) ~= "table" then
        return nil
    end

    local jobId =
        HolyCleanText(
            row.JobId
            or row.jobId
            or row.ServerId
            or row.id
            or row.Id
        )

    if jobId == "" then
        return nil
    end

    local pets =
        {}

    if type(row.Pets) == "table" then

        for _, petRow in ipairs(row.Pets) do

            local pet =
                HolyServerFinderNormalizeBackendPet(
                    petRow
                )

            if pet then

                table.insert(
                    pets,
                    pet
                )
            end
        end
    end

    table.sort(pets, function(a, b)

        if a.RarityRank ~= b.RarityRank then
            return a.RarityRank > b.RarityRank
        end

        if a.PriceNumber ~= b.PriceNumber then
            return a.PriceNumber > b.PriceNumber
        end

        return tostring(a.DisplayName)
            < tostring(b.DisplayName)
    end)

    local now =
        os.time()

    local maxExpiresAt =
        tonumber(
            row.ExpiresAt
            or row.expiresAt
        )
        or 0

    if maxExpiresAt <= 0 then

        for _, pet in ipairs(pets) do

            maxExpiresAt =
                math.max(
                    maxExpiresAt,
                    tonumber(pet.ExpiresAt)
                    or 0
                )
        end
    end

    local bestPet =
        pets[1]
        or {}

    local displayName =
        HolyCleanText(
            row.DisplayName
            or row.displayName
        )

    if displayName == "" then

        displayName =
            HolyServerFinderBuildPetSummary(
                pets,
                3
            )
    end

    return {
        Key =
            jobId,

        Id =
            jobId,

        PlaceId =
            tonumber(
                row.PlaceId
                or row.placeId
            )
            or game.PlaceId,

        JobId =
            jobId,

        DisplayName =
            displayName,

        Name =
            HolyServerFinderBuildPetSearchBlob(
                pets
            ),

        Pet =
            displayName,

        PetName =
            displayName,

        BestPet =
            HolyCleanText(
                row.BestPet
                or row.bestPet
                or bestPet.Pet
                or bestPet.PetName
            ),

        BestDisplayName =
            bestPet.DisplayName
            or bestPet.Pet
            or "",

        Rarity =
            HolyCleanText(
                row.Rarity
                or row.rarity
                or bestPet.Rarity
            ),

        Size =
            HolyServerFinderBuildUniquePetField(
                pets,
                "Size"
            ),

        Variant =
            HolyServerFinderBuildUniquePetField(
                pets,
                "Variant"
            ),

        Mutation =
            HolyServerFinderBuildUniquePetField(
                pets,
                "Mutation"
            ),

        Playing =
            tonumber(
                row.Playing
                or row.playing
            )
            or 0,

        MaxPlayers =
            tonumber(
                row.MaxPlayers
                or row.maxPlayers
            )
            or 8,

        ServerVersion =
            HolyCleanText(
                row.ServerVersion
                or row.serverVersion
            ),

        ReportedAt =
            tonumber(
                row.ReportedAt
                or row.reportedAt
            )
            or now,

        ExpiresAt =
            maxExpiresAt,

        TimeLeft =
            math.max(
                0,
                maxExpiresAt - now
            ),

        PetCount =
            tonumber(
                row.PetCount
                or row.petCount
            )
            or #pets,

        Pets =
            pets,

        Source =
            "Cloudflare",

        IsCurrentServer =
            jobId == tostring(game.JobId),
    }
end

function HolyServerFinderFetchBackendRows()

    if HolyAuthRequireServerSniper(
        "Server Finder Backend",
        false
    ) ~= true then

        return nil,
            "server sniper slot required"
    end

    if type(HolyGetRequestFunction()) ~= "function" then
        return nil,
            "request unsupported"
    end

    local hideFullValue =
        HOLY_SERVER_FINDER_STATE.HideFull ~= false
        and "1"
        or "0"

    local url =
        HolyServerFinderBackendUrl(
            "/servers"
        )
        .. "?placeId="
        .. tostring(game.PlaceId)
        .. "&limit=100"
        .. "&maxAge=45"
        .. "&hideFull="
        .. hideFullValue

    local data,
        requestReason =
        HolyServerFinderRequestJson(
            "GET",
            url,
            nil
        )

    HOLY_SERVER_FINDER_REPORTER.LastFetchAt =
        os.time()

    if type(data) ~= "table"
    or data.ok ~= true then

        HOLY_SERVER_FINDER_REPORTER.LastFetchStatus =
            tostring(requestReason or "fetch failed")

        return nil,
            HOLY_SERVER_FINDER_REPORTER.LastFetchStatus
    end

    local rows =
        {}

    local serverRows =
        type(data.servers) == "table"
        and data.servers
        or type(data.Servers) == "table"
        and data.Servers
        or {}

    for _, serverRow in ipairs(serverRows) do

        local normalized =
            HolyServerFinderNormalizeBackendRow(
                serverRow
            )

        if normalized then

            table.insert(
                rows,
                normalized
            )
        end
    end

    HOLY_SERVER_FINDER_REPORTER.LastFetchStatus =
        "Fetched "
        .. tostring(#rows)
        .. " server(s)"

    return rows,
        "ok"
end

function HolyServerFinderMergeRows(backendRows, localRows)

    local output =
        {}

    local indexByJobId =
        {}

    local function add(row, allowReplace)

        if type(row) ~= "table" then
            return
        end

        local jobId =
            HolyCleanText(
                row.JobId
                or row.jobId
                or row.ServerId
                or row.Id
                or row.Key
            )

        if jobId == "" then
            return
        end

        local existingIndex =
            indexByJobId[jobId]

        if existingIndex then

            if allowReplace == true then

                output[existingIndex] =
                    row
            end

            return
        end

        indexByJobId[jobId] =
            #output + 1

        table.insert(
            output,
            row
        )
    end

    for _, row in ipairs(backendRows or {}) do

        add(
            row,
            false
        )
    end

    for _, row in ipairs(localRows or {}) do

        add(
            row,
            true
        )
    end

    return output
end

function HolyServerFinderPetBaseName(pet)

    pet =
        type(pet) == "table"
        and pet
        or {}

    local baseName =
        HolyCleanText(
            pet.Pet
            or pet.PetName
            or pet.BasePet
            or pet.Name
        )

    if baseName ~= "" then
        return baseName
    end

    return HolyCleanText(
        pet.DisplayName
        or "Unknown Pet"
    )
end

function HolyServerFinderPetDisplayName(pet)

    pet =
        type(pet) == "table"
        and pet
        or {}

    local baseName =
        HolyCleanText(
            pet.Pet
            or pet.PetName
            or pet.BasePet
        )

    local displayName =
        HolyCleanText(
            pet.DisplayName
            or pet.Name
        )

    local size =
        HolySniperNormalizeSizeName(
            pet.Size
            or pet.size
            or "Normal"
        )

    local variant =
        HolySniperNormalizeVariantName(
            pet.Variant
            or pet.variant
            or pet.Mutation
            or pet.mutation
            or "Normal"
        )

    if baseName ~= "" then

        return HolyLivePetsBuildDisplayName(
            baseName,
            size,
            variant
        )
    end

    if displayName ~= "" then
        return displayName
    end

    return "Unknown Pet"
end

function HolyServerFinderPetGroupKey(pet)

    pet =
        type(pet) == "table"
        and pet
        or {}

    local baseName =
        HolySniperPetAliasKey(
            HolyServerFinderPetBaseName(
                pet
            )
        )

    local size =
        HolySniperNormalizeSizeName(
            pet.Size
            or pet.size
            or "Normal"
        )

    local variant =
        HolySniperNormalizeVariantName(
            pet.Variant
            or pet.variant
            or pet.Mutation
            or pet.mutation
            or "Normal"
        )

    local rarity =
        HolyCleanText(
            pet.Rarity
            or pet.rarity
        )

    return table.concat({
        baseName,
        size:lower(),
        variant:lower(),
        rarity:lower(),
    }, "|")
end

function HolyServerFinderClonePetForDisplay(pet)

    pet =
        type(pet) == "table"
        and pet
        or {}

    local copy =
        {}

    for key, value in pairs(pet) do

        copy[key] =
            value
    end

    local baseName =
        HolyServerFinderPetBaseName(
            pet
        )

    local size =
        HolySniperNormalizeSizeName(
            pet.Size
            or pet.size
            or "Normal"
        )

    local variant =
        HolySniperNormalizeVariantName(
            pet.Variant
            or pet.variant
            or pet.Mutation
            or pet.mutation
            or "Normal"
        )

    copy.Pet =
        baseName

    copy.PetName =
        baseName

    copy.Size =
        size

    copy.Variant =
        variant

    copy.Mutation =
        variant

    copy.DisplayName =
        HolyServerFinderPetDisplayName(
            copy
        )

    copy.Rarity =
        HolyCleanText(
            copy.Rarity
            or copy.rarity
        )

    copy.RarityRank =
        tonumber(copy.RarityRank)
        or HolyServerFinderRarityRank(
            copy.Rarity
        )

    copy.PriceNumber =
        tonumber(
            copy.PriceNumber
            or copy.Price
            or copy.price
        )
        or 0

    copy.Price =
        copy.PriceNumber

    return copy
end

function HolyServerFinderBuildPetDisplayRows(serverRows)

    local output =
        {}

    local now =
        os.time()

    for _, serverRow in ipairs(serverRows or {}) do

        if type(serverRow) ~= "table" then
            continue
        end

        local jobId =
            HolyCleanText(
                serverRow.JobId
                or serverRow.jobId
                or serverRow.ServerId
                or serverRow.Id
                or serverRow.Key
            )

        if jobId == "" then
            continue
        end

        local pets =
            {}

        if type(serverRow.Pets) == "table" then

            for _, pet in ipairs(serverRow.Pets) do

                if type(pet) == "table" then

                    local copy =
                        HolyServerFinderClonePetForDisplay(
                            pet
                        )

                    table.insert(
                        pets,
                        copy
                    )
                end
            end
        end

        if #pets <= 0 then

            local copy =
                HolyServerFinderClonePetForDisplay(
                    serverRow
                )

            if HolyCleanText(copy.DisplayName) ~= ""
            and HolyCleanText(copy.DisplayName) ~= "Unknown Pet" then

                table.insert(
                    pets,
                    copy
                )
            end
        end

        if #pets <= 0 then
            continue
        end

        local groups =
            {}

        local order =
            {}

        for _, pet in ipairs(pets) do

            local key =
                HolyServerFinderPetGroupKey(
                    pet
                )

            if groups[key] == nil then

                groups[key] = {
                    Key =
                        key,

                    Count =
                        0,

                    Pets =
                        {},

                    DisplayName =
                        HolyCleanText(
                            pet.DisplayName
                        ),

                    BasePet =
                        HolyCleanText(
                            pet.Pet
                            or pet.PetName
                        ),

                    Rarity =
                        HolyCleanText(
                            pet.Rarity
                        ),

                    RarityRank =
                        tonumber(pet.RarityRank)
                        or HolyServerFinderRarityRank(
                            pet.Rarity
                        ),

                    Size =
                        HolySniperNormalizeSizeName(
                            pet.Size
                            or "Normal"
                        ),

                    Variant =
                        HolySniperNormalizeVariantName(
                            pet.Variant
                            or pet.Mutation
                            or "Normal"
                        ),

                    PriceNumber =
                        tonumber(
                            pet.PriceNumber
                            or pet.Price
                        )
                        or 0,

                    ExpiresAt =
                        0,
                }

                table.insert(
                    order,
                    key
                )
            end

            local group =
                groups[key]

            group.Count =
                group.Count + 1

            group.PriceNumber =
                math.max(
                    tonumber(group.PriceNumber)
                    or 0,
                    tonumber(
                        pet.PriceNumber
                        or pet.Price
                    )
                    or 0
                )

            group.RarityRank =
                math.max(
                    tonumber(group.RarityRank)
                    or 0,
                    tonumber(pet.RarityRank)
                    or HolyServerFinderRarityRank(
                        pet.Rarity
                    )
                )

            local expiresAt =
                tonumber(
                    pet.ExpiresAt
                    or pet.expiresAt
                )
                or 0

            if expiresAt <= 0 then

                local spawnedAt =
                    tonumber(
                        pet.SpawnedAt
                        or pet.spawnedAt
                    )
                    or 0

                local lifetime =
                    tonumber(
                        pet.Lifetime
                        or pet.lifetime
                    )
                    or 0

                if spawnedAt > 0
                and lifetime > 0 then

                    expiresAt =
                        spawnedAt
                        + lifetime
                end
            end

            if expiresAt > group.ExpiresAt then

                group.ExpiresAt =
                    expiresAt
            end

            table.insert(
                group.Pets,
                pet
            )
        end

        for _, key in ipairs(order) do

            local group =
                groups[key]

            local displayName =
                HolyCleanText(
                    group.DisplayName
                )

            if displayName == "" then

                displayName =
                    HolyLivePetsBuildDisplayName(
                        group.BasePet,
                        group.Size,
                        group.Variant
                    )
            end

            if group.Count > 1 then

                displayName =
                    displayName
                    .. " x"
                    .. tostring(group.Count)
            end

            local expiresAt =
                tonumber(group.ExpiresAt)
                or tonumber(serverRow.ExpiresAt)
                or 0

            local otherPetCount =
                math.max(
                    0,
                    #pets - group.Count
                )

            local searchBlob =
                HolyServerFinderBuildPetSearchBlob(
                    group.Pets
                )

            table.insert(
                output,
                {
                    Key =
                        tostring(jobId)
                        .. "|pet|"
                        .. tostring(key),

                    Id =
                        tostring(jobId)
                        .. "|pet|"
                        .. tostring(key),

                    JobId =
                        jobId,

                    PlaceId =
                        tonumber(
                            serverRow.PlaceId
                            or serverRow.placeId
                        )
                        or game.PlaceId,

                    DisplayName =
                        displayName,

                    Name =
                        searchBlob,

                    Pet =
                        displayName,

                    PetName =
                        displayName,

                    BasePet =
                        group.BasePet,

                    BestPet =
                        group.BasePet,

                    BestDisplayName =
                        displayName,

                    Rarity =
                        group.Rarity,

                    RarityRank =
                        group.RarityRank,

                    Size =
                        group.Size,

                    Variant =
                        group.Variant,

                    Mutation =
                        group.Variant,

                    Price =
                        group.PriceNumber,

                    PriceNumber =
                        group.PriceNumber,

                    Playing =
                        tonumber(
                            serverRow.Playing
                            or serverRow.playing
                        )
                        or 0,

                    MaxPlayers =
                        tonumber(
                            serverRow.MaxPlayers
                            or serverRow.maxPlayers
                        )
                        or 8,

                    ServerVersion =
                        HolyCleanText(
                            serverRow.ServerVersion
                            or serverRow.serverVersion
                        ),

                    ReportedAt =
                        tonumber(
                            serverRow.ReportedAt
                            or serverRow.reportedAt
                        )
                        or now,

                    ExpiresAt =
                        expiresAt,

                    TimeLeft =
                        math.max(
                            0,
                            expiresAt > 0
                            and expiresAt - now
                            or 0
                        ),

                    PetCount =
                        group.Count,

                    ServerPetCount =
                        #pets,

                    OtherPetCount =
                        otherPetCount,

                    Pets =
                        group.Pets,

                    Source =
                        serverRow.Source
                        or "Cloudflare",

                    IsCurrentServer =
                        serverRow.IsCurrentServer == true
                        or jobId == tostring(game.JobId),

                    ParentServerRow =
                        serverRow,
                }
            )
        end
    end

    table.sort(output, function(a, b)

        if a.IsCurrentServer ~= b.IsCurrentServer then
            return a.IsCurrentServer == true
        end

        local rarityA =
            tonumber(a.RarityRank)
            or 0

        local rarityB =
            tonumber(b.RarityRank)
            or 0

        if rarityA ~= rarityB then
            return rarityA > rarityB
        end

        local priceA =
            tonumber(a.PriceNumber)
            or 0

        local priceB =
            tonumber(b.PriceNumber)
            or 0

        if priceA ~= priceB then
            return priceA > priceB
        end

        local timeA =
            tonumber(a.TimeLeft)
            or 0

        local timeB =
            tonumber(b.TimeLeft)
            or 0

        if timeA ~= timeB then
            return timeA > timeB
        end

        return tostring(a.DisplayName or "")
            < tostring(b.DisplayName or "")
    end)

    return output
end

function HolyServerFinderRefreshRows(hud, reason)

    if HolyAuthRequireServerSniper(
        "Server Finder Refresh",
        true
    ) ~= true then

        return false
    end

    if type(hud) ~= "table"
    or type(hud.SetRows) ~= "function" then
        return false
    end

    HolyServerFinderReportForRefresh(
        reason or "refresh"
    )

    local localRows =
        HolyServerFinderBuildLocalRows()

    local backendRows =
        nil

    local ok,
        result =
        pcall(function()

            return HolyServerFinderFetchBackendRows()
        end)

    if ok == true
    and type(result) == "table" then

        backendRows =
            result
    end

    local mergedRows =
        HolyServerFinderMergeRows(
            backendRows,
            localRows
        )

    local displayRows =
        HolyServerFinderAnnotateDisplayRows(
            HolyServerFinderBuildPetDisplayRows(
                mergedRows
            )
        )

    hud:SetRows(
        displayRows
    )

    HolyServerFinderEvaluateAutoJoin(
        hud
    )

    return true
end

function HolyServerFinderPullStateFromHud(hud)

    if type(hud) ~= "table"
    or type(hud.GetSettings) ~= "function" then
        return false
    end

    local settings =
        hud:GetSettings()

    if type(settings) ~= "table" then
        return false
    end

    HOLY_SERVER_FINDER_STATE.AutoRefresh =
        settings.AutoRefresh == true

    HOLY_SERVER_FINDER_STATE.RefreshDelay =
        math.clamp(
            tonumber(settings.RefreshDelay)
            or 5,
            1,
            60
        )

    HOLY_SERVER_FINDER_STATE.HideFull =
        settings.HideFull ~= false

    HOLY_SERVER_FINDER_STATE.SelectedPets =
        HolyServerFinderMapFromArray(
            settings.SelectedPets
        )

    HOLY_SERVER_FINDER_STATE.SelectedRarities =
        HolyServerFinderMapFromArray(
            settings.SelectedRarities
        )

    HOLY_SERVER_FINDER_STATE.SelectedSizes =
        HolyServerFinderSizeMapFromArray(
            settings.SelectedSizes
            or settings.SelectedTraits
        )

    HOLY_SERVER_FINDER_STATE.SelectedVariants =
        HolyServerFinderVariantMapFromArray(
            settings.SelectedVariants
            or settings.SelectedTraits
        )

    HOLY_SERVER_FINDER_STATE.SelectedTraits =
        {}

    HOLY_SERVER_FINDER_STATE.Minimized =
        settings.Minimized == true

    HOLY_SERVER_FINDER_STATE.Position =
        HolyServerFinderReadPosition(
            settings.Position
        )

    HOLY_SERVER_FINDER_STATE.FilterPosition =
        HolyServerFinderReadPosition(
            settings.FilterPosition
        )

    HOLY_SERVER_FINDER_STATE.HudScale =
        HolyServerFinderReadHudScale(
            settings.HudScale
            or settings.Scale
            or HOLY_SERVER_FINDER_STATE.HudScale
            or 80
        )

    HOLY_SERVER_FINDER_STATE.AutoJoinMode =
        HolyServerFinderNormalizeAutoJoinMode(
            settings.AutoJoinMode
            or HOLY_SERVER_FINDER_STATE.AutoJoinMode
            or "Off"
        )

    HolyServerFinderEnsureAutoJoinState()

    return true
end

function HolyServerFinderApplyStateToHud(hud)

    if type(hud) ~= "table"
    or type(hud.ApplySettings) ~= "function" then
        return false
    end

    HolyServerFinderEnsureAutoJoinState()

    hud:ApplySettings({
        AutoRefresh =
            HOLY_SERVER_FINDER_STATE.AutoRefresh == true,

        RefreshDelay =
            HOLY_SERVER_FINDER_STATE.RefreshDelay,

        HideFull =
            HOLY_SERVER_FINDER_STATE.HideFull ~= false,

        AutoJoinMode =
            HolyServerFinderNormalizeAutoJoinMode(
                HOLY_SERVER_FINDER_STATE.AutoJoinMode
            ),

        SelectedPets =
            HolyServerFinderArrayFromMap(
                HOLY_SERVER_FINDER_STATE.SelectedPets
            ),

        SelectedRarities =
            HolyServerFinderArrayFromMap(
                HOLY_SERVER_FINDER_STATE.SelectedRarities
            ),

        SelectedSizes =
            HolyServerFinderArrayFromMap(
                HOLY_SERVER_FINDER_STATE.SelectedSizes
            ),

        SelectedVariants =
            HolyServerFinderArrayFromMap(
                HOLY_SERVER_FINDER_STATE.SelectedVariants
            ),

        Minimized =
            HOLY_SERVER_FINDER_STATE.Minimized == true,

        Position =
            HOLY_SERVER_FINDER_STATE.Position,

        FilterPosition =
            HOLY_SERVER_FINDER_STATE.FilterPosition,

        HudScale =
            HolyServerFinderGetHudScale(),

        Scale =
            HolyServerFinderGetHudScaleFactor(),
    })

    HolyServerFinderApplyScaleToHud(
        hud
    )

    return true
end

function HolyServerFinderSyncToggle(value)

    if HOLY_SERVER_FINDER_TOGGLE_LOCK == true then
        return false
    end

    local toggle =
        HOLY_SERVER_FINDER_TOGGLE

    if type(toggle) ~= "table"
    or type(toggle.SetValue) ~= "function" then
        return false
    end

    HOLY_SERVER_FINDER_TOGGLE_LOCK =
        true

    pcall(function()

        toggle:SetValue(
            value == true
        )
    end)

    HOLY_SERVER_FINDER_TOGGLE_LOCK =
        false

    return true
end

function HolyServerFinderSetHudVisible(value)

    value =
        value == true

    if value == true
    and HolyAuthRequireServerSniper(
        "Server Pet Finder HUD",
        true
    ) ~= true then

        HOLY_SERVER_FINDER_STATE.Enabled =
            false

        HOLY_SERVER_FINDER_STATE.AutoJoinMode =
            "Off"

        HolyServerFinderSyncToggle(
            false
        )

        HolyQueueSaveServerFinderSettings()

        if type(HOLY_SERVER_FINDER_HUD) == "table"
        and type(HOLY_SERVER_FINDER_HUD.Hide) == "function" then

            HOLY_SERVER_FINDER_HUD:Hide()
        end

        return false
    end

    HOLY_SERVER_FINDER_STATE.Enabled =
        value

    HolyQueueSaveServerFinderSettings()

    if value == true then

        HolyServerFinderOpenHud()

        return true
    end

    if type(HOLY_SERVER_FINDER_HUD) == "table"
    and type(HOLY_SERVER_FINDER_HUD.Hide) == "function" then

        HOLY_SERVER_FINDER_HUD:Hide()
    end

    return true
end

function HolyServerFinderOpenHud()

    if HolyAuthRequireServerSniper(
        "Server Pet Finder HUD",
        true
    ) ~= true then

        return false
    end

    local filterOptions =
        HolyServerFinderBuildFilterOptions()

    if HOLY_SERVER_FINDER_HUD == nil then

        HOLY_SERVER_FINDER_HUD =
            Library:CreateServerFinderHUD({
                Title =
                    "HOLY Server Finder",

                CurrentServer =
                    tostring(game.JobId),

                AutoRefresh =
                    HOLY_SERVER_FINDER_STATE.AutoRefresh == true,

                RefreshDelay =
                    HOLY_SERVER_FINDER_STATE.RefreshDelay,

                HideFull =
                    HOLY_SERVER_FINDER_STATE.HideFull ~= false,

                HudScale =
                    HolyServerFinderGetHudScale(),

                Scale =
                    HolyServerFinderGetHudScaleFactor(),

                AutoJoinMode =
                    HolyServerFinderNormalizeAutoJoinMode(
                        HOLY_SERVER_FINDER_STATE.AutoJoinMode
                    ),

                SelectedPets =
                    HolyServerFinderArrayFromMap(
                        HOLY_SERVER_FINDER_STATE.SelectedPets
                    ),

                SelectedRarities =
                    HolyServerFinderArrayFromMap(
                        HOLY_SERVER_FINDER_STATE.SelectedRarities
                    ),

                SelectedSizes =
                    HolyServerFinderArrayFromMap(
                        HOLY_SERVER_FINDER_STATE.SelectedSizes
                    ),

                SelectedVariants =
                    HolyServerFinderArrayFromMap(
                        HOLY_SERVER_FINDER_STATE.SelectedVariants
                    ),

                Minimized =
                    HOLY_SERVER_FINDER_STATE.Minimized == true,

                Position =
                    HOLY_SERVER_FINDER_STATE.Position,

                FilterPosition =
                    HOLY_SERVER_FINDER_STATE.FilterPosition,

                FilterPets =
                    filterOptions.Pets,

                FilterRarities =
                    filterOptions.Rarities,

                FilterSizes =
                    filterOptions.Sizes,

                FilterVariants =
                    filterOptions.Variants,

                OnVisibleChanged =
                    function(visible, hud)

                        HOLY_SERVER_FINDER_STATE.Enabled =
                            visible == true

                        if visible == true then

                            HolyServerFinderPullStateFromHud(
                                hud
                            )
                        end

                        HolyServerFinderSyncToggle(
                            visible == true
                        )

                        HolyQueueSaveServerFinderSettings()
                    end,

                OnSettingsChanged =
                    function(hud)

                        HolyServerFinderPullStateFromHud(
                            hud
                        )

                        HolyQueueSaveServerFinderSettings()
                    end,

                OnAutoJoinModeChanged =
                    function(mode, hud)

                        HolyServerFinderSetAutoJoinMode(
                            mode
                        )

                        HolyServerFinderEvaluateAutoJoin(
                            hud
                        )
                    end,

                OnOpenAutoJoinRules =
                    function()

                        HolyServerFinderShowAutoJoinRulesPopup()
                    end,

                OnRefresh =
                    function(hud)

                        HolyServerFinderRefreshRows(
                            hud,
                            "refresh button"
                        )
                    end,

                OnJoin =
                    function(row)

                        HolyServerFinderJoinRow(
                            row,
                            "Manual Join"
                        )
                    end,
            })
    end

    HolyServerFinderApplyStateToHud(
        HOLY_SERVER_FINDER_HUD
    )

    HolyServerFinderApplyFilterOptions(
        HOLY_SERVER_FINDER_HUD
    )

    HolyServerFinderRefreshRows(
        HOLY_SERVER_FINDER_HUD,
        "hud open"
    )

    HOLY_SERVER_FINDER_HUD:SetCurrentServer(
        tostring(game.JobId)
    )

    HOLY_SERVER_FINDER_HUD:Show()
end


