function HolyShopRefreshMode()

    local isBuy =
        HOLY_SHOP_STATE.Mode ~= "Sell"

    HolySetGroupboxVisible(
        ShopSeedsBox,
        isBuy
    )

    HolySetGroupboxVisible(
        ShopGearBox,
        isBuy
    )

    HolySetGroupboxVisible(
        ShopCratesBox,
        isBuy
    )

    HolySetGroupboxVisible(
        ShopAuctionBox,
        isBuy
    )

    HolySetGroupboxVisible(
        ShopSellBox,
        not isBuy
    )

    HolySetGroupboxVisible(
        ShopFiltersBox,
        not isBuy
    )

    HolySetGroupboxVisible(
        ShopDoubleBox,
        not isBuy
    )

    HolySetGroupboxVisible(
        ShopDailyDealBox,
        not isBuy
    )
end

function HolyShopSetMode(mode)

    mode =
        tostring(mode or "Buy")

    if mode ~= "Sell" then

        mode =
            "Buy"
    end

    HOLY_SHOP_STATE.Mode =
        mode

    HolySaveShopSettings()

    if ShopModeControl
    and type(ShopModeControl.SetValue) == "function" then

        ShopModeControl:SetValue(
            mode,
            true
        )
    end

    HolyShopRefreshMode()
end

